const PY_BUNDLE = {"housing_generator/__init__.py": "", "housing_generator/application/__init__.py": "", "housing_generator/application/dto/__init__.py": "", "housing_generator/application/dto/generation_request.py": "from dataclasses import dataclass\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\n\n\n@dataclass(frozen=True)\nclass GenerationRequest:\n    \"\"\"DTO de entrada del caso de uso GenerateLayoutUseCase.\"\"\"\n    program: Program\n    lot: Lot\n    max_attempts: int = 1\n", "housing_generator/application/dto/validation_result.py": "from dataclasses import dataclass, field\nfrom typing import List\n\n\n@dataclass(frozen=True)\nclass ValidationResult:\n    \"\"\"Resultado de validar un Layout contra una restricción. Separa\n    `violations` (no se cumple) de `warnings` (no verificable con los\n    datos disponibles -- tercera categoría, no aprobado por defecto ni\n    bloqueo). Ver [ARCH:validation-result].\n    \"\"\"\n    violations: List[str] = field(default_factory=list)\n    warnings: List[str] = field(default_factory=list)\n\n    @property\n    def is_valid(self) -> bool:\n        return len(self.violations) == 0\n\n    @staticmethod\n    def merge(results: List[\"ValidationResult\"]) -> \"ValidationResult\":\n        violations: List[str] = []\n        warnings: List[str] = []\n        for result in results:\n            violations.extend(result.violations)\n            warnings.extend(result.warnings)\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/application/ports/__init__.py": "", "housing_generator/application/ports/adjacency_graph_builder_port.py": "from abc import ABC, abstractmethod\nimport networkx as nx\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass AdjacencyGraphBuilderPort(ABC):\n    \"\"\"Construye el grafo de adyacencia REAL a partir de la geometria ya\n    generada de un Layout (quien toca a quien de verdad).\n\n    Distinto de BuildAdjacencyGraphUseCase: aquel construye un grafo a\n    partir de AdjacencyRequirement (intencion declarada antes de generar);\n    este se construye a partir del resultado geometrico ya colocado.\n    \"\"\"\n\n    @abstractmethod\n    def build(self, layout: Layout) -> nx.Graph:\n        ...\n", "housing_generator/application/ports/constraint_validator_port.py": "from abc import ABC, abstractmethod\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.application.dto.validation_result import ValidationResult\n\n\nclass ConstraintValidatorPort(ABC):\n    \"\"\"Valida un Layout contra restricciones duras/blandas.\"\"\"\n\n    @abstractmethod\n    def validate(self, layout: Layout) -> ValidationResult:\n        ...\n", "housing_generator/application/ports/layout_generator_port.py": "from abc import ABC, abstractmethod\nfrom typing import List\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass LayoutGeneratorPort(ABC):\n    \"\"\"Coloca las estancias de un programa dentro de un solar, respetando\n    las zonas dadas. Distintas estrategias (slicing, grafos, geneticos,\n    CSP...) implementan este mismo puerto y son intercambiables.\"\"\"\n\n    @abstractmethod\n    def generate(self, program: Program, lot: Lot, zones: List[Zone]) -> Layout:\n        ...\n", "housing_generator/application/ports/layout_repository_port.py": "from abc import ABC, abstractmethod\nfrom typing import List, Optional\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n\nclass LayoutRepositoryPort(ABC):\n    \"\"\"Persistencia de layouts generados (JSON, base de datos, etc.).\"\"\"\n\n    @abstractmethod\n    def save(\n        self, layout: Layout, path: str,\n        adjacency_requirements: Optional[List[AdjacencyRequirement]] = None,\n    ) -> None:\n        ...\n\n    @abstractmethod\n    def load(self, path: str) -> Layout:\n        ...\n", "housing_generator/application/ports/viabilidad_urbanistica_validator_port.py": "from abc import ABC, abstractmethod\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.application.dto.validation_result import ValidationResult\n\n\nclass ViabilidadUrbanisticaValidatorPort(ABC):\n    \"\"\"Comprueba viabilidad urbanística (edificabilidad, ocupación,\n    altura, frente) contra superficies DECLARADAS -- a diferencia de\n    `ConstraintValidatorPort`, no necesita un `Layout` ya colocado con\n    geometría real, se ejecuta ANTES de generar nada. Ver\n    [ARCH:viabilidad-urbanistica].\"\"\"\n\n    @abstractmethod\n    def validate(self, program: Program, lot: Lot, num_plantas: int) -> ValidationResult:\n        ...\n", "housing_generator/application/ports/zoning_strategy_port.py": "from abc import ABC, abstractmethod\nfrom typing import List\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.zone import Zone\n\n\nclass ZoningStrategyPort(ABC):\n    \"\"\"Agrupa las estancias de un programa en macro-zonas (dia/noche/servicio).\n\n    Puerto (interfaz) segun arquitectura hexagonal: la capa de aplicacion\n    depende de esta abstraccion, nunca de una implementacion concreta.\n    \"\"\"\n\n    @abstractmethod\n    def build_zones(self, program: Program) -> List[Zone]:\n        ...\n", "housing_generator/application/use_cases/__init__.py": "", "housing_generator/application/use_cases/build_adjacency_graph.py": "import networkx as nx\nfrom housing_generator.domain.entities.program import Program\n\n\nclass BuildAdjacencyGraphUseCase:\n    \"\"\"Convierte los requisitos de adyacencia de un Program en un grafo\n    ponderado: la estructura de datos detras del clasico 'diagrama de\n    burbujas' que usan los arquitectos en la fase de programacion.\"\"\"\n\n    _WEIGHTS = {\n        \"must_be_near\": 3,\n        \"should_be_near\": 2,\n        \"indifferent\": 1,\n        \"must_be_away\": -3,\n    }\n\n    def execute(self, program: Program) -> nx.Graph:\n        graph = nx.Graph()\n        for room in program.rooms:\n            graph.add_node(room.id, name=room.name, room_type=room.room_type, zone=room.zone)\n\n        for req in program.adjacency_requirements:\n            weight = self._WEIGHTS[req.strength.value]\n            graph.add_edge(req.room_a_id, req.room_b_id, weight=weight, strength=req.strength)\n\n        return graph\n", "housing_generator/application/use_cases/generate_building.py": "from typing import Callable, Dict, List, Optional\nfrom shapely.geometry.base import BaseGeometry\nfrom housing_generator.application.ports.zoning_strategy_port import ZoningStrategyPort\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.ports.viabilidad_urbanistica_validator_port import (\n    ViabilidadUrbanisticaValidatorPort,\n)\nfrom housing_generator.domain.entities.building import Building\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.enums import NivelPlanta, NIVEL_PLANTA_ORDEN, RoomType, SpaceCategory\nfrom housing_generator.domain.exceptions import LayoutGenerationError\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n# Fabrica de validadores por planta -- funcion, no clases concretas\n# (aplicacion no depende de infraestructura). Ver [ARCH:generate-building].\nPerFloorValidatorsFactory = Callable[\n    [List[AdjacencyRequirement], Optional[BaseGeometry], List[BaseGeometry], int, Dict[str, int], bool],\n    ConstraintValidatorPort,\n]\nLayoutGeneratorFactory = Callable[[ConstraintValidatorPort, List[AdjacencyRequirement]], LayoutGeneratorPort]\n\n\nclass GenerateBuildingUseCase:\n    \"\"\"Orquesta la generación de una vivienda de varias plantas: agrupa\n    por `Room.level`, genera cada planta de abajo a arriba (búsqueda\n    independiente por planta), encadenando alineación de escalera y\n    continuidad de núcleo húmedo entre plantas consecutivas. Ver\n    [ARCH:generate-building].\n    \"\"\"\n\n    def __init__(\n        self,\n        per_floor_validators_factory: PerFloorValidatorsFactory,\n        layout_generator_factory: LayoutGeneratorFactory,\n        zoning_strategy: ZoningStrategyPort,\n        programa_minimo_validator: ConstraintValidatorPort,\n        bano_acceso_validator: ConstraintValidatorPort,\n        viabilidad_urbanistica_validator: Optional[ViabilidadUrbanisticaValidatorPort] = None,\n        adjacency_requirements: Optional[List[AdjacencyRequirement]] = None,\n    ):\n        self._per_floor_validators_factory = per_floor_validators_factory\n        self._layout_generator_factory = layout_generator_factory\n        self._zoning_strategy = zoning_strategy\n        self._programa_minimo_validator = programa_minimo_validator\n        self._bano_acceso_validator = bano_acceso_validator\n        self._viabilidad_urbanistica_validator = viabilidad_urbanistica_validator\n        self._adjacency_requirements = adjacency_requirements or []\n\n    def execute(self, program: Program, lot: Lot) -> Building:\n        rooms_by_level = self._group_by_level(program.rooms)\n        levels = [lvl for lvl in NIVEL_PLANTA_ORDEN if lvl in rooms_by_level]\n\n        # comprobacion de viabilidad urbanistica ANTES de generar nada\n        # -- mismo espiritu que un informe de viabilidad real (Fase 4\n        # de la hoja de ruta investigada con el usuario): si el\n        # programa no es urbanisticamente viable, decirlo al instante,\n        # no despues de minutos de busqueda que nunca podia tener\n        # exito. Ver [ARCH:viabilidad-urbanistica].\n        if self._viabilidad_urbanistica_validator is not None:\n            viabilidad = self._viabilidad_urbanistica_validator.validate(program, lot, len(levels))\n            if not viabilidad.is_valid:\n                raise LayoutGenerationError(\n                    f\"Programa no viable urbanisticamente: {viabilidad.violations}\"\n                )\n\n        total_num_estancias = sum(1 for r in program.rooms if r.space_category == SpaceCategory.ESTANCIA)\n        global_rank = self._compute_global_rank(program.rooms)\n\n        building = Building()\n        previous_layout: Optional[Layout] = None\n        current_buildable_polygon: BaseGeometry = lot.buildable_area.polygon\n\n        for level in levels:\n            level_rooms = rooms_by_level[level]\n            level_room_ids = {r.id for r in level_rooms}\n            level_adjacency = [\n                req for req in self._adjacency_requirements\n                if req.room_a_id in level_room_ids and req.room_b_id in level_room_ids\n            ]\n            level_program = Program(rooms=level_rooms, adjacency_requirements=level_adjacency)\n\n            reference_stair = self._staircase_boundary(previous_layout)\n            reference_wet = self._wet_boundaries(previous_layout)\n            floor_below_exists = previous_layout is not None\n\n            # encogimiento progresivo del contorno, solo desde la 2a\n            # planta. Ver [ARCH:generate-building].\n            if floor_below_exists:\n                current_buildable_polygon = self._shrink_for_next_floor(\n                    current_buildable_polygon, lot.retranqueo_incremento_por_planta_m, level_rooms,\n                )\n            floor_lot = Lot(\n                boundary=Boundary(polygon=current_buildable_polygon),\n                entrance_side=lot.entrance_side,\n                street_side=lot.street_side,\n                retranqueo_m=None,  # ya aplicado al construir current_buildable_polygon\n            )\n\n            composite = self._per_floor_validators_factory(\n                level_adjacency, reference_stair, reference_wet, total_num_estancias, global_rank,\n                floor_below_exists,\n            )\n            generator = self._layout_generator_factory(composite, level_adjacency)\n            zones = self._zoning_strategy.build_zones(level_program)\n            layout = generator.generate(level_program, floor_lot, zones)\n\n            result = composite.validate(layout)\n            if not result.is_valid:\n                raise LayoutGenerationError(\n                    f\"No se pudo generar un layout valido para la planta '{level.value}'. \"\n                    f\"Ultimas violaciones: {result.violations}\"\n                )\n\n            building.floors[level] = layout\n            previous_layout = layout\n\n        self._check_programa_minimo(building)\n        self._check_bano_acceso_general(building)\n        return building\n\n    @staticmethod\n    def _shrink_for_next_floor(\n        previous_polygon: BaseGeometry, increment_m: Optional[float], level_rooms: List[Room],\n    ) -> BaseGeometry:\n        \"\"\"Encoge el contorno de la planta anterior por `increment_m`\n        (mismo mecanismo que `Lot.buildable_area`). Con red de\n        seguridad -- ver [ARCH:generate-building].\"\"\"\n        if increment_m is None or increment_m <= 0:\n            return previous_polygon\n\n        shrunk = previous_polygon.buffer(-increment_m)\n        required_area = sum(r.dimensions.area_m2 for r in level_rooms)\n        if shrunk.area < required_area:\n            return previous_polygon  # red de seguridad: copia exacta, no un area inviable\n        return shrunk\n\n    @staticmethod\n    def _compute_global_rank(rooms: List[Room]) -> Dict[str, int]:\n        \"\"\"Puesto de Tabla 1 (1=mayor) de cada estancia entre TODAS las\n        del edificio, precalculado antes de generar ninguna planta --\n        las areas son DECLARADAS en el Program, no dependen de la\n        geometria ya colocada, asi que esto se puede saber de antemano.\"\"\"\n        estancias = [r for r in rooms if r.space_category == SpaceCategory.ESTANCIA]\n        ordenadas = sorted(estancias, key=lambda r: r.dimensions.area_m2, reverse=True)\n        return {room.id: puesto for puesto, room in enumerate(ordenadas, start=1)}\n\n    @staticmethod\n    def _group_by_level(rooms: List[Room]) -> Dict[NivelPlanta, List[Room]]:\n        grouped: Dict[NivelPlanta, List[Room]] = {}\n        for room in rooms:\n            level = room.level or NivelPlanta.PLANTA_BAJA\n            grouped.setdefault(level, []).append(room)\n        return grouped\n\n    @staticmethod\n    def _staircase_boundary(layout: Optional[Layout]) -> Optional[BaseGeometry]:\n        if layout is None:\n            return None\n        for room in layout.rooms:\n            if room.room_type == RoomType.STAIRCASE and room.is_placed:\n                return room.boundary.polygon\n        return None\n\n    @staticmethod\n    def _wet_boundaries(layout: Optional[Layout]) -> List[BaseGeometry]:\n        if layout is None:\n            return []\n        return [r.boundary.polygon for r in layout.rooms if r.is_wet and r.is_placed]\n\n    def _check_bano_acceso_general(self, building: Building) -> None:\n        \"\"\"Reutiliza el validador de una sola planta, ejecutado POR\n        PLANTA -- la accesibilidad de un baño no se hereda de otra\n        planta. Ver [ARCH:generate-building].\"\"\"\n        any_bathroom_anywhere = any(\n            r.room_type == RoomType.BATHROOM for layout in building.floors.values() for r in layout.rooms\n        )\n        if not any_bathroom_anywhere:\n            return  # ninguna planta tiene banos -- ViviendaMinimaValidator ya lo habria bloqueado antes\n\n        for layout in building.floors.values():\n            has_bathroom_here = any(r.room_type == RoomType.BATHROOM for r in layout.rooms)\n            if not has_bathroom_here:\n                continue\n            if self._bano_acceso_validator.validate(layout).is_valid:\n                return  # esta planta ya tiene al menos un bano con acceso general -- suficiente\n\n        raise LayoutGenerationError(\n            \"Ninguna planta del edificio tiene un baño con acceso directo a circulación \"\n            \"general (CORRIDOR/ENTRANCE_HALL) -- con varias plantas, todos los baños \"\n            \"quedarían en-suite, sin ninguno de acceso general para el conjunto de la vivienda\"\n        )\n\n    def _check_programa_minimo(self, building: Building) -> None:\n        all_rooms = [room for layout in building.floors.values() for room in layout.rooms]\n        synthetic_layout = Layout(\n            lot=next(iter(building.floors.values())).lot,\n            rooms=all_rooms,\n            zones=[],\n        )\n        result = self._programa_minimo_validator.validate(synthetic_layout)\n        if not result.is_valid:\n            raise LayoutGenerationError(\n                f\"El edificio completo no cumple el programa minimo de vivienda \"\n                f\"(comprobado uniendo todas las plantas): {result.violations}\"\n            )\n", "housing_generator/application/use_cases/generate_layout.py": "from housing_generator.application.dto.generation_request import GenerationRequest\nfrom housing_generator.application.ports.zoning_strategy_port import ZoningStrategyPort\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.exceptions import LayoutGenerationError\n\n\nclass GenerateLayoutUseCase:\n    \"\"\"Orquesta zonificación → colocación → validación para producir\n    un Layout válido. Dependencias inyectadas como puertos (interfaces)\n    -- el algoritmo concreto puede cambiarse sin tocar este caso de uso.\n    \"\"\"\n\n    def __init__(\n        self,\n        zoning_strategy: ZoningStrategyPort,\n        layout_generator: LayoutGeneratorPort,\n        constraint_validator: ConstraintValidatorPort,\n    ):\n        self._zoning_strategy = zoning_strategy\n        self._layout_generator = layout_generator\n        self._constraint_validator = constraint_validator\n\n    def execute(self, request: GenerationRequest) -> Layout:\n        zones = self._zoning_strategy.build_zones(request.program)\n\n        last_result = None\n        for _ in range(max(1, request.max_attempts)):\n            layout = self._layout_generator.generate(request.program, request.lot, zones)\n            result = self._constraint_validator.validate(layout)\n            if result.is_valid:\n                layout.metadata[\"violations\"] = 0\n                layout.metadata[\"warnings\"] = len(result.warnings)\n                return layout\n            last_result = result\n\n        last_violations = last_result.violations if last_result else []\n        raise LayoutGenerationError(\n            f\"No se pudo generar un layout valido tras {request.max_attempts} intento(s). \"\n            f\"Ultimas violaciones: {last_violations}\"\n        )\n", "housing_generator/application/use_cases/validate_layout.py": "from housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass ValidateLayoutUseCase:\n    def __init__(self, constraint_validator: ConstraintValidatorPort):\n        self._constraint_validator = constraint_validator\n\n    def execute(self, layout: Layout) -> ValidationResult:\n        return self._constraint_validator.validate(layout)\n", "housing_generator/config/__init__.py": "", "housing_generator/config/container.py": "\"\"\"Composition root: conecta las implementaciones concretas de\ninfraestructura con los casos de uso de aplicacion a traves de sus\npuertos. Este es el UNICO lugar del codebase que puede conocer a la vez\nlas clases concretas y los puertos; el resto del sistema solo conoce\ninterfaces (ports).\n\"\"\"\nfrom typing import Optional, List\nfrom housing_generator.application.use_cases.generate_layout import GenerateLayoutUseCase\nfrom housing_generator.infrastructure.algorithms.zoning.treemap_zoning import TreemapZoningStrategy\nfrom housing_generator.infrastructure.algorithms.layout_generation.simulated_annealing_generator import (\n    SimulatedAnnealingLayoutGenerator,\n)\nfrom housing_generator.infrastructure.algorithms.layout_generation.btree_layout_generator import (\n    BTreeLayoutGenerator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.adjacency_validator import (\n    AdjacencyConstraintValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.composite_constraint_validator import (\n    CompositeConstraintValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.wet_core_validator import (\n    build_wet_core_validator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.day_night_zoning_validator import (\n    build_day_zone_grouping_validator,\n    build_night_zone_grouping_validator,\n    build_service_zone_grouping_validator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.estancia_minimum_area_validator import (\n    EstanciaMinimumAreaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.servicio_minimum_area_validator import (\n    ServicioMinimumAreaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.dormitorio_armario_validator import (\n    DormitorioArmarioValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.trastero_minimum_area_validator import (\n    TrasteroMinimumAreaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.ancho_libre_estancia_validator import (\n    AnchoLibreEstanciaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.ancho_libre_practico_validator import (\n    AnchoLibrePracticoValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.vivienda_accesible_validator import (\n    ViviendaAccesibleValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.proporcion_maxima_validator import (\n    ProporcionMaximaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.area_objetivo_validator import (\n    AreaObjetivoValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.ancho_libre_pasillo_validator import (\n    AnchoLibrePasilloValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.altura_libre_validator import (\n    AlturaLibreValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.exterior_contact_validator import (\n    ExteriorContactValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.cocina_integrada_validator import (\n    CocinaIntegradaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.vivienda_minima_validator import (\n    ViviendaMinimaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.viabilidad_urbanistica_validator import (\n    ViabilidadUrbanisticaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.espacio_acceso_validator import (\n    EspacioAccesoValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.bano_acceso_validator import (\n    BanoAccesoGeneralValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.escalera_ancho_libre_validator import (\n    EscaleraAnchoLibreValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.pasillo_topologia_validator import (\n    PasilloTopologiaValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.escalera_alineacion_validator import (\n    EscaleraAlineacionValidator,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.nucleo_humedo_vertical_validator import (\n    NucleoHumedoVerticalValidator,\n)\nfrom housing_generator.infrastructure.algorithms.layout_generation.soft_constraint_scorer import (\n    SoftConstraintScorer,\n)\nfrom housing_generator.application.use_cases.generate_building import GenerateBuildingUseCase\nfrom housing_generator.infrastructure.algorithms.adjacency.geometry_adjacency_graph_builder import (\n    GeometryAdjacencyGraphBuilder,\n)\n\n# Umbral de adyacencia interior (pared compartida entre estancias),\n# confirmado por el usuario para el grafo de adyacencia real.\nADJACENCY_MIN_SHARED_EDGE_M = 0.1\n\n\ndef build_per_floor_validators(\n    adjacency_requirements, graph_builder, total_num_estancias=None, global_rank=None,\n    vivienda_accesible: bool = False,\n) -> List:\n    \"\"\"Validadores que se aplican a UNA sola planta (Layout). No\n    incluye `ViviendaMinimaValidator` ni `BanoAccesoGeneralValidator`\n    (ámbito edificio, ver `generate_building.py`). `vivienda_accesible`\n    opt-in. Ver [ARCH:container].\n    \"\"\"\n    return [\n        AdjacencyConstraintValidator(adjacency_requirements),\n        build_wet_core_validator(graph_builder),\n        build_day_zone_grouping_validator(graph_builder),\n        build_night_zone_grouping_validator(graph_builder),\n        build_service_zone_grouping_validator(graph_builder),\n        EstanciaMinimumAreaValidator(\n            total_num_estancias_override=total_num_estancias, global_rank_override=global_rank,\n        ),\n        ServicioMinimumAreaValidator(total_num_estancias_override=total_num_estancias),\n        DormitorioArmarioValidator(),\n        TrasteroMinimumAreaValidator(),\n        AnchoLibreEstanciaValidator(),\n        AnchoLibrePracticoValidator(),\n        AnchoLibrePasilloValidator(),\n        AlturaLibreValidator(),\n        ExteriorContactValidator(),\n        CocinaIntegradaValidator(total_num_estancias_override=total_num_estancias),\n        EspacioAccesoValidator(),\n        EscaleraAnchoLibreValidator(),\n        PasilloTopologiaValidator(graph_builder),\n        ViviendaAccesibleValidator(activo=vivienda_accesible),\n        ProporcionMaximaValidator(),\n        AreaObjetivoValidator(),\n    ]\n\n\ndef build_generate_layout_use_case(\n    adjacency_requirements: Optional[List] = None,\n    max_iterations: int = 2000,\n    seed: Optional[int] = None,\n    vivienda_accesible: bool = False,\n) -> GenerateLayoutUseCase:\n    \"\"\"Fábrica del caso de uso GenerateLayout con todas las reglas de\n    una sola planta (`build_per_floor_validators`) + las de ámbito\n    edificio (`ViviendaMinimaValidator`, `BanoAccesoGeneralValidator`\n    -- con una única planta, \"edificio\" y \"planta\" son lo mismo).\n    Generador: `SimulatedAnnealingLayoutGenerator`. Ver\n    [ARCH:container].\n    \"\"\"\n    graph_builder = GeometryAdjacencyGraphBuilder(min_shared_edge_m=ADJACENCY_MIN_SHARED_EDGE_M)\n\n    validators = build_per_floor_validators(\n        adjacency_requirements, graph_builder, vivienda_accesible=vivienda_accesible,\n    ) + [\n        ViviendaMinimaValidator(),\n        BanoAccesoGeneralValidator(graph_builder),\n    ]\n    composite = CompositeConstraintValidator(validators)\n    soft_scorer = SoftConstraintScorer(adjacency_requirements or [], graph_builder)\n\n    layout_generator = SimulatedAnnealingLayoutGenerator(\n        constraint_validator=composite,\n        max_iterations=max_iterations,\n        seed=seed,\n        soft_constraint_scorer=soft_scorer,\n    )\n\n    return GenerateLayoutUseCase(\n        zoning_strategy=TreemapZoningStrategy(),\n        layout_generator=layout_generator,\n        constraint_validator=composite,\n    )\n\n\ndef build_generate_building_use_case(\n    adjacency_requirements: Optional[List] = None,\n    max_iterations: int = 2000,\n    seed: Optional[int] = None,\n    vivienda_accesible: bool = False,\n    experimental_btree: bool = False,\n) -> GenerateBuildingUseCase:\n    \"\"\"Fábrica de `GenerateBuildingUseCase` con las fábricas concretas\n    ya resueltas -- único punto que conecta el caso de uso multi-planta\n    con infraestructura real. `vivienda_accesible` opt-in, aplicado\n    igual en todas las plantas. `experimental_btree`: usa\n    `BTreeLayoutGenerator` en vez de `SimulatedAnnealingLayoutGenerator`\n    -- migración en curso (Fase 4/5, comparación empírica), ver\n    `docs/referencia/generador/prototipo-btree/`. Ver [ARCH:container].\n    \"\"\"\n    graph_builder = GeometryAdjacencyGraphBuilder(min_shared_edge_m=ADJACENCY_MIN_SHARED_EDGE_M)\n\n    def per_floor_validators_factory(\n        level_adjacency, reference_stair, reference_wet, total_num_estancias, global_rank, floor_below_exists,\n    ):\n        validators = build_per_floor_validators(\n            level_adjacency, graph_builder, total_num_estancias, global_rank,\n            vivienda_accesible=vivienda_accesible,\n        ) + [\n            EscaleraAlineacionValidator(\n                reference_boundary=reference_stair, floor_below_exists=floor_below_exists,\n            ),\n            NucleoHumedoVerticalValidator(reference_wet_boundaries=reference_wet),\n        ]\n        return CompositeConstraintValidator(validators)\n\n    def layout_generator_factory(composite, level_adjacency):\n        soft_scorer = SoftConstraintScorer(level_adjacency, graph_builder)\n        if experimental_btree:\n            return BTreeLayoutGenerator(\n                constraint_validator=composite,\n                max_iterations=max_iterations,\n                seed=seed,\n                soft_constraint_scorer=soft_scorer,\n            )\n        return SimulatedAnnealingLayoutGenerator(\n            constraint_validator=composite,\n            max_iterations=max_iterations,\n            seed=seed,\n            soft_constraint_scorer=soft_scorer,\n        )\n\n    return GenerateBuildingUseCase(\n        per_floor_validators_factory=per_floor_validators_factory,\n        layout_generator_factory=layout_generator_factory,\n        zoning_strategy=TreemapZoningStrategy(),\n        programa_minimo_validator=ViviendaMinimaValidator(),\n        bano_acceso_validator=BanoAccesoGeneralValidator(graph_builder),\n        viabilidad_urbanistica_validator=ViabilidadUrbanisticaValidator(),\n        adjacency_requirements=adjacency_requirements,\n    )\n", "housing_generator/domain/__init__.py": "", "housing_generator/domain/entities/__init__.py": "", "housing_generator/domain/entities/building.py": "from dataclasses import dataclass, field\nfrom typing import Dict, List, Optional\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import NivelPlanta, NIVEL_PLANTA_ORDEN\n\n\n@dataclass\nclass Building:\n    \"\"\"Vivienda de varias plantas: una `Layout` completa por cada\n    `NivelPlanta` presente, coordinada verticalmente (huella de\n    escalera alineada, núcleo húmedo solapado). No reemplaza a\n    `Layout` para una sola planta -- `Building` es la composición de\n    varias.\n    \"\"\"\n    floors: Dict[NivelPlanta, Layout] = field(default_factory=dict)\n\n    @property\n    def is_complete(self) -> bool:\n        return bool(self.floors) and all(layout.is_complete for layout in self.floors.values())\n\n    def ordered_levels(self) -> List[NivelPlanta]:\n        \"\"\"Niveles presentes, de abajo a arriba (subconjunto de\n        NIVEL_PLANTA_ORDEN).\"\"\"\n        return [level for level in NIVEL_PLANTA_ORDEN if level in self.floors]\n\n    def level_below(self, level: NivelPlanta) -> Optional[NivelPlanta]:\n        \"\"\"Nivel inmediatamente inferior ya presente en este Building\n        (no necesariamente el anterior en NIVEL_PLANTA_ORDEN).\"\"\"\n        present = self.ordered_levels()\n        idx = present.index(level) if level in present else -1\n        if idx <= 0:\n            return None\n        return present[idx - 1]\n", "housing_generator/domain/entities/layout.py": "from dataclasses import dataclass, field\nfrom typing import List, Dict\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.lot import Lot\n\n\n@dataclass\nclass Layout:\n    \"\"\"Resultado generado: estancias colocadas en el espacio, agrupadas en zonas.\"\"\"\n    lot: Lot\n    rooms: List[Room]\n    zones: List[Zone]\n    metadata: Dict[str, float] = field(default_factory=dict)  # p.ej. score de fitness\n\n    @property\n    def is_complete(self) -> bool:\n        return all(r.is_placed for r in self.rooms)\n", "housing_generator/domain/entities/lot.py": "from dataclasses import dataclass\nfrom typing import FrozenSet, List, Optional\nfrom shapely.geometry import box, LineString, Polygon\nfrom housing_generator.domain.value_objects.boundary import Boundary\n\n\n@dataclass(frozen=True)\nclass Lot:\n    \"\"\"Solar/parcela edificable, con datos simplificados de orientación.\n\n    `retranqueo_m`: separación mínima a los lindes (vivienda AISLADA).\n    `None` = sin retranqueo, área edificable = parcela completa.\n    `retranqueo_incremento_por_planta_m`: encoge el contorno\n    progresivamente planta a planta (`None` = todas comparten contorno).\n    `medianera_sides`: subconjunto de {\"north\",\"south\",\"east\",\"west\"}\n    con pared compartida (sin retranqueo, sin contacto exterior ahí);\n    vacío = vivienda aislada.\n\n    Parámetros urbanísticos (Zona 0, \"Introducción de datos\") -- todos\n    opcionales, mismo convenio que `retranqueo_m`: `None` = sin esa\n    restricción concreta. Investigados contra fuentes reales (varios\n    PGOU municipales, no solo teoría) antes de añadirlos -- son el\n    conjunto estándar de una ficha urbanística real, confirmado\n    también contra el framework académico REGEN (2026): edificabilidad\n    y ocupación son restricciones SEPARADAS (una sobre el techo total,\n    otra sobre la huella en planta), no una sola cosa.\n\n    `coeficiente_edificabilidad`: m² de techo permitidos por m² de\n    parcela (m²t/m²s) -- limita la SUMA de superficies de todas las\n    plantas.\n    `ocupacion_maxima_pct`: % de la parcela que puede cubrir la huella\n    en planta (0-100).\n    `altura_maxima_plantas`: número máximo de plantas sobre rasante.\n    `frente_minimo_m`: ancho mínimo de fachada al vial (`street_side`).\n\n    Ver [ARCH:lot].\n    \"\"\"\n    boundary: Boundary\n    entrance_side: str = \"south\"   # north | south | east | west\n    street_side: str = \"south\"\n    retranqueo_m: Optional[float] = None\n    retranqueo_incremento_por_planta_m: Optional[float] = None\n    medianera_sides: FrozenSet[str] = frozenset()\n    coeficiente_edificabilidad: Optional[float] = None\n    ocupacion_maxima_pct: Optional[float] = None\n    altura_maxima_plantas: Optional[int] = None\n    frente_minimo_m: Optional[float] = None\n\n    @property\n    def frente_actual_m(self) -> float:\n        \"\"\"Ancho real de la parcela en el lado que da a la calle\n        (`street_side`) -- para parcela rectangular simple, el lado\n        norte/sur mide lo mismo que el ancho en X; el lado este/oeste,\n        lo mismo que el fondo en Y. Ver [ARCH:lot].\"\"\"\n        minx, miny, maxx, maxy = self.boundary.polygon.bounds\n        if self.street_side in (\"north\", \"south\"):\n            return maxx - minx\n        return maxy - miny\n\n    @property\n    def buildable_area(self) -> Boundary:\n        \"\"\"Área edificable real: parcela reducida por retranqueo,\n        excepto en lados de medianera. Ver [ARCH:lot].\"\"\"\n        if (self.retranqueo_m is None or self.retranqueo_m <= 0) and not self.medianera_sides:\n            return self.boundary\n\n        minx, miny, maxx, maxy = self.boundary.polygon.bounds\n        r = self.retranqueo_m or 0.0\n        new_minx = minx if \"west\" in self.medianera_sides else minx + r\n        new_maxx = maxx if \"east\" in self.medianera_sides else maxx - r\n        new_miny = miny if \"south\" in self.medianera_sides else miny + r\n        new_maxy = maxy if \"north\" in self.medianera_sides else maxy - r\n\n        if new_minx >= new_maxx or new_miny >= new_maxy:\n            # retranqueo excesivo: colapsa a vacio, no a rectangulo invertido\n            return Boundary(polygon=Polygon())\n        return Boundary(polygon=box(new_minx, new_miny, new_maxx, new_maxy))\n\n    def medianera_boundary_segments(self) -> List[LineString]:\n        \"\"\"Segmentos de linde en medianera (posición original de la\n        parcela). Usado por `count_exterior_sides`. Ver [ARCH:lot].\"\"\"\n        minx, miny, maxx, maxy = self.boundary.polygon.bounds\n        segments = []\n        if \"north\" in self.medianera_sides:\n            segments.append(LineString([(minx, maxy), (maxx, maxy)]))\n        if \"south\" in self.medianera_sides:\n            segments.append(LineString([(minx, miny), (maxx, miny)]))\n        if \"east\" in self.medianera_sides:\n            segments.append(LineString([(maxx, miny), (maxx, maxy)]))\n        if \"west\" in self.medianera_sides:\n            segments.append(LineString([(minx, miny), (minx, maxy)]))\n        return segments\n", "housing_generator/domain/entities/program.py": "from dataclasses import dataclass, field\nfrom typing import List\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.domain.exceptions import InvalidProgramError\n\n\n@dataclass\nclass Program:\n    \"\"\"El encargo de diseno: estancias solicitadas + requisitos de adyacencia.\"\"\"\n    rooms: List[Room]\n    adjacency_requirements: List[AdjacencyRequirement] = field(default_factory=list)\n\n    def __post_init__(self):\n        ids = [r.id for r in self.rooms]\n        if len(ids) != len(set(ids)):\n            raise InvalidProgramError(\"Hay ids de estancia duplicados en el programa\")\n\n        room_ids = set(ids)\n        for req in self.adjacency_requirements:\n            if req.room_a_id not in room_ids or req.room_b_id not in room_ids:\n                raise InvalidProgramError(\n                    f\"Un requisito de adyacencia referencia una estancia inexistente: {req}\"\n                )\n\n    @property\n    def total_area_m2(self) -> float:\n        return sum(r.dimensions.area_m2 for r in self.rooms)\n\n    def room_by_id(self, room_id: str) -> Room:\n        for r in self.rooms:\n            if r.id == room_id:\n                return r\n        raise KeyError(room_id)\n", "housing_generator/domain/entities/room.py": "from dataclasses import dataclass\nfrom typing import Optional\nfrom housing_generator.domain.enums import (\n    RoomType,\n    ZoneType,\n    SpaceCategory,\n    NivelPlanta,\n    DEFAULT_ROOM_ZONE,\n    DEFAULT_WET_ROOMS,\n    DEFAULT_SPACE_CATEGORY,\n    DEFAULT_SERVICE_SUBTYPE,\n    DEFAULT_MIN_EXTERIOR_SIDES,\n)\nfrom housing_generator.domain.value_objects.dimensions import Dimensions\nfrom housing_generator.domain.value_objects.boundary import Boundary\n\n\n@dataclass\nclass Room:\n    \"\"\"Una estancia a ubicar en la vivienda (entidad de dominio).\n\n    `boundary` es None hasta que un LayoutGenerator la coloca en el espacio;\n    hasta entonces Room solo representa el requisito programatico.\n    \"\"\"\n    id: str\n    name: str\n    room_type: RoomType\n    dimensions: Dimensions\n    zone: Optional[ZoneType] = None\n    is_wet: Optional[bool] = None\n    space_category: Optional[SpaceCategory] = None\n    service_subtype: Optional[str] = None\n    min_exterior_sides: Optional[int] = None\n    # Solo RoomType.KITCHEN: cocina abierta con el salon. Ver\n    # CocinaIntegradaValidator, [ARCH:cocina-integrada].\n    integrated_in_largest_room: bool = False\n    vertical_opening_m2: Optional[float] = None\n    boundary: Optional[Boundary] = None\n    # Planta de esta estancia (multi-planta). None = una sola planta\n    # (se asume PLANTA_BAJA implicitamente).\n    level: Optional[NivelPlanta] = None\n\n    def __post_init__(self):\n        if self.zone is None:\n            self.zone = DEFAULT_ROOM_ZONE.get(self.room_type, ZoneType.DAY)\n        if self.is_wet is None:\n            self.is_wet = self.room_type in DEFAULT_WET_ROOMS\n        if self.space_category is None:\n            self.space_category = DEFAULT_SPACE_CATEGORY.get(self.room_type, SpaceCategory.OTROS)\n        if self.service_subtype is None:\n            self.service_subtype = DEFAULT_SERVICE_SUBTYPE.get(self.room_type)\n        if self.min_exterior_sides is None:\n            self.min_exterior_sides = DEFAULT_MIN_EXTERIOR_SIDES.get(self.room_type, 0)\n\n    @property\n    def is_placed(self) -> bool:\n        return self.boundary is not None\n", "housing_generator/domain/entities/zone.py": "from dataclasses import dataclass, field\nfrom typing import List, Optional\nfrom housing_generator.domain.enums import ZoneType\nfrom housing_generator.domain.value_objects.boundary import Boundary\n\n\n@dataclass\nclass Zone:\n    \"\"\"Macro-zona (dia / noche / servicio) que agrupa varias estancias.\"\"\"\n    zone_type: ZoneType\n    room_ids: List[str] = field(default_factory=list)\n    boundary: Optional[Boundary] = None\n\n    def add_room(self, room_id: str) -> None:\n        if room_id not in self.room_ids:\n            self.room_ids.append(room_id)\n", "housing_generator/domain/enums.py": "\"\"\"Enumeraciones y mapeos base del dominio de zonificacion residencial.\"\"\"\nfrom enum import Enum\n\n\nclass ZoneType(str, Enum):\n    \"\"\"Macro-zonas según grado de privacidad y horario de uso.\n    CIRCULATION no es una macro-zona de uso, es la clasificación para\n    estancias que sirven a varias a la vez (CORRIDOR, ENTRANCE_HALL).\n    Ver [ARCH:enums].\n    \"\"\"\n    DAY = \"day\"          # Social/publica: estar, comedor, cocina abierta, acceso\n    NIGHT = \"night\"       # Privada: dormitorios, banos privados\n    SERVICE = \"service\"   # Servicio: lavadero, trasteros, garaje, cuarto tecnico\n    CIRCULATION = \"circulation\"  # Vestibulo/pasillo: sirve a varias zonas, no es una\n\n\nclass RoomType(str, Enum):\n    LIVING_ROOM = \"living_room\"\n    DINING_ROOM = \"dining_room\"\n    KITCHEN = \"kitchen\"\n    BEDROOM = \"bedroom\"\n    MASTER_BEDROOM = \"master_bedroom\"\n    BATHROOM = \"bathroom\"\n    TOILET = \"toilet\"              # aseo: sin banera/ducha, min. distinto al de BATHROOM\n    ENTRANCE_HALL = \"entrance_hall\"\n    STUDY = \"study\"\n    LAUNDRY = \"laundry\"\n    DRYING_AREA = \"drying_area\"    # tendedero\n    STORAGE = \"storage\"            # almacenamiento general (Tabla 2: despensa, ropa de cama...)\n    STORAGE_ROOM = \"storage_room\"  # trastero (B.2.5: regla fija, objetos/trastos, distinto de almacenamiento)\n    GARAGE = \"garage\"\n    TECHNICAL_ROOM = \"technical_room\"\n    CORRIDOR = \"corridor\"\n    STAIRCASE = \"staircase\"        # escalera interior -- conecta dos plantas, huella debe alinearse entre ambas\n\n\nclass AdjacencyStrength(str, Enum):\n    \"\"\"Fuerza de un requisito de adyacencia: cerca/lejos obligatorio o\n    preferente, o indiferente. SHOULD_BE_* usa una métrica distinta de\n    MUST_BE_* -- ver [ARCH:enums] y `SoftConstraintScorer`.\"\"\"\n    MUST_BE_NEAR = \"must_be_near\"\n    SHOULD_BE_NEAR = \"should_be_near\"\n    INDIFFERENT = \"indifferent\"\n    SHOULD_BE_AWAY = \"should_be_away\"\n    MUST_BE_AWAY = \"must_be_away\"\n\n\n# Zona por defecto por tipo, editable via Room.zone. Ver [ARCH:enums].\nDEFAULT_ROOM_ZONE = {\n    RoomType.LIVING_ROOM: ZoneType.DAY,\n    RoomType.DINING_ROOM: ZoneType.DAY,\n    RoomType.KITCHEN: ZoneType.DAY,\n    RoomType.ENTRANCE_HALL: ZoneType.CIRCULATION,\n    RoomType.STUDY: ZoneType.DAY,\n    RoomType.CORRIDOR: ZoneType.CIRCULATION,\n    RoomType.STAIRCASE: ZoneType.CIRCULATION,\n    RoomType.TOILET: ZoneType.DAY,\n    RoomType.BEDROOM: ZoneType.NIGHT,\n    RoomType.MASTER_BEDROOM: ZoneType.NIGHT,\n    RoomType.BATHROOM: ZoneType.NIGHT,\n    RoomType.LAUNDRY: ZoneType.SERVICE,\n    RoomType.DRYING_AREA: ZoneType.SERVICE,\n    RoomType.STORAGE: ZoneType.SERVICE,\n    RoomType.STORAGE_ROOM: ZoneType.SERVICE,\n    RoomType.GARAGE: ZoneType.SERVICE,\n    RoomType.TECHNICAL_ROOM: ZoneType.SERVICE,\n}\n\n\n# Locales con conexion a fontaneria/saneamiento. Ver [ARCH:enums].\nDEFAULT_WET_ROOMS = {\n    RoomType.KITCHEN,\n    RoomType.BATHROOM,\n    RoomType.TOILET,\n    RoomType.LAUNDRY,\n}\n\n\nclass SpaceCategory(str, Enum):\n    \"\"\"Clasificación normativa para superficie mínima: ESTANCIA (Tabla\n    1), SERVICIO (Tabla 2, cocina/baño/aseo/lavadero/tendedero/\n    almacenamiento), CIRCULACION (reglas de anchura), OTROS (fuera de\n    Tabla 1/2). Ver [ARCH:enums].\"\"\"\n    ESTANCIA = \"estancia\"\n    SERVICIO = \"servicio\"\n    CIRCULACION = \"circulacion\"\n    OTROS = \"otros\"  # garaje, cuarto tecnico... fuera de Tabla 1 y Tabla 2\n\n\nDEFAULT_SPACE_CATEGORY = {\n    RoomType.LIVING_ROOM: SpaceCategory.ESTANCIA,\n    RoomType.DINING_ROOM: SpaceCategory.ESTANCIA,\n    RoomType.BEDROOM: SpaceCategory.ESTANCIA,\n    RoomType.MASTER_BEDROOM: SpaceCategory.ESTANCIA,\n    RoomType.STUDY: SpaceCategory.ESTANCIA,\n    RoomType.KITCHEN: SpaceCategory.SERVICIO,\n    RoomType.BATHROOM: SpaceCategory.SERVICIO,\n    RoomType.TOILET: SpaceCategory.SERVICIO,\n    RoomType.LAUNDRY: SpaceCategory.SERVICIO,\n    RoomType.DRYING_AREA: SpaceCategory.SERVICIO,\n    RoomType.STORAGE: SpaceCategory.SERVICIO,  # \"almacenamiento\" (Tabla 2), confirmado\n    RoomType.STORAGE_ROOM: SpaceCategory.SERVICIO,  # \"trastero\" (B.2.5, regla fija -- NO Tabla 2)\n    RoomType.ENTRANCE_HALL: SpaceCategory.CIRCULACION,\n    RoomType.CORRIDOR: SpaceCategory.CIRCULACION,\n    RoomType.STAIRCASE: SpaceCategory.CIRCULACION,\n    RoomType.GARAGE: SpaceCategory.OTROS,        # no es pieza vividera, fuera de Tabla 1/2\n    RoomType.TECHNICAL_ROOM: SpaceCategory.OTROS,\n}\n\n\n# Clave de Tabla 2 (A.3.2.2 / nhv.lua) para cada RoomType de categoria\n# SERVICIO. Solo los tipos presentes aqui participan en la validacion de\n# Tabla 2; el resto (ESTANCIA/CIRCULACION/OTROS) queda fuera por diseno.\nDEFAULT_SERVICE_SUBTYPE = {\n    RoomType.KITCHEN: \"cocina\",\n    RoomType.BATHROOM: \"bano\",\n    RoomType.TOILET: \"aseo\",\n    RoomType.LAUNDRY: \"lavadero\",\n    RoomType.DRYING_AREA: \"tendedero\",\n    RoomType.STORAGE: \"almacenamiento\",\n}\n\n\n# Minimo de lados con contacto exterior real por tipo, vivienda\n# UNIFAMILIAR. Confirmado caso por caso con el usuario. GARAGE=0 --\n# corregido tras investigacion (sin respaldo normativo real). Ver\n# [ARCH:enums].\n#\n# DISPLAY_NAMES debe coincidir EXACTAMENTE con DISPLAY en\n# html/js/00-shared.js -- ver [ARCH:enums].\nDISPLAY_NAMES = {\n    RoomType.LIVING_ROOM: \"Salón\",\n    RoomType.DINING_ROOM: \"Comedor\",\n    RoomType.KITCHEN: \"Cocina\",\n    RoomType.BEDROOM: \"Dormitorio\",\n    RoomType.MASTER_BEDROOM: \"Dormitorio principal\",\n    RoomType.BATHROOM: \"Baño\",\n    RoomType.TOILET: \"Aseo\",\n    RoomType.ENTRANCE_HALL: \"Recibidor\",\n    RoomType.STUDY: \"Despacho\",\n    RoomType.LAUNDRY: \"Lavadero\",\n    RoomType.DRYING_AREA: \"Tendedero\",\n    RoomType.STORAGE: \"Almacén\",\n    RoomType.STORAGE_ROOM: \"Trastero\",\n    RoomType.GARAGE: \"Garaje\",\n    RoomType.TECHNICAL_ROOM: \"Cuarto técnico\",\n    RoomType.CORRIDOR: \"Pasillo\",\n    RoomType.STAIRCASE: \"Escalera\",\n}\n\nDEFAULT_MIN_EXTERIOR_SIDES = {\n    RoomType.LIVING_ROOM: 1,\n    RoomType.DINING_ROOM: 1,\n    RoomType.KITCHEN: 1,\n    RoomType.BEDROOM: 1,\n    RoomType.MASTER_BEDROOM: 1,\n    RoomType.BATHROOM: 0,\n    RoomType.TOILET: 0,\n    RoomType.ENTRANCE_HALL: 1,\n    RoomType.STUDY: 1,\n    RoomType.LAUNDRY: 0,\n    RoomType.DRYING_AREA: 1,\n    RoomType.STORAGE: 0,\n    RoomType.STORAGE_ROOM: 0,\n    RoomType.GARAGE: 0,\n    RoomType.TECHNICAL_ROOM: 0,\n    RoomType.CORRIDOR: 0,\n    RoomType.STAIRCASE: 0,\n}\n\n\n# Niveles/plantas de una vivienda -- formaliza como enum lo que hasta\n# ahora solo vivia como texto en docs/fuentes/niveles_plantas.md y en el\n# dashboard (JS). SOTANO=-2 ... BAJO_CUBIERTA=4 permite comparar\n# \"por encima/por debajo de\" con < > directamente sobre el valor.\nclass NivelPlanta(str, Enum):\n    SOTANO = \"sotano\"\n    SEMISOTANO = \"semisotano\"\n    PLANTA_BAJA = \"planta_baja\"\n    PLANTA_SUPERIOR = \"planta_superior\"\n    BAJO_CUBIERTA = \"bajo_cubierta\"\n\n\n# Orden vertical de abajo a arriba -- indice = posicion relativa, no un\n# numero de planta real (SEMISOTANO no siempre existe entre SOTANO y\n# PLANTA_BAJA, pero cuando ambos existen este es su orden correcto).\nNIVEL_PLANTA_ORDEN = [\n    NivelPlanta.SOTANO,\n    NivelPlanta.SEMISOTANO,\n    NivelPlanta.PLANTA_BAJA,\n    NivelPlanta.PLANTA_SUPERIOR,\n    NivelPlanta.BAJO_CUBIERTA,\n]\n", "housing_generator/domain/exceptions.py": "\"\"\"Excepciones propias del dominio. Nunca se deben lanzar excepciones\ngenericas (ValueError, Exception) desde la capa de dominio o aplicacion;\nusar siempre estas clases o subclases especificas de infraestructura.\"\"\"\n\n\nclass HousingGeneratorError(Exception):\n    \"\"\"Excepcion base de todo el sistema.\"\"\"\n\n\nclass InvalidProgramError(HousingGeneratorError):\n    \"\"\"El programa (lista de estancias + requisitos) es inconsistente.\"\"\"\n\n\nclass LayoutGenerationError(HousingGeneratorError):\n    \"\"\"No se pudo generar un layout valido para un programa/solar dados.\"\"\"\n", "housing_generator/domain/services/type_adjacency_catalog.py": "\"\"\"Catálogo de relaciones espaciales entre tipos de estancia,\nformalizado como estructura ejecutable del dominio. Generado\nprogramáticamente desde docs/fuentes/relaciones_espaciales.md. Ver\n[ARCH:type-adjacency-catalog] para qué pares se omiten y por qué.\n\"\"\"\nfrom typing import Dict, List, Optional, Tuple\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.enums import RoomType, AdjacencyStrength\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n# Pares fuera del catalogo estatico. Ver [ARCH:type-adjacency-catalog].\nCONDICIONAL_PAIRS = {\n    (RoomType.BEDROOM, RoomType.BATHROOM),\n    (RoomType.MASTER_BEDROOM, RoomType.BATHROOM),\n}\nYA_CUBIERTO_PAIRS = {\n    (RoomType.KITCHEN, RoomType.BATHROOM),\n}\n\nDEFAULT_TYPE_ADJACENCY: Dict[Tuple[RoomType, RoomType], AdjacencyStrength] = {\n    (RoomType.BATHROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BATHROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BATHROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BATHROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.BEDROOM, RoomType.STUDY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.BEDROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.BATHROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.DINING_ROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.KITCHEN): AdjacencyStrength.MUST_BE_NEAR,\n    (RoomType.DINING_ROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.MASTER_BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.DINING_ROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.DINING_ROOM, RoomType.TOILET): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.DRYING_AREA, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.ENTRANCE_HALL, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.ENTRANCE_HALL, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.ENTRANCE_HALL, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.ENTRANCE_HALL, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.MASTER_BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.KITCHEN, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.KITCHEN, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LAUNDRY, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LAUNDRY, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.BATHROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.DINING_ROOM): AdjacencyStrength.MUST_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.KITCHEN): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.MASTER_BEDROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.STUDY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.LIVING_ROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.LIVING_ROOM, RoomType.TOILET): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.MASTER_BEDROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.MASTER_BEDROOM, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.MASTER_BEDROOM, RoomType.STUDY): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.MASTER_BEDROOM, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STORAGE, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STORAGE_ROOM, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STORAGE_ROOM, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STUDY, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STUDY, RoomType.DRYING_AREA): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.GARAGE): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.LAUNDRY): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.STORAGE): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.STUDY, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.STUDY, RoomType.TECHNICAL_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n    (RoomType.TOILET, RoomType.CORRIDOR): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.TOILET, RoomType.ENTRANCE_HALL): AdjacencyStrength.SHOULD_BE_NEAR,\n    (RoomType.TOILET, RoomType.STORAGE_ROOM): AdjacencyStrength.SHOULD_BE_AWAY,\n}\n\n\ndef get_type_adjacency(type_a: RoomType, type_b: RoomType) -> Optional[AdjacencyStrength]:\n    \"\"\"Consulta el catalogo para un par de tipos, sin importar el orden\n    (el diccionario se genero directamente de una tabla fila/columna,\n    no con claves canonicamente ordenadas).\"\"\"\n    return DEFAULT_TYPE_ADJACENCY.get((type_a, type_b)) or DEFAULT_TYPE_ADJACENCY.get((type_b, type_a))\n\n\ndef build_adjacency_requirements(rooms: List[Room]) -> List[AdjacencyRequirement]:\n    \"\"\"Genera automáticamente los AdjacencyRequirement que aplican a un\n    conjunto de estancias, según su RoomType y el catálogo. Se aplica a\n    cada par existente por TIPO (dos BEDROOM reciben la misma relación).\n    Ver [ARCH:type-adjacency-catalog].\"\"\"\n    requirements: List[AdjacencyRequirement] = []\n    for i, room_a in enumerate(rooms):\n        for room_b in rooms[i + 1:]:\n            if room_a.room_type == room_b.room_type:\n                continue\n            type_pair_a = (room_a.room_type, room_b.room_type)\n            type_pair_b = (room_b.room_type, room_a.room_type)\n            if type_pair_a in CONDICIONAL_PAIRS or type_pair_b in CONDICIONAL_PAIRS:\n                continue\n            if type_pair_a in YA_CUBIERTO_PAIRS or type_pair_b in YA_CUBIERTO_PAIRS:\n                continue\n\n            strength = get_type_adjacency(room_a.room_type, room_b.room_type)\n            if strength is not None:\n                requirements.append(AdjacencyRequirement(room_a.id, room_b.id, strength))\n\n    return requirements\n\n\ndef build_program_with_auto_adjacency(rooms: List[Room]) -> Program:\n    \"\"\"Construye un `Program` derivando sus `AdjacencyRequirement`\n    automáticamente en vez de exigir declararlos a mano. Vive en\n    domain/services (lógica de dominio pura, sin infraestructura). Ver\n    [ARCH:type-adjacency-catalog].\"\"\"\n    return Program(rooms=rooms, adjacency_requirements=build_adjacency_requirements(rooms))\n", "housing_generator/domain/value_objects/__init__.py": "", "housing_generator/domain/value_objects/adjacency.py": "from dataclasses import dataclass\nfrom housing_generator.domain.enums import AdjacencyStrength\n\n\n@dataclass(frozen=True)\nclass AdjacencyRequirement:\n    \"\"\"Requisito de adyacencia (no dirigido) entre dos estancias, por id.\n\n    Es la unidad minima de datos de la clasica 'matriz de adyacencia' /\n    'diagrama de burbujas' empleada en programacion arquitectonica.\n    \"\"\"\n    room_a_id: str\n    room_b_id: str\n    strength: AdjacencyStrength\n\n    def involves(self, room_id: str) -> bool:\n        return room_id in (self.room_a_id, self.room_b_id)\n\n    def other(self, room_id: str) -> str:\n        if room_id == self.room_a_id:\n            return self.room_b_id\n        if room_id == self.room_b_id:\n            return self.room_a_id\n        raise ValueError(f\"La estancia {room_id} no pertenece a este requisito\")\n", "housing_generator/domain/value_objects/boundary.py": "from dataclasses import dataclass\nfrom shapely.geometry import Polygon\n\n\n@dataclass(frozen=True)\nclass Boundary:\n    \"\"\"Envuelve un Polygon de shapely: la huella de un solar o de una estancia.\"\"\"\n    polygon: Polygon\n\n    @property\n    def area_m2(self) -> float:\n        return self.polygon.area\n\n    @property\n    def centroid(self):\n        return self.polygon.centroid\n\n    def contains(self, other: \"Boundary\") -> bool:\n        return self.polygon.contains(other.polygon)\n", "housing_generator/domain/value_objects/dimensions.py": "from dataclasses import dataclass\nfrom typing import Optional\n\n\n@dataclass(frozen=True)\nclass Dimensions:\n    \"\"\"Requisito de area/proporcion/altura de una estancia. Inmutable (value object).\"\"\"\n    area_m2: float\n    min_width_m: float = 2.0\n    max_aspect_ratio: float = 2.5\n    ceiling_height_m: Optional[float] = None  # A.3.1.1: None = no declarada, no se asume\n\n    def __post_init__(self):\n        if self.area_m2 <= 0:\n            raise ValueError(\"area_m2 debe ser positivo\")\n        if self.min_width_m <= 0:\n            raise ValueError(\"min_width_m debe ser positivo\")\n        if self.ceiling_height_m is not None and self.ceiling_height_m <= 0:\n            raise ValueError(\"ceiling_height_m debe ser positivo si se declara\")\n", "housing_generator/infrastructure/__init__.py": "", "housing_generator/infrastructure/algorithms/__init__.py": "", "housing_generator/infrastructure/algorithms/adjacency/__init__.py": "", "housing_generator/infrastructure/algorithms/adjacency/door_graph.py": "from typing import List\nimport networkx as nx\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.domain.enums import AdjacencyStrength\nfrom housing_generator.infrastructure.algorithms.constraints.adjacency_validator import (\n    MUST_BE_NEAR_MIN_SHARED_LENGTH_M,\n)\n\n# Grafo de puertas: capa separada de la adyacencia geometrica. Ver\n# [ARCH:door-graph].\n\n\ndef build_door_graph(layout: Layout, adjacency_requirements: List[AdjacencyRequirement]) -> nx.Graph:\n    \"\"\"Subconjunto disperso del grafo de adyacencia geométrica: solo\n    pares con MUST_BE_NEAR declarado Y satisfecho por la geometría\n    final. No modela geometría de puertas (posición/ancho/apertura).\n    Ver [ARCH:door-graph].\"\"\"\n    graph = nx.Graph()\n    placed_ids = {r.id for r in layout.rooms if r.is_placed}\n    rooms_by_id = {r.id: r for r in layout.rooms if r.is_placed}\n\n    for room_id in placed_ids:\n        room = rooms_by_id[room_id]\n        graph.add_node(room_id, name=room.name, room_type=room.room_type)\n\n    for req in adjacency_requirements:\n        if req.strength != AdjacencyStrength.MUST_BE_NEAR:\n            continue\n        if req.room_a_id not in placed_ids or req.room_b_id not in placed_ids:\n            continue\n\n        room_a = rooms_by_id[req.room_a_id]\n        room_b = rooms_by_id[req.room_b_id]\n        shared_length = room_a.boundary.polygon.boundary.intersection(\n            room_b.boundary.polygon.boundary\n        ).length\n        if shared_length >= MUST_BE_NEAR_MIN_SHARED_LENGTH_M:  # mismo umbral que AdjacencyConstraintValidator\n            graph.add_edge(req.room_a_id, req.room_b_id, shared_length_m=shared_length)\n\n    return graph\n", "housing_generator/infrastructure/algorithms/adjacency/geometry_adjacency_graph_builder.py": "from typing import Optional\nimport networkx as nx\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\n\n\nclass GeometryAdjacencyGraphBuilder(AdjacencyGraphBuilderPort):\n    \"\"\"Construye el grafo de adyacencia real midiendo la longitud del\n    segmento de borde compartido entre cada par de estancias colocadas\n    (no un simple `touches()`, que también da positivo con un contacto\n    de esquina). Cachea por referencia real al `Layout`, no por `id()`\n    -- ver [ARCH:geometry-adjacency-graph] para el porqué.\n    \"\"\"\n\n    def __init__(self, min_shared_edge_m: float = 0.1):\n        self._min_shared_edge_m = min_shared_edge_m\n        self._cache_layout_ref: Optional[Layout] = None\n        self._cache_result: Optional[nx.Graph] = None\n\n    def build(self, layout: Layout) -> nx.Graph:\n        if layout is self._cache_layout_ref:\n            return self._cache_result\n\n        graph = nx.Graph()\n        placed_rooms = [r for r in layout.rooms if r.is_placed]\n\n        for room in placed_rooms:\n            graph.add_node(\n                room.id,\n                name=room.name,\n                room_type=room.room_type,\n                zone=room.zone,\n                is_wet=room.is_wet,\n            )\n\n        for i, room_a in enumerate(placed_rooms):\n            for room_b in placed_rooms[i + 1:]:\n                shared_length = self._shared_boundary_length(room_a, room_b)\n                if shared_length >= self._min_shared_edge_m:\n                    graph.add_edge(room_a.id, room_b.id, shared_length_m=shared_length)\n\n        self._cache_layout_ref = layout\n        self._cache_result = graph\n        return graph\n\n    @staticmethod\n    def _shared_boundary_length(room_a: Room, room_b: Room) -> float:\n        boundary_a = room_a.boundary.polygon.boundary\n        boundary_b = room_b.boundary.polygon.boundary\n        return boundary_a.intersection(boundary_b).length\n", "housing_generator/infrastructure/algorithms/constraints/__init__.py": "", "housing_generator/infrastructure/algorithms/constraints/adjacency_validator.py": "from typing import List, Optional\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import AdjacencyStrength\n\n# Longitud minima de borde compartido para \"unidas por un lado\" (no\n# solo esquina) -- lo bastante para que quepa una puerta.\nMUST_BE_NEAR_MIN_SHARED_LENGTH_M = 1.0\n\n\nclass AdjacencyConstraintValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba restricciones duras:\n    - toda estancia debe estar colocada\n    - el limite del solar debe contener cada estancia\n    - las estancias marcadas MUST_BE_AWAY no deben tocarse\n    - las estancias marcadas MUST_BE_NEAR deben compartir un borde de al\n      menos MUST_BE_NEAR_MIN_SHARED_LENGTH_M (no basta con tocarse en un\n      punto o un tramo muy corto)\n    \"\"\"\n\n    def __init__(self, adjacency_requirements: Optional[list] = None, touch_tolerance_m: float = 0.05):\n        self._requirements = adjacency_requirements or []\n        self._tolerance = touch_tolerance_m\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n\n        # layout.lot no cambia entre iteraciones del recocido -- calcular\n        # el buffer UNA vez por validacion, no una vez POR ESTANCIA (bug\n        # de rendimiento real, encontrado con cProfile: 2748 llamadas a\n        # .buffer() para 458 evaluaciones en una prueba de 6 estancias,\n        # exactamente 6x mas de lo necesario). Ver [ARCH:adjacency-validator].\n        lot_boundary_buffered = layout.lot.boundary.polygon.buffer(self._tolerance)\n\n        for room in layout.rooms:\n            if not room.is_placed:\n                violations.append(f\"La estancia '{room.id}' no fue colocada\")\n                continue\n            if not lot_boundary_buffered.contains(room.boundary.polygon):\n                violations.append(f\"La estancia '{room.id}' queda fuera del limite del solar\")\n\n        rooms_by_id = {r.id: r for r in layout.rooms if r.is_placed}\n        for req in self._requirements:\n            room_a = rooms_by_id.get(req.room_a_id)\n            room_b = rooms_by_id.get(req.room_b_id)\n            if not room_a or not room_b:\n                continue\n\n            if req.strength == AdjacencyStrength.MUST_BE_AWAY:\n                if room_a.boundary.polygon.distance(room_b.boundary.polygon) < self._tolerance:\n                    violations.append(\n                        f\"Las estancias '{req.room_a_id}' y '{req.room_b_id}' deben estar \"\n                        f\"separadas pero son adyacentes\"\n                    )\n\n            elif req.strength == AdjacencyStrength.MUST_BE_NEAR:\n                shared_length = room_a.boundary.polygon.boundary.intersection(\n                    room_b.boundary.polygon.boundary\n                ).length\n                if shared_length < MUST_BE_NEAR_MIN_SHARED_LENGTH_M:\n                    violations.append(\n                        f\"Las estancias '{req.room_a_id}' y '{req.room_b_id}' deben compartir \"\n                        f\"al menos {MUST_BE_NEAR_MIN_SHARED_LENGTH_M:.2f}m de borde, pero \"\n                        f\"comparten {shared_length:.2f}m\"\n                    )\n\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/altura_libre_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\n\n# A.3.1.1: altura libre minima. Ver [ARCH:altura-libre].\nALTURA_LIBRE_MIN_M = 2.50\nALTURA_LIBRE_REDUCIDA_M = 2.20\n\nROOM_TYPES_REDUCCION_DIRECTA = {\n    RoomType.ENTRANCE_HALL,  # vestibulo\n    RoomType.CORRIDOR,       # pasillo\n    RoomType.STAIRCASE,      # escaleras\n    RoomType.BATHROOM,       # bano\n    RoomType.TOILET,         # aseo\n    RoomType.LAUNDRY,        # lavadero\n    RoomType.DRYING_AREA,    # tendedero\n    RoomType.GARAGE,         # garajes de viviendas unifamiliares\n}\nROOM_TYPES_FUERA_DE_ALCANCE = {RoomType.TECHNICAL_ROOM}\n\n\nclass AlturaLibreValidator(ConstraintValidatorPort):\n    \"\"\"Valida `Room.dimensions.ceiling_height_m` contra A.3.1.1. Sin\n    altura declarada: aviso. Piezas de reducción directa: violación\n    solo si < 2.20m. Resto: violación si < 2.20m, aviso si 2.20-2.50m\n    (posible excepción del 30%, no verificable). Ver [ARCH:altura-libre].\n    \"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type in ROOM_TYPES_FUERA_DE_ALCANCE:\n                continue\n\n            altura = room.dimensions.ceiling_height_m\n            if altura is None:\n                warnings.append(\n                    f\"'{room.id}': altura de techo no declarada, no se puede verificar A.3.1.1\"\n                )\n                continue\n\n            if room.room_type in ROOM_TYPES_REDUCCION_DIRECTA:\n                if altura < ALTURA_LIBRE_REDUCIDA_M:\n                    violations.append(\n                        f\"'{room.id}': altura libre {altura:.2f}m por debajo del minimo \"\n                        f\"reducido de A.3.1.1.b ({ALTURA_LIBRE_REDUCIDA_M:.2f}m)\"\n                    )\n            else:\n                if altura < ALTURA_LIBRE_REDUCIDA_M:\n                    violations.append(\n                        f\"'{room.id}': altura libre {altura:.2f}m por debajo incluso del \"\n                        f\"minimo reducido de A.3.1.1 ({ALTURA_LIBRE_REDUCIDA_M:.2f}m)\"\n                    )\n                elif altura < ALTURA_LIBRE_MIN_M:\n                    warnings.append(\n                        f\"'{room.id}': altura libre {altura:.2f}m por debajo de \"\n                        f\"{ALTURA_LIBRE_MIN_M:.2f}m -- podria cumplir via la excepcion del \"\n                        f\"30% de superficie (A.3.1.1.c), no verificable sin geometria parcial\"\n                    )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/ancho_libre_estancia_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import meets_minimum_width\n\n# A.3.2.1: ancho libre minimo. Ver [ARCH:ancho-libre-estancia].\nANCHO_LIBRE_ESTANCIA_MAYOR_M = 2.70\nANCHO_LIBRE_DORMITORIO_DOBLE_M = 2.60   # habitacion >= 12m2\nANCHO_LIBRE_DORMITORIO_INDIVIDUAL_M = 2.00  # habitacion < 12m2\nANCHO_LIBRE_COCINA_M = 1.80\nANCHO_LIBRE_BANO_M = 1.60\nDORMITORIO_DOBLE_AREA_UMBRAL_M2 = 12.0\n\n_DORMITORIO_TYPES = {RoomType.BEDROOM, RoomType.MASTER_BEDROOM}\n\n\nclass AnchoLibreEstanciaValidator(ConstraintValidatorPort):\n    \"\"\"A.3.2.1: ancho libre mínimo para estancia mayor, dormitorios,\n    cocina y baño. Ver [ARCH:ancho-libre-estancia].\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        placed_rooms = [r for r in layout.rooms if r.is_placed]\n\n        mayor = next((r for r in placed_rooms if r.room_type == RoomType.LIVING_ROOM), None)\n        if mayor is not None:\n            self._check(mayor, ANCHO_LIBRE_ESTANCIA_MAYOR_M, \"estancia mayor (A.3.2.1.a)\", violations, warnings)\n\n        for room in placed_rooms:\n            if room.room_type in _DORMITORIO_TYPES:\n                if room.dimensions.area_m2 >= DORMITORIO_DOBLE_AREA_UMBRAL_M2:\n                    minimo, etiqueta = ANCHO_LIBRE_DORMITORIO_DOBLE_M, \"dormitorio doble (A.3.2.1.e/f)\"\n                else:\n                    minimo, etiqueta = ANCHO_LIBRE_DORMITORIO_INDIVIDUAL_M, \"dormitorio individual (A.3.2.1.g/h)\"\n                self._check(room, minimo, etiqueta, violations, warnings)\n            elif room.room_type == RoomType.KITCHEN:\n                self._check(room, ANCHO_LIBRE_COCINA_M, \"cocina (A.3.2.1)\", violations, warnings)\n            elif room.room_type == RoomType.BATHROOM:\n                self._check(room, ANCHO_LIBRE_BANO_M, \"bano (A.3.2.1)\", violations, warnings)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n\n    @staticmethod\n    def _check(room, minimo: float, etiqueta: str, violations: List[str], warnings: List[str]) -> None:\n        cumple = meets_minimum_width(room.boundary.polygon, minimo)\n        if cumple is False:\n            violations.append(\n                f\"'{room.id}' ({etiqueta}): ancho libre por debajo del minimo de {minimo:.2f}m\"\n            )\n        elif cumple is None:\n            warnings.append(\n                f\"'{room.id}' ({etiqueta}): forma no rectangular, no se puede verificar \"\n                f\"el ancho libre de {minimo:.2f}m\"\n            )\n", "housing_generator/infrastructure/algorithms/constraints/ancho_libre_pasillo_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# A.3.2.3: pasillos rectangulares (particion guillotina), ancho\n# uniforme -- se aplica el minimo de todo el recorrido (1.00m), no el\n# de estrechamiento puntual (0.90m).\nANCHO_LIBRE_PASILLO_M = 1.00\n\n\nclass AnchoLibrePasilloValidator(ConstraintValidatorPort):\n    \"\"\"A.3.2.3: ancho libre de cada CORRIDOR ≥ 1.00m.\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type != RoomType.CORRIDOR or not room.is_placed:\n                continue\n            v, w = evaluate_minimum_width(\n                room.id, room.boundary.polygon, ANCHO_LIBRE_PASILLO_M,\n                violation_message=f\"ancho libre por debajo del minimo de A.3.2.3 ({ANCHO_LIBRE_PASILLO_M:.2f}m)\",\n                warning_message=\"forma no rectangular, no se puede verificar el ancho libre de pasillo (A.3.2.3)\",\n            )\n            violations.extend(v)\n            warnings.extend(w)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/ancho_libre_practico_validator.py": "from typing import List, Set\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# NO NORMATIVO -- criterio de ingenieria practica, confirmado\n# explicitamente con el usuario. Ver [ARCH:ancho-libre-practico].\nANCHO_LIBRE_PRACTICO_M = 1.20\n\n# NO NORMATIVO -- umbral MAS BAJO para aseo y tendedero, confirmado\n# explicitamente con el usuario tras un caso real: el generador\n# automatico del dashboard crea estas dos estancias al minimo legal\n# exacto de Tabla 2 (1.5m2, 3+ dormitorios) -- a 1.20m de ancho eso\n# deja solo 1.25m de fondo, una tira casi imposible de colocar bien\n# junto con el resto de restricciones. Un aseo real (solo WC + lavabo\n# pequeno) o un tendedero pueden ser legitimamente mas estrechos que\n# un lavadero (que necesita hueco para lavadora) en construccion real\n# -- se mantiene 1.20m para LAUNDRY, se relaja a 0.90m solo para estos\n# dos. A 1.5m2 y 0.90m de ancho, quedan 1.67m de fondo (proporcion\n# 1.85:1), un margen mucho mas comodo. Ver [ARCH:ancho-libre-practico].\nANCHO_LIBRE_REDUCIDO_M = 0.90\nTIPOS_CON_ANCHO_REDUCIDO: Set[RoomType] = {RoomType.TOILET, RoomType.DRYING_AREA}\n\nTIPOS_SIN_ANCHO_NORMATIVO: Set[RoomType] = {\n    RoomType.DINING_ROOM,\n    RoomType.STUDY,\n    RoomType.TOILET,\n    RoomType.LAUNDRY,\n    RoomType.DRYING_AREA,\n    RoomType.STORAGE,\n    RoomType.ENTRANCE_HALL,\n    RoomType.GARAGE,\n    RoomType.TECHNICAL_ROOM,\n}\n\n\nclass AnchoLibrePracticoValidator(ConstraintValidatorPort):\n    \"\"\"Ancho libre mínimo NO normativo (1.20m, o 0.90m para aseo y\n    tendedero) para tipos que el decreto deja sin ancho libre\n    especificado -- evita formas técnicamente conformes en área pero\n    inservibles en la práctica. Ver [ARCH:ancho-libre-practico].\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type not in TIPOS_SIN_ANCHO_NORMATIVO or not room.is_placed:\n                continue\n            umbral = ANCHO_LIBRE_REDUCIDO_M if room.room_type in TIPOS_CON_ANCHO_REDUCIDO else ANCHO_LIBRE_PRACTICO_M\n            v, w = evaluate_minimum_width(\n                room.id, room.boundary.polygon, umbral,\n                violation_message=(\n                    f\"ancho libre por debajo del minimo practico de ingenieria \"\n                    f\"({umbral:.2f}m, NO normativo -- el Decreto 29/2010 \"\n                    f\"no especifica ancho libre para este tipo, pero una estancia mas \"\n                    f\"estrecha que esto no es utilizable en la practica)\"\n                ),\n                warning_message=\"forma no rectangular, no se puede verificar el ancho libre práctico\",\n            )\n            violations.extend(v)\n            warnings.extend(w)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/area_objetivo_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n# NO NORMATIVO -- criterio de ingenieria confirmado explicitamente,\n# no del Decreto 29/2010. Encontrado con un caso real (captura de\n# pantalla del usuario): un Pasillo declarado a 4.0m2 se genero mas\n# grande que un Dormitorio declarado a 8.0m2 -- ninguna regla exigia\n# que el area REALMENTE generada se pareciera al area DECLARADA, solo\n# que superase el minimo normativo (Tabla 1/2). Investigado antes de\n# fijar el valor: el algoritmo squarified treemap ORIGINAL (Bruls et\n# al. 2000, la misma fuente ya citada en este proyecto) se define como\n# \"area predefinida sin ningun espacio sin usar\" -- coincidencia\n# exacta por diseno del propio algoritmo. La desviacion la introduce\n# nuestra propia extension (`ratio_override`/`slide_wall`, hasta\n# +-8% por movimiento, sin limite acumulado ni penalizacion). Sin\n# fuente citable para \"cuanto es aceptable\" en este contexto -- ver\n# [ARCH:area-objetivo].\nTOLERANCIA_AREA = 0.15\n\n\nclass AreaObjetivoValidator(ConstraintValidatorPort):\n    \"\"\"Compara el área realmente generada de cada estancia colocada\n    contra su área declarada (`Room.dimensions.area_m2`) -- violación\n    si la desviación supera el ±15% NO normativo. Ver\n    [ARCH:area-objetivo].\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if not room.is_placed:\n                continue\n            area_declarada = room.dimensions.area_m2\n            if not area_declarada or area_declarada <= 0:\n                continue\n            area_generada = room.boundary.polygon.area\n            desviacion = abs(area_generada - area_declarada) / area_declarada\n            if desviacion > TOLERANCIA_AREA:\n                violations.append(\n                    f\"'{room.id}': area generada {area_generada:.1f}m2 se desvia un \"\n                    f\"{desviacion*100:.0f}% del area declarada {area_declarada:.1f}m2 \"\n                    f\"(NO normativo -- maximo aceptado {TOLERANCIA_AREA*100:.0f}%)\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/bano_acceso_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType, SpaceCategory\n\n# Regla \"Condicional\" del catalogo. Ver [ARCH:bano-acceso].\n\n\nclass BanoAccesoGeneralValidator(ConstraintValidatorPort):\n    \"\"\"Al menos un BATHROOM debe tener adyacencia real con circulación\n    (CORRIDOR o ENTRANCE_HALL) -- ninguno puede quedar capturado\n    exclusivamente dentro de un dormitorio si es el único con acceso\n    general. Sin BATHROOM colocado, o sin NINGUNA circulación en el\n    programa (no aplica -- no hay nada con lo que exigir adyacencia),\n    no aplica. Ver [ARCH:bano-acceso].\n    \"\"\"\n\n    def __init__(self, graph_builder: AdjacencyGraphBuilderPort):\n        self._graph_builder = graph_builder\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        bathrooms = [r for r in layout.rooms if r.is_placed and r.room_type == RoomType.BATHROOM]\n        if not bathrooms:\n            return ValidationResult()\n\n        graph = self._graph_builder.build(layout)\n        circulation_ids = {\n            r.id for r in layout.rooms\n            if r.is_placed and r.space_category == SpaceCategory.CIRCULACION\n        }\n        if not circulation_ids:\n            # BUG REAL encontrado en auditoria de diagnostico: sin\n            # NINGUNA estancia de circulacion en el programa (valido --\n            # \"programa minimo\" no exige recibidor/pasillo), esta regla\n            # era IMPOSIBLE de satisfacer sea cual fuera la geometria\n            # (neighbors & circulation_ids nunca podia ser no-vacio).\n            # Mismo patron \"no aplica\" que EspacioAccesoValidator.\n            return ValidationResult()\n\n        for bath in bathrooms:\n            if bath.id not in graph:\n                continue\n            neighbors = set(graph.neighbors(bath.id))\n            if neighbors & circulation_ids:\n                return ValidationResult()  # al menos uno tiene acceso general -- regla satisfecha\n\n        violations: List[str] = [\n            f\"Ningún baño tiene acceso directo desde circulación general (CORRIDOR/ENTRANCE_HALL) \"\n            f\"-- con {len(bathrooms)} baño(s) en el programa, al menos uno no puede quedar \"\n            f\"capturado exclusivamente dentro de un dormitorio\"\n        ]\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/cocina_integrada_validator.py": "from typing import List, Optional, Tuple\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.enums import RoomType, SpaceCategory\nfrom housing_generator.infrastructure.algorithms.constraints.estancia_minimum_area_validator import (\n    minimo_estancia,\n)\nfrom housing_generator.infrastructure.algorithms.constraints.servicio_minimum_area_validator import (\n    tabla_servicios_para,\n)\n\n# A.3.2.2 / nhv.lua (validarCocinaIntegrada): superficie minima del\n# CONJUNTO = suma de minimos de cada pieza. Ver [ARCH:cocina-integrada].\nAPERTURA_VERTICAL_MIN_M2 = 3.5\n\n\nclass CocinaIntegradaValidator(ConstraintValidatorPort):\n    \"\"\"Valida la cocina integrada en la estancia mayor (RoomType.KITCHEN\n    con `integrated_in_largest_room=True`): sin cocina integrada, no\n    aplica; con cocina pero sin salón, aviso; con ambos, comprueba\n    superficie combinada + apertura vertical. Ver [ARCH:cocina-integrada].\n    \"\"\"\n\n    def __init__(self, total_num_estancias_override: Optional[int] = None):\n        self._total_override = total_num_estancias_override\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        cocina = next(\n            (r for r in layout.rooms if r.room_type == RoomType.KITCHEN and r.integrated_in_largest_room),\n            None,\n        )\n        if cocina is None:\n            return ValidationResult()\n\n        mayor = next((r for r in layout.rooms if r.room_type == RoomType.LIVING_ROOM), None)\n        if mayor is None:\n            return ValidationResult(\n                warnings=[\"Cocina integrada declarada pero no hay salón (LIVING_ROOM) en el \"\n                          \"programa -- no se puede determinar la estancia mayor\"]\n            )\n\n        local_count = sum(1 for r in layout.rooms if r.space_category == SpaceCategory.ESTANCIA)\n        num_estancias = self._total_override if self._total_override is not None else local_count\n\n        area_violations, area_warnings = self._check_combined_area(mayor, cocina, num_estancias)\n        opening_violations, opening_warnings = self._check_vertical_opening(mayor, cocina)\n\n        return ValidationResult(\n            violations=area_violations + opening_violations,\n            warnings=area_warnings + opening_warnings,\n        )\n\n    @staticmethod\n    def _check_combined_area(mayor: Room, cocina: Room, num_estancias: int) -> Tuple[List[str], List[str]]:\n        \"\"\"Superficie minima del CONJUNTO salon+cocina: suma de los\n        minimos de cada pieza por separado (Tabla 1 + Tabla 2).\"\"\"\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        minimo_mayor = minimo_estancia(num_estancias, 1)\n        minimo_cocina = tabla_servicios_para(num_estancias).get(\"cocina\")\n\n        if minimo_mayor is not None and minimo_cocina is not None:\n            minimo_combinado = minimo_mayor + minimo_cocina\n            area_combinada = mayor.dimensions.area_m2 + cocina.dimensions.area_m2\n            if area_combinada < minimo_combinado:\n                violations.append(\n                    f\"'{mayor.id}' + '{cocina.id}': superficie combinada {area_combinada:.1f}m2 \"\n                    f\"por debajo del minimo {minimo_combinado:.1f}m2 \"\n                    f\"({minimo_mayor:.1f}m2 estancia mayor + {minimo_cocina:.1f}m2 cocina, \"\n                    f\"cada una segun su propia tabla)\"\n                )\n        else:\n            warnings.append(\n                f\"No se pudo determinar el minimo combinado de '{mayor.id}' + '{cocina.id}' \"\n                f\"-- revisar el numero de estancias\"\n            )\n        return violations, warnings\n\n    @staticmethod\n    def _check_vertical_opening(mayor: Room, cocina: Room) -> Tuple[List[str], List[str]]:\n        \"\"\"Apertura vertical minima de relacion entre cocina y salon.\"\"\"\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        if cocina.vertical_opening_m2 is None:\n            warnings.append(\n                f\"'{cocina.id}': falta declarar 'vertical_opening_m2' -- no se puede verificar \"\n                f\"la apertura minima de {APERTURA_VERTICAL_MIN_M2:.1f}m2 con '{mayor.id}'\"\n            )\n        elif cocina.vertical_opening_m2 < APERTURA_VERTICAL_MIN_M2:\n            violations.append(\n                f\"'{cocina.id}': apertura vertical de relación con '{mayor.id}' de \"\n                f\"{cocina.vertical_opening_m2:.1f}m2, por debajo del mínimo \"\n                f\"{APERTURA_VERTICAL_MIN_M2:.1f}m2\"\n            )\n        return violations, warnings\n", "housing_generator/infrastructure/algorithms/constraints/composite_constraint_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n\nclass CompositeConstraintValidator(ConstraintValidatorPort):\n    \"\"\"Ejecuta varios ConstraintValidatorPort sobre el mismo Layout y\n    fusiona sus resultados (violaciones + avisos de todos, unidos).\n\n    Permite que GenerateLayoutUseCase siga aceptando UN solo\n    ConstraintValidatorPort mientras el sistema acumula validadores\n    independientes (nucleo humedo, zonificacion, Tabla 1, Tabla 2...)\n    sin que ninguno tenga que saber de los demas.\n    \"\"\"\n\n    def __init__(self, validators: List[ConstraintValidatorPort]):\n        self._validators = validators\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        return ValidationResult.merge([v.validate(layout) for v in self._validators])\n", "housing_generator/infrastructure/algorithms/constraints/day_night_zoning_validator.py": "from typing import List\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.infrastructure.algorithms.constraints.grouping_constraint_validator import (\n    GroupingConstraintValidator,\n)\nfrom housing_generator.domain.enums import ZoneType, SpaceCategory\n\n# Ver [ARCH:day-night-zoning].\nZONA_DIA_MAX_DISTANCE = 2\nZONA_NOCHE_MAX_DISTANCE = 2\n\n# Excluye circulacion (CORRIDOR/ENTRANCE_HALL): sirve a varias zonas a\n# la vez, no debe atraparse en la agrupacion de una sola. Ver [ARCH:day-night-zoning].\ndef _is_non_circulation_in_zone(zone: ZoneType):\n    return lambda room: room.zone == zone and room.space_category != SpaceCategory.CIRCULACION\n\n\ndef build_day_zone_grouping_validator(\n    graph_builder: AdjacencyGraphBuilderPort,\n    max_distance: int = ZONA_DIA_MAX_DISTANCE,\n) -> GroupingConstraintValidator:\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=_is_non_circulation_in_zone(ZoneType.DAY),\n        max_distance=max_distance,\n        label=\"zona dia\",\n    )\n\n\ndef build_night_zone_grouping_validator(\n    graph_builder: AdjacencyGraphBuilderPort,\n    max_distance: int = ZONA_NOCHE_MAX_DISTANCE,\n) -> GroupingConstraintValidator:\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=_is_non_circulation_in_zone(ZoneType.NIGHT),\n        max_distance=max_distance,\n        label=\"zona noche\",\n    )\n\n\ndef build_day_night_zoning_validators(\n    graph_builder: AdjacencyGraphBuilderPort,\n) -> List[GroupingConstraintValidator]:\n    \"\"\"Conveniencia: las dos validaciones juntas, en una lista.\"\"\"\n    return [\n        build_day_zone_grouping_validator(graph_builder),\n        build_night_zone_grouping_validator(graph_builder),\n    ]\n\n\n# Zonificacion de servicio: extension propia, no en nhv.lua. Ver\n# [ARCH:day-night-zoning].\nZONA_SERVICIO_MAX_DISTANCE = 2\n\n\ndef build_service_zone_grouping_validator(\n    graph_builder: AdjacencyGraphBuilderPort,\n    max_distance: int = ZONA_SERVICIO_MAX_DISTANCE,\n) -> GroupingConstraintValidator:\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=_is_non_circulation_in_zone(ZoneType.SERVICE),\n        max_distance=max_distance,\n        label=\"zona servicio\",\n    )\n", "housing_generator/infrastructure/algorithms/constraints/dormitorio_armario_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_fit_rectangle\n\n# Espacio de armario empotrado, confirmado por investigacion, no en\n# nhv.lua. Ver [ARCH:dormitorio-armario].\nARMARIO_PROFUNDIDAD_MIN_M = 0.60\nARMARIO_LARGO_MIN_PEQUENO_M = 1.00\nARMARIO_LARGO_MIN_GRANDE_M = 1.50\nARMARIO_AREA_UMBRAL_GRANDE_M2 = 8.0\n\n\ndef armario_largo_minimo(area_m2: float) -> float:\n    if area_m2 > ARMARIO_AREA_UMBRAL_GRANDE_M2:\n        return ARMARIO_LARGO_MIN_GRANDE_M\n    return ARMARIO_LARGO_MIN_PEQUENO_M  # incluye <=6m2 como asuncion conservadora\n\n\nclass DormitorioArmarioValidator(ConstraintValidatorPort):\n    \"\"\"Exige que cada dormitorio admita, dentro de su propia forma, un\n    hueco de armario empotrado. No reserva esa superficie -- solo\n    comprueba que la geometría sea capaz de alojarlo. Ver\n    [ARCH:dormitorio-armario].\n    \"\"\"\n\n    ROOM_TYPES = {RoomType.BEDROOM, RoomType.MASTER_BEDROOM}\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type not in self.ROOM_TYPES or not room.is_placed:\n                continue\n\n            largo = armario_largo_minimo(room.dimensions.area_m2)\n            cabe = can_fit_rectangle(room.boundary.polygon, largo, ARMARIO_PROFUNDIDAD_MIN_M)\n\n            if cabe is False:\n                violations.append(\n                    f\"'{room.id}': no admite el hueco de armario empotrado minimo \"\n                    f\"({largo:.2f}m x {ARMARIO_PROFUNDIDAD_MIN_M:.2f}m) dentro de su \"\n                    f\"propia forma\"\n                )\n            elif cabe is None:\n                warnings.append(\n                    f\"'{room.id}': forma no rectangular, no se puede verificar el \"\n                    f\"hueco de armario empotrado\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/escalera_alineacion_validator.py": "from typing import List, Optional\nfrom shapely.geometry import Polygon\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\n\n# Ver [ARCH:escalera-alineacion].\nESCALERA_ALINEACION_MIN_OVERLAP_RATIO = 0.90\n\n\nclass EscaleraAlineacionValidator(ConstraintValidatorPort):\n    \"\"\"Exige que la huella de STAIRCASE en esta planta se solape\n    sustancialmente (≥90%) con la huella ya resuelta de la planta de\n    abajo. Ver [ARCH:escalera-alineacion].\"\"\"\n\n    def __init__(self, reference_boundary: Optional[Polygon], floor_below_exists: bool = True):\n        self._reference = reference_boundary\n        self._floor_below_exists = floor_below_exists\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        staircases = [r for r in layout.rooms if r.room_type == RoomType.STAIRCASE and r.is_placed]\n\n        if not self._floor_below_exists:\n            return ValidationResult()  # planta mas baja del edificio -- nada que alinear\n\n        if self._reference is None:\n            if staircases:\n                return ValidationResult(violations=[\n                    \"Esta planta declara escalera, pero la planta inferior no tiene ninguna \"\n                    \"-- la escalera no arranca de ningun sitio\"\n                ])\n            return ValidationResult()  # ninguna de las dos plantas tiene escalera -- correcto\n\n        if not staircases:\n            return ValidationResult(violations=[\n                \"La planta inferior tiene escalera pero esta planta no declara ninguna \"\n                \"RoomType.STAIRCASE -- la escalera no puede quedar sin continuidad\"\n            ])\n\n        violations: List[str] = []\n        for stair in staircases:\n            intersection_area = stair.boundary.polygon.intersection(self._reference).area\n            smaller_area = min(stair.boundary.polygon.area, self._reference.area)\n            ratio = intersection_area / smaller_area if smaller_area > 0 else 0.0\n            if ratio < ESCALERA_ALINEACION_MIN_OVERLAP_RATIO:\n                violations.append(\n                    f\"'{stair.id}': solapamiento con la escalera de la planta inferior de \"\n                    f\"{ratio:.0%}, por debajo del minimo exigido \"\n                    f\"({ESCALERA_ALINEACION_MIN_OVERLAP_RATIO:.0%})\"\n                )\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/escalera_ancho_libre_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# CTE DB-SUA 1, escalera de uso restringido (confirmado, ver\n# docs/fuentes/niveles_plantas.md) -- 0.80m, no el de uso general (1.00-1.20m).\nESCALERA_ANCHO_LIBRE_MIN_M = 0.80\n\n\nclass EscaleraAnchoLibreValidator(ConstraintValidatorPort):\n    \"\"\"Ancho libre minimo de RoomType.STAIRCASE (0.80m, uso restringido\n    CTE DB-SUA 1). No comprueba huella/contrahuella de peldanos\n    (geometria de escalon, fuera de alcance -- ver niveles_plantas.md)\n    ni alineacion entre plantas (ver EscaleraAlineacionValidator, aparte).\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n        for room in layout.rooms:\n            if room.room_type != RoomType.STAIRCASE or not room.is_placed:\n                continue\n            v, w = evaluate_minimum_width(\n                room.id, room.boundary.polygon, ESCALERA_ANCHO_LIBRE_MIN_M,\n                violation_message=(\n                    f\"ancho libre por debajo del minimo de escalera de uso \"\n                    f\"restringido ({ESCALERA_ANCHO_LIBRE_MIN_M:.2f}m, CTE DB-SUA 1)\"\n                ),\n                warning_message=\"forma no rectangular, no se puede verificar el ancho libre de escalera\",\n            )\n            violations.extend(v)\n            warnings.extend(w)\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/espacio_acceso_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_inscribe_square\n\n# Espacio de acceso interior, cuadrado 1.50m. Ver [ARCH:espacio-acceso].\nESPACIO_ACCESO_CUADRADO_M = 1.50\n\n\nclass EspacioAccesoValidator(ConstraintValidatorPort):\n    \"\"\"Cuadrado inscribible de 1.50m en el recibidor (ENTRANCE_HALL).\n    Sin ENTRANCE_HALL en el programa, no aplica. Ver\n    [ARCH:espacio-acceso].\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if room.room_type != RoomType.ENTRANCE_HALL:\n                continue\n            if not room.is_placed:\n                continue\n\n            cumple = can_inscribe_square(room.boundary.polygon, ESPACIO_ACCESO_CUADRADO_M)\n            if cumple is False:\n                violations.append(\n                    f\"'{room.id}': no admite el cuadrado de {ESPACIO_ACCESO_CUADRADO_M:.2f}m \"\n                    f\"de lado exigido en el espacio de acceso interior\"\n                )\n            elif cumple is None:\n                warnings.append(\n                    f\"'{room.id}': forma no rectangular, no se puede verificar el cuadrado \"\n                    f\"de acceso interior de {ESPACIO_ACCESO_CUADRADO_M:.2f}m\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/estancia_minimum_area_validator.py": "from typing import List, Dict, Optional, Tuple\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.enums import SpaceCategory, RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_inscribe_square\n\n# Tabla 1 (A.3.2.1 en nhv.lua / Decreto 29/2010): superficie util minima\n# POR ESTANCIA segun el puesto que ocupa por tamano (E1 = la mayor, E2 =\n# la segunda...), NO una superficie total. Portado literalmente de la\n# fuente normativa -- estos numeros no son heuristica de este proyecto.\nTABLA_1: Dict[int, List[float]] = {\n    1: [25],\n    2: [16, 12],\n    3: [18, 12, 8],\n    4: [20, 12, 8, 8],\n    5: [22, 12, 8, 8, 6],\n}\nTABLA_1_MAS_DE_CINCO: List[float] = [25, 12, 8, 8, 8]  # E1..E5 fijos si hay >5 estancias\nMINIMO_ESTANCIA_ADICIONAL = 6.0  # E6, E7... cuando hay mas de 5\n\n# A.3.2.1.a: lado del cuadrado inscribible exigido a la estancia mayor\nCUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M = 3.30\n\n\ndef minimo_estancia(num_estancias: int, indice: int) -> Optional[float]:\n    \"\"\"Minimo de superficie util para la estancia que ocupa el puesto\n    `indice` (1 = la mayor) en una vivienda con `num_estancias` estancias.\"\"\"\n    if num_estancias <= 5:\n        fila = TABLA_1.get(num_estancias)\n        if fila is None or indice > len(fila):\n            return None\n        return fila[indice - 1]\n    if indice <= 5:\n        return TABLA_1_MAS_DE_CINCO[indice - 1]\n    return MINIMO_ESTANCIA_ADICIONAL\n\n\nclass EstanciaMinimumAreaValidator(ConstraintValidatorPort):\n    \"\"\"Tabla 1: superficie mínima por puesto de tamaño entre las\n    estancias (space_category ESTANCIA). La estancia mayor para el\n    cuadrado inscribible (A.3.2.1.a) es siempre el salón. Ver\n    [ARCH:estancia-minimum-area].\n    \"\"\"\n\n    def __init__(\n        self,\n        total_num_estancias_override: Optional[int] = None,\n        global_rank_override: Optional[Dict[str, int]] = None,\n    ):\n        self._total_override = total_num_estancias_override\n        self._global_rank = global_rank_override\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        estancias = [r for r in layout.rooms if r.space_category == SpaceCategory.ESTANCIA]\n        if not estancias:\n            return ValidationResult()\n\n        ordenadas = sorted(estancias, key=lambda r: r.dimensions.area_m2, reverse=True)\n        num_estancias = self._total_override if self._total_override is not None else len(ordenadas)\n\n        violations = self._check_rank_minimums(ordenadas, num_estancias)\n        cuadrado_violations, warnings = self._check_estancia_mayor_cuadrado(estancias, ordenadas)\n        violations.extend(cuadrado_violations)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n\n    def _check_rank_minimums(self, ordenadas: List[Room], num_estancias: int) -> List[str]:\n        \"\"\"Tabla 1 propiamente dicha: superficie minima por puesto de\n        tamano (E1=mayor, E2=segunda...).\"\"\"\n        violations: List[str] = []\n        for local_i, room in enumerate(ordenadas, start=1):\n            puesto = self._global_rank.get(room.id, local_i) if self._global_rank else local_i\n            minimo = minimo_estancia(num_estancias, puesto)\n            if minimo is not None and room.dimensions.area_m2 < minimo:\n                violations.append(\n                    f\"'{room.id}': {room.dimensions.area_m2:.1f}m2, por debajo del minimo de \"\n                    f\"Tabla 1 para el puesto {puesto} de {num_estancias} estancias ({minimo:.1f}m2)\"\n                )\n        return violations\n\n    def _check_estancia_mayor_cuadrado(\n        self, estancias: List[Room], ordenadas: List[Room],\n    ) -> Tuple[List[str], List[str]]:\n        \"\"\"A.3.2.1.a: cuadrado inscribible de 3.30m de lado en la\n        estancia mayor (siempre el salon, RoomType.LIVING_ROOM).\"\"\"\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        mayor = next((r for r in estancias if r.room_type == RoomType.LIVING_ROOM), None)\n        if mayor is None:\n            if self._total_override is not None:\n                # multi-planta sin salon en ESTA planta = caso normal\n                # (esta en otra planta). Ver [ARCH:estancia-minimum-area].\n                return violations, warnings\n            mayor = ordenadas[0]\n            warnings.append(\n                f\"No hay 'living_room' declarado entre las estancias; se usa '{mayor.id}' \"\n                f\"(la de mayor area) como sustituto de la estancia mayor para el cuadrado \"\n                f\"inscribible -- confirmar si esto es correcto para este programa\"\n            )\n\n        if mayor.is_placed:\n            cabe = can_inscribe_square(mayor.boundary.polygon, CUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M)\n            if cabe is False:\n                violations.append(\n                    f\"'{mayor.id}' (estancia mayor): no cabe el cuadrado inscribible de \"\n                    f\"{CUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M:.2f}m de lado\"\n                )\n            elif cabe is None:\n                warnings.append(\n                    f\"'{mayor.id}' (estancia mayor): forma no rectangular, no se puede \"\n                    f\"verificar el cuadrado inscribible de {CUADRADO_INSCRIBIBLE_ESTANCIA_MAYOR_LADO_M:.2f}m \"\n                    f\"con la geometria computacional implementada actualmente\"\n                )\n\n        return violations, warnings\n", "housing_generator/infrastructure/algorithms/constraints/exterior_contact_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.infrastructure.geometry.shapely_utils import count_exterior_sides\n\n# Umbral de contacto con el exterior (0.3m) -- distinto y mayor que el\n# umbral de adyacencia interior entre estancias (0.1m), confirmado por\n# el usuario en la sesion de nucleo humedo/grafo de adyacencia.\nEXTERIOR_MIN_CONTACT_M = 0.3\n\n\nclass ExteriorContactValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba que cada estancia tenga al menos\n    `room.min_exterior_sides` lados con contacto real al límite del\n    solar. Ver [ARCH:exterior-contact].\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        # borde del area edificable, no de la parcela legal completa.\n        # Ver [ARCH:exterior-contact].\n        lot_polygon = layout.lot.buildable_area.polygon\n        excluded_segments = layout.lot.medianera_boundary_segments()\n\n        for room in layout.rooms:\n            if not room.is_placed or room.min_exterior_sides <= 0:\n                continue\n\n            lados = count_exterior_sides(\n                room.boundary.polygon, lot_polygon, EXTERIOR_MIN_CONTACT_M,\n                excluded_segments=excluded_segments,\n            )\n\n            if lados is None:\n                warnings.append(\n                    f\"'{room.id}': forma no rectangular, no se puede verificar el \"\n                    f\"contacto exterior\"\n                )\n            elif lados < room.min_exterior_sides:\n                violations.append(\n                    f\"'{room.id}': {lados} lado(s) con contacto exterior, \"\n                    f\"por debajo del minimo exigido ({room.min_exterior_sides})\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/grouping_constraint_validator.py": "from typing import Callable, List, Optional, Union\nimport networkx as nx\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.entities.room import Room\n\n\nclass GroupingConstraintValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba que las estancias que cumplen `predicate` estén a\n    distancia (paredes a cruzar) ≤ `max_distance` entre sí, sobre el\n    grafo de adyacencia real. Mecanismo genérico: sirve tanto para\n    núcleo húmedo como para zonificación día/noche/servicio, solo\n    cambian los parámetros. `max_distance` puede ser un entero fijo, o\n    una función del número de miembros del grupo (para exigencias que\n    se relajan con grupos más grandes -- ver [ARCH:nucleo-humedo-distancia]).\n    \"\"\"\n\n    def __init__(\n        self,\n        graph_builder: AdjacencyGraphBuilderPort,\n        predicate: Callable[[Room], bool],\n        max_distance: Union[int, Callable[[int], int]],\n        label: str,\n    ):\n        self._graph_builder = graph_builder\n        self._predicate = predicate\n        self._max_distance = max_distance\n        self._label = label\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        graph = self._graph_builder.build(layout)\n        members = [r.id for r in layout.rooms if r.is_placed and self._predicate(r)]\n        max_distance = self._max_distance(len(members)) if callable(self._max_distance) else self._max_distance\n\n        violations: List[str] = []\n        for i, room_a_id in enumerate(members):\n            for room_b_id in members[i + 1:]:\n                distance = self._distance(graph, room_a_id, room_b_id)\n                if distance is None:\n                    violations.append(\n                        f\"'{room_a_id}' y '{room_b_id}' ({self._label}) no estan conectadas \"\n                        f\"en el grafo de adyacencia real\"\n                    )\n                elif distance > max_distance:\n                    violations.append(\n                        f\"'{room_a_id}' y '{room_b_id}' ({self._label}) estan a distancia \"\n                        f\"{distance}, por encima del maximo permitido ({max_distance})\"\n                    )\n        return ValidationResult(violations=violations)\n\n    @staticmethod\n    def _distance(graph: nx.Graph, a: str, b: str) -> Optional[int]:\n        try:\n            return nx.shortest_path_length(graph, a, b)\n        except (nx.NetworkXNoPath, nx.NodeNotFound):\n            return None\n", "housing_generator/infrastructure/algorithms/constraints/nucleo_humedo_vertical_validator.py": "from typing import List\nfrom shapely.geometry import Polygon\nfrom shapely.ops import unary_union\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n# Continuidad de bajantes. Ver [ARCH:nucleo-humedo-vertical].\n\n\nclass NucleoHumedoVerticalValidator(ConstraintValidatorPort):\n    \"\"\"Cada estancia húmeda debe solapar en planta con alguna húmeda\n    de la planta inmediatamente inferior. Sin referencia, no aplica.\n    Ver [ARCH:nucleo-humedo-vertical].\"\"\"\n\n    def __init__(self, reference_wet_boundaries: List[Polygon]):\n        self._reference_union = unary_union(reference_wet_boundaries) if reference_wet_boundaries else None\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        if self._reference_union is None:\n            return ValidationResult()\n\n        wet_rooms = [r for r in layout.rooms if r.is_wet and r.is_placed]\n        violations: List[str] = []\n        for room in wet_rooms:\n            overlap = room.boundary.polygon.intersection(self._reference_union).area\n            if overlap <= 0:\n                violations.append(\n                    f\"'{room.id}': sin solape en planta con ninguna estancia humeda de la \"\n                    f\"planta inferior -- continuidad de bajantes rota\"\n                )\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/pasillo_topologia_validator.py": "from typing import List, Set\nimport networkx as nx\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType, SpaceCategory\n\n# Puntos de corte sobre adyacencia geometrica real, no grafo de\n# puertas. Ver [ARCH:pasillo-topologia].\nEXENTOS_DE_LA_REGLA = {RoomType.LIVING_ROOM, RoomType.DINING_ROOM}\n\n\nclass PasilloTopologiaValidator(ConstraintValidatorPort):\n    \"\"\"Ninguna estancia protegida (no circulación, no exenta) puede ser\n    un punto de corte obligado hacia otra estancia protegida. Ver\n    [ARCH:pasillo-topologia].\"\"\"\n\n    def __init__(self, graph_builder: AdjacencyGraphBuilderPort):\n        self._graph_builder = graph_builder\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        graph = self._graph_builder.build(layout)\n        rooms_by_id = {r.id: r for r in layout.rooms if r.is_placed}\n\n        circulation_ids: Set[str] = {\n            rid for rid in graph.nodes\n            if rooms_by_id[rid].space_category == SpaceCategory.CIRCULACION\n        }\n        if not circulation_ids:\n            return ValidationResult()  # nada de circulacion en el grafo -- no hay nada que comprobar\n\n        protected_ids: Set[str] = {\n            rid for rid in graph.nodes\n            if rooms_by_id[rid].space_category != SpaceCategory.CIRCULACION\n            and rooms_by_id[rid].room_type not in EXENTOS_DE_LA_REGLA\n        }\n\n        violations: List[str] = []\n        for candidate_id in protected_ids:\n            reduced = graph.copy()\n            reduced.remove_node(candidate_id)\n\n            # componentes conexas calculadas UNA vez por candidato, no una\n            # vez por PAR -- bug de rendimiento real, encontrado con\n            # cProfile a escala mayor (13 estancias): node_connected_component\n            # hace su propia busqueda BFS/DFS completa cada vez que se\n            # llama, y se llamaba una vez POR CADA other_id, recalculando\n            # la misma componente para estancias que ya estaban juntas.\n            # nx.connected_components ya da TODAS las componentes en una\n            # sola pasada -- el resto es una simple consulta de diccionario.\n            component_by_node = {\n                node: component\n                for component in nx.connected_components(reduced)\n                for node in component\n            }\n\n            for other_id in protected_ids:\n                if other_id == candidate_id or other_id not in component_by_node:\n                    continue\n                reachable = component_by_node[other_id]\n                if not (reachable & circulation_ids):\n                    violations.append(\n                        f\"'{rooms_by_id[candidate_id].id}' actúa como paso obligado hacia \"\n                        f\"'{rooms_by_id[other_id].id}' -- sin ella, esta última queda \"\n                        f\"desconectada de toda circulación\"\n                    )\n\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/proporcion_maxima_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\n\n# NO NORMATIVO -- criterio de diseno confirmado explicitamente, no del\n# Decreto 29/2010. Ver [ARCH:proporcion-maxima].\nPROPORCION_MAXIMA = 2.5\n\n\nclass ProporcionMaximaValidator(ConstraintValidatorPort):\n    \"\"\"Proporción ancho:alto máxima NO normativa (2.5:1) para\n    CUALQUIER estancia -- red de seguridad general contra tiras finas\n    que cumplen el ancho mínimo pero son absurdas en proporción. Ver\n    [ARCH:proporcion-maxima].\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        for room in layout.rooms:\n            if not room.is_placed:\n                continue\n            bounds = room.boundary.polygon.bounds\n            width = bounds[2] - bounds[0]\n            height = bounds[3] - bounds[1]\n            if width <= 0 or height <= 0:\n                continue\n            ratio = max(width, height) / min(width, height)\n            if ratio > PROPORCION_MAXIMA:\n                violations.append(\n                    f\"'{room.id}': proporcion {ratio:.1f}:1 ({width:.2f}m x {height:.2f}m) por encima \"\n                    f\"del maximo practico de {PROPORCION_MAXIMA:.1f}:1 (NO normativo -- criterio de \"\n                    f\"ingenieria confirmado, evita formas alargadas absurdas)\"\n                )\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/servicio_minimum_area_validator.py": "from typing import List, Dict, Optional\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import SpaceCategory\n\n# Tabla 2 (A.3.2.2). Ver [ARCH:servicio-minimum-area].\nTABLA_2: Dict[int, Dict[str, float]] = {\n    1: {\"cocina\": 5, \"bano\": 5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 1},\n    2: {\"cocina\": 7, \"bano\": 5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 2},\n    3: {\"cocina\": 7, \"bano\": 5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 3},\n    4: {\"cocina\": 9, \"bano\": 5, \"aseo\": 1.5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 4},\n    5: {\"cocina\": 9, \"bano\": 5, \"aseo\": 1.5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 5},\n}\nTABLA_2_MAS_DE_CINCO: Dict[str, float] = {\n    \"cocina\": 10, \"bano\": 5, \"aseo\": 1.5, \"lavadero\": 1.5, \"tendedero\": 1.5, \"almacenamiento\": 6,\n}\n\n\ndef tabla_servicios_para(num_estancias: int) -> Dict[str, float]:\n    \"\"\"Fila de Tabla 2 correspondiente a `num_estancias` (numero de\n    estancias -- categoria ESTANCIA, no numero total de piezas).\"\"\"\n    if num_estancias in TABLA_2:\n        return TABLA_2[num_estancias]\n    if num_estancias < 1:\n        return TABLA_2[1]\n    return TABLA_2_MAS_DE_CINCO\n\n\nclass ServicioMinimumAreaValidator(ConstraintValidatorPort):\n    \"\"\"Tabla 2: superficie mínima por tipo de servicio (cocina, baño,\n    aseo, lavadero, tendedero, almacenamiento), según número de\n    estancias. Ver [ARCH:servicio-minimum-area].\"\"\"\n\n    def __init__(self, total_num_estancias_override: Optional[int] = None):\n        self._total_override = total_num_estancias_override\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        local_count = sum(1 for r in layout.rooms if r.space_category == SpaceCategory.ESTANCIA)\n        num_estancias = self._total_override if self._total_override is not None else local_count\n        tabla = tabla_servicios_para(num_estancias)\n\n        violations: List[str] = []\n        for room in layout.rooms:\n            if room.service_subtype is None:\n                continue\n            if room.integrated_in_largest_room:\n                continue  # se valida en CocinaIntegradaValidator\n            minimo = tabla.get(room.service_subtype)\n            if minimo is None:\n                continue\n            if room.dimensions.area_m2 < minimo:\n                violations.append(\n                    f\"'{room.id}' ({room.service_subtype}): {room.dimensions.area_m2:.1f}m2, \"\n                    f\"por debajo del minimo de Tabla 2 para {num_estancias} estancias \"\n                    f\"({minimo:.1f}m2)\"\n                )\n\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/trastero_minimum_area_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import evaluate_minimum_width\n\n# B.2.5: superficie fija. Ver [ARCH:trastero-minimum-area].\nTRASTERO_AREA_MIN_M2 = 4.00\nTRASTERO_ANCHO_LIBRE_MIN_M = 1.60\n\n\nclass TrasteroMinimumAreaValidator(ConstraintValidatorPort):\n    \"\"\"B.2.5: superficie mínima fija y ancho libre mínimo para\n    trasteros (STORAGE_ROOM) -- distinto de \"almacenamiento\" (Tabla 2,\n    escala con estancias). Ver [ARCH:trastero-minimum-area].\"\"\"\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n        for room in layout.rooms:\n            if room.room_type != RoomType.STORAGE_ROOM:\n                continue\n            if room.dimensions.area_m2 < TRASTERO_AREA_MIN_M2:\n                violations.append(\n                    f\"'{room.id}': {room.dimensions.area_m2:.1f}m2, por debajo del minimo \"\n                    f\"fijo de B.2.5 para trasteros ({TRASTERO_AREA_MIN_M2:.1f}m2)\"\n                )\n            if room.is_placed:\n                v, w = evaluate_minimum_width(\n                    room.id, room.boundary.polygon, TRASTERO_ANCHO_LIBRE_MIN_M,\n                    violation_message=(\n                        f\"ancho libre por debajo del minimo de B.2.5 ({TRASTERO_ANCHO_LIBRE_MIN_M:.2f}m)\"\n                    ),\n                    warning_message=\"forma no rectangular, no se puede verificar el ancho libre de trastero (B.2.5)\",\n                )\n                violations.extend(v)\n                warnings.extend(w)\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/viabilidad_urbanistica_validator.py": "\"\"\"Comprobación de viabilidad urbanística -- se ejecuta ANTES de\nintentar generar nada, no después de que la búsqueda falle sola.\nMismo espíritu que un \"informe de viabilidad\" real (ver\ndocs/referencia/generador/ para el contexto completo de por qué se\nañadió esto) -- y el mismo patrón que usan herramientas reales de\ndiseño generativo (Finch: \"como un corrector ortográfico para\nplantas\", avisa al instante contra reglas de área/ratios).\n\nA diferencia del resto de validadores (`ConstraintValidatorPort`,\noperan sobre un `Layout` ya colocado con geometría real), este\ncomprueba SUPERFICIES DECLARADAS contra los parámetros urbanísticos\nde la parcela -- no necesita esperar a que nada se coloque.\n\nCada parámetro es opcional (`None` = sin esa restricción, mismo\nconvenio que `Lot.retranqueo_m`) -- los valores concretos vienen\nsiempre del usuario (de su PGOU/ficha urbanística real), nunca\ninventados aquí. Ver [ARCH:viabilidad-urbanistica].\n\"\"\"\nfrom typing import List\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.application.ports.viabilidad_urbanistica_validator_port import (\n    ViabilidadUrbanisticaValidatorPort,\n)\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.program import Program\n\n\nclass ViabilidadUrbanisticaValidator(ViabilidadUrbanisticaValidatorPort):\n    \"\"\"Comprueba edificabilidad, ocupación, altura y frente de fachada\n    -- los cuatro parámetros estándar de una ficha urbanística real\n    (confirmado contra varios PGOU municipales, no solo teoría).\n    Ver [ARCH:viabilidad-urbanistica].\"\"\"\n\n    def validate(self, program: Program, lot: Lot, num_plantas: int) -> ValidationResult:\n        violations: List[str] = []\n        superficie_parcela = lot.boundary.polygon.area\n\n        if lot.coeficiente_edificabilidad is not None:\n            techo_declarado = sum(r.dimensions.area_m2 for r in program.rooms)\n            techo_maximo = lot.coeficiente_edificabilidad * superficie_parcela\n            if techo_declarado > techo_maximo:\n                violations.append(\n                    f\"Edificabilidad superada: el programa declara {techo_declarado:.1f}m² de \"\n                    f\"techo (todas las plantas), pero el coeficiente de edificabilidad \"\n                    f\"({lot.coeficiente_edificabilidad:.2f} m²t/m²s) sobre {superficie_parcela:.1f}m² \"\n                    f\"de parcela solo permite {techo_maximo:.1f}m²\"\n                )\n\n        if lot.ocupacion_maxima_pct is not None:\n            # estimacion de la huella: la planta con MAS superficie\n            # declarada de todas, no siempre la baja -- mas\n            # conservador si alguna planta superior resulta mayor\n            # (voladizos, por ejemplo). Chequeo \"a mano\" deliberado\n            # (FAR/ocupacion x superficie), no un solver de envolvente\n            # preciso -- mismo nivel de sofisticacion que un chequeo\n            # rapido de viabilidad, no un estudio tecnico completo.\n            superficie_por_planta: dict = {}\n            for room in program.rooms:\n                nivel = room.level.value if room.level else \"sin_nivel\"\n                superficie_por_planta[nivel] = superficie_por_planta.get(nivel, 0.0) + room.dimensions.area_m2\n            huella_estimada = max(superficie_por_planta.values()) if superficie_por_planta else 0.0\n            huella_maxima = (lot.ocupacion_maxima_pct / 100.0) * superficie_parcela\n            if huella_estimada > huella_maxima:\n                violations.append(\n                    f\"Ocupación superada: la planta más grande declara {huella_estimada:.1f}m² \"\n                    f\"(estimación de la huella), pero la ocupación máxima \"\n                    f\"({lot.ocupacion_maxima_pct:.0f}%) sobre {superficie_parcela:.1f}m² de \"\n                    f\"parcela solo permite {huella_maxima:.1f}m²\"\n                )\n\n        if lot.altura_maxima_plantas is not None and num_plantas > lot.altura_maxima_plantas:\n            violations.append(\n                f\"Altura superada: el programa declara {num_plantas} plantas, pero la altura \"\n                f\"máxima permitida es de {lot.altura_maxima_plantas} plantas\"\n            )\n\n        if lot.frente_minimo_m is not None and lot.frente_actual_m < lot.frente_minimo_m:\n            violations.append(\n                f\"Frente de fachada insuficiente: la parcela mide {lot.frente_actual_m:.1f}m \"\n                f\"en el lado de calle ('{lot.street_side}'), pero el frente mínimo exigido es \"\n                f\"de {lot.frente_minimo_m:.1f}m\"\n            )\n\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/vivienda_accesible_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\nfrom housing_generator.infrastructure.geometry.shapely_utils import can_inscribe_square, evaluate_minimum_width\n\n# DB-SUA Anejo A + Base 5.4 Galicia, OPT-IN. Ver [ARCH:vivienda-accesible].\nCIRCULO_GIRO_ACCESIBLE_M = 1.50  # DB-SUA Anejo A / Base 5.4\nPASILLO_ACCESIBLE_ANCHO_M = 1.20  # Base 5.4 -- mas exigente que A.3.2.3\n\n# Ver [ARCH:vivienda-accesible] para el criterio de esta lista.\nTIPOS_CON_CIRCULO_GIRO = {\n    RoomType.LIVING_ROOM, RoomType.DINING_ROOM, RoomType.BEDROOM,\n    RoomType.MASTER_BEDROOM, RoomType.KITCHEN, RoomType.BATHROOM,\n}\n\n\nclass ViviendaAccesibleValidator(ConstraintValidatorPort):\n    \"\"\"Vivienda declarada accesible (DB-SUA Anejo A + Base 5.4 Galicia)\n    -- solo activo con `activo=True`. Exige círculo de giro Ø1.50m en\n    estancias habitables + baño, y pasillo ≥1.20m (además del mínimo\n    general, no lo sustituye). Ver [ARCH:vivienda-accesible].\"\"\"\n\n    def __init__(self, activo: bool = False):\n        self.activo = activo\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        violations: List[str] = []\n        warnings: List[str] = []\n\n        if not self.activo:\n            return ValidationResult(violations=violations, warnings=warnings)\n\n        for room in layout.rooms:\n            if not room.is_placed:\n                continue\n\n            if room.room_type in TIPOS_CON_CIRCULO_GIRO:\n                cumple = can_inscribe_square(room.boundary.polygon, CIRCULO_GIRO_ACCESIBLE_M)\n                if cumple is False:\n                    violations.append(\n                        f\"'{room.id}': vivienda accesible, no admite el circulo de giro \"\n                        f\"de Ø{CIRCULO_GIRO_ACCESIBLE_M:.2f}m exigido (DB-SUA/Base 5.4)\"\n                    )\n                elif cumple is None:\n                    warnings.append(\n                        f\"'{room.id}': forma no rectangular, no se puede verificar el \"\n                        f\"circulo de giro de vivienda accesible\"\n                    )\n\n            if room.room_type == RoomType.CORRIDOR:\n                v, w = evaluate_minimum_width(\n                    room.id, room.boundary.polygon, PASILLO_ACCESIBLE_ANCHO_M,\n                    violation_message=(\n                        f\"ancho libre por debajo del minimo de vivienda accesible \"\n                        f\"({PASILLO_ACCESIBLE_ANCHO_M:.2f}m, Base 5.4 -- mas exigente que \"\n                        f\"el general de A.3.2.3)\"\n                    ),\n                    warning_message=\"forma no rectangular, no se puede verificar el ancho de pasillo accesible\",\n                )\n                violations.extend(v)\n                warnings.extend(w)\n\n        return ValidationResult(violations=violations, warnings=warnings)\n", "housing_generator/infrastructure/algorithms/constraints/vivienda_minima_validator.py": "from typing import List\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.application.dto.validation_result import ValidationResult\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import RoomType\n\n# Programa minimo: Decreto 29/2010, I.A.2.3. Ver [ARCH:vivienda-minima].\n\n\nclass ViviendaMinimaValidator(ConstraintValidatorPort):\n    \"\"\"Comprueba que el Program contenga las seis piezas del programa\n    mínimo legal: salón, cocina, baño completo, lavadero, tendedero y\n    almacenamiento general. Ver [ARCH:vivienda-minima].\"\"\"\n\n    _REQUIRED = [\n        (RoomType.LIVING_ROOM, \"un salón (LIVING_ROOM) -- una estancia de estar-comedor\"),\n        (RoomType.KITCHEN, \"una cocina (KITCHEN)\"),\n        (RoomType.BATHROOM, \"un baño completo (BATHROOM) -- un aseo (TOILET) no sustituye este requisito\"),\n        (RoomType.LAUNDRY, \"un lavadero (LAUNDRY)\"),\n        (RoomType.DRYING_AREA, \"un tendedero (DRYING_AREA)\"),\n        (RoomType.STORAGE, \"un espacio de almacenamiento general (STORAGE)\"),\n    ]\n\n    def validate(self, layout: Layout) -> ValidationResult:\n        types_present = {r.room_type for r in layout.rooms}\n        violations: List[str] = [\n            f\"Programa mínimo incompleto: falta {descripcion}\"\n            for room_type, descripcion in self._REQUIRED\n            if room_type not in types_present\n        ]\n        return ValidationResult(violations=violations)\n", "housing_generator/infrastructure/algorithms/constraints/wet_core_validator.py": "from housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.infrastructure.algorithms.constraints.grouping_constraint_validator import (\n    GroupingConstraintValidator,\n)\n\n# Nucleo humedo: todas las piezas humedas (cocina, bano, lavadero...)\n# deben quedar cerca entre si (confirmado por `nhv.lua`: bajantes\n# cortos, ahorro real en fontaneria). Sin fuente normativa que\n# especifique un numero concreto (investigado contra CTE DB-HS 5,\n# evacuacion de aguas -- da distancias METRICAS de tuberia dentro de\n# un mismo cuarto humedo, nunca una distancia entre estancias\n# distintas ni un umbral que varie segun cuantas humedas haya).\n#\n# Distancia GRADUADA segun el numero de humedas -- criterio de\n# ingenieria confirmado explicitamente (NO normativo, mismo tipo de\n# decision que AnchoLibrePractico/ProporcionMaxima), tras un\n# diagnostico real: con 2 humedas, distancia 1 (pared compartida)\n# convergia en el 80% de semillas probadas; con 3+ humedas, la MISMA\n# exigencia (las 3 mutuamente a distancia 1, un \"molinillo\" geometrico\n# mucho mas restrictivo) bajaba la convergencia a 7-20%. Relajado a\n# distancia 2 a partir de 3 humedas -- sigue siendo \"cerca\" (maximo 1\n# estancia de por medio), solo deja de exigir contacto directo mutuo\n# entre las tres a la vez. Ver [ARCH:nucleo-humedo-distancia].\nNUCLEO_HUMEDO_MAX_DISTANCE_DOS = 1\nNUCLEO_HUMEDO_MAX_DISTANCE_TRES_O_MAS = 2\n\n\ndef _nucleo_humedo_max_distance(num_humedas: int) -> int:\n    return NUCLEO_HUMEDO_MAX_DISTANCE_DOS if num_humedas <= 2 else NUCLEO_HUMEDO_MAX_DISTANCE_TRES_O_MAS\n\n\ndef build_wet_core_validator(graph_builder: AdjacencyGraphBuilderPort) -> GroupingConstraintValidator:\n    \"\"\"Fabrica el validador de nucleo humedo: primer caso concreto del\n    mecanismo generico GroupingConstraintValidator.\"\"\"\n    return GroupingConstraintValidator(\n        graph_builder=graph_builder,\n        predicate=lambda room: room.is_wet,\n        max_distance=_nucleo_humedo_max_distance,\n        label=\"nucleo humedo\",\n    )\n", "housing_generator/infrastructure/algorithms/layout_generation/__init__.py": "", "housing_generator/infrastructure/algorithms/layout_generation/btree_layout_generator.py": "import copy\nimport math\nimport random\nfrom typing import Dict, List, Optional, Tuple\n\nfrom shapely.affinity import translate\nfrom shapely.geometry import Polygon\nfrom shapely.ops import unary_union\n\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.exceptions import LayoutGenerationError\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.infrastructure.geometry.shapely_utils import polygon_to_shapes\nfrom housing_generator.infrastructure.algorithms.layout_generation.btree_partition import (\n    BStarNode,\n    build_random_tree,\n    compute_positions,\n    random_neighbor,\n)\nfrom housing_generator.infrastructure.algorithms.layout_generation.soft_constraint_scorer import (\n    SoftConstraintScorer,\n)\n\n\nclass BTreeLayoutGenerator(LayoutGeneratorPort):\n    \"\"\"Genera el layout con un árbol B* (Chang & Chang 2000) en vez del\n    árbol de partición (`SimulatedAnnealingLayoutGenerator`) -- pieza\n    intercambiable vía `LayoutGeneratorPort`, en paralelo al sistema\n    actual, no en sustitución (Fase 4 de la migración planificada en\n    `docs/referencia/generador/prototipo-btree/`).\n\n    Misma función objetivo que el generador actual (comparación\n    lexicográfica duro/blando, duro siempre dominante) y mismo bucle\n    de recocido -- lo que cambia es la representación geométrica: en\n    vez de particionar un rectángulo, se empaquetan las estancias\n    directamente, lo que permite siluetas no rectangulares (en L, en\n    U, con patio interior) que el árbol de partición no puede\n    representar por definición. Ver [ARCH:btree-partition].\n    \"\"\"\n\n    def __init__(\n        self,\n        constraint_validator: ConstraintValidatorPort,\n        max_iterations: int = 2000,\n        initial_temperature: float = 10.0,\n        cooling_rate: float = 0.995,\n        seed: Optional[int] = None,\n        soft_constraint_scorer: Optional[SoftConstraintScorer] = None,\n    ):\n        self._constraint_validator = constraint_validator\n        self._max_iterations = max_iterations\n        self._initial_temperature = initial_temperature\n        self._cooling_rate = cooling_rate\n        self._seed = seed\n        self._soft_scorer = soft_constraint_scorer\n\n    def generate(self, program: Program, lot: Lot, zones: List[Zone]) -> Layout:\n        rng = random.Random(self._seed)  # recreado en cada llamada, seed reproducible siempre\n        room_ids = [room.id for room in program.rooms]\n        areas = {room.id: room.dimensions.area_m2 for room in program.rooms}\n\n        current_tree = build_random_tree(room_ids, rng)\n        current_layout = self._materialize(current_tree, program, lot, areas)\n        current_hard, current_soft, current_locked = self._evaluate(current_layout, room_ids)\n\n        best_layout = current_layout\n        best_hard, best_soft = current_hard, current_soft\n\n        temperature = self._initial_temperature\n        for _ in range(self._max_iterations):\n            if best_hard == 0 and best_soft == 0:\n                break\n\n            candidate_tree = random_neighbor(current_tree, rng, areas, locked_room_ids=current_locked)\n            candidate_layout = self._materialize(candidate_tree, program, lot, areas)\n            candidate_hard, candidate_soft, candidate_locked = self._evaluate(candidate_layout, room_ids)\n\n            # comparacion lexicografica: si lo duro cambia, decide solo\n            # el delta duro; lo blando solo cuenta si empata. Ver\n            # [ARCH:simulated-annealing].\n            delta: float\n            if candidate_hard != current_hard:\n                delta = candidate_hard - current_hard\n            else:\n                delta = candidate_soft - current_soft\n\n            accepted = delta <= 0 or rng.random() < math.exp(-delta / max(temperature, 1e-9))\n            if accepted:\n                current_tree, current_layout = candidate_tree, candidate_layout\n                current_hard, current_soft, current_locked = candidate_hard, candidate_soft, candidate_locked\n                if (current_hard, current_soft) < (best_hard, best_soft):\n                    best_layout = current_layout\n                    best_hard, best_soft = current_hard, current_soft\n\n            temperature *= self._cooling_rate\n\n        if best_hard > 0:\n            raise LayoutGenerationError(\n                f\"No se pudo generar un layout valido (arbol B*). Ultimas violaciones: \"\n                f\"{self._constraint_validator.validate(best_layout).violations}\"\n            )\n        return best_layout\n\n    def _materialize(self, tree: BStarNode, program: Program, lot: Lot, areas: Dict[str, float]) -> Layout:\n        # a diferencia del arbol de particion (huella decidida de\n        # antemano, ver footprint.py), aqui la huella es el RESULTADO\n        # del propio empaquetado -- se calcula primero (siempre parte\n        # de (0,0)) y se ancla despues, no al reves. Ver [ARCH:btree-partition].\n        positions = compute_positions(tree, areas)\n        buildable_polygon = lot.buildable_area.polygon\n        offset_x, offset_y = self._anchor_offset(buildable_polygon, positions, lot.entrance_side)\n\n        placed_rooms = []\n        for room in program.rooms:\n            placed_room = copy.copy(room)  # copia superficial: no muta el Room del Program original\n            placed_room.boundary = Boundary(polygon=translate(positions[room.id], offset_x, offset_y))\n            placed_rooms.append(placed_room)\n\n        zones_map: Dict = {}\n        for room in placed_rooms:\n            zones_map.setdefault(room.zone, []).append(room.id)\n        built_zones = [Zone(zone_type=zone_type, room_ids=ids) for zone_type, ids in zones_map.items()]\n\n        layout = Layout(lot=lot, rooms=placed_rooms, zones=built_zones)\n        # VACIO: aqui incluye tanto el exterior (alrededor de la huella)\n        # como el interior (huecos DENTRO de la propia silueta del\n        # empaquetado, p.ej. un patio rodeado de estancias) -- una sola\n        # resta geometrica cubre ambos casos, a diferencia del arbol de\n        # particion (huella siempre maciza, solo existe vacio exterior).\n        union_estancias = unary_union([r.boundary.polygon for r in placed_rooms])\n        vacio_polygon = buildable_polygon.difference(union_estancias)\n        layout.metadata[\"vacio_shapes\"] = polygon_to_shapes(vacio_polygon)\n        return layout\n\n    @staticmethod\n    def _anchor_offset(\n        buildable_polygon: Polygon, positions: Dict[str, Polygon], entrance_side: str,\n    ) -> Tuple[float, float]:\n        \"\"\"Traslada el empaquetado (que siempre parte de (0,0)) para\n        anclarlo al lado de entrada de la parcela, centrado en el eje\n        perpendicular -- mismo patrón que `footprint.footprint_rectangle`,\n        adaptado a que aquí el tamaño no se elige, es el resultado.\"\"\"\n        minx, miny, maxx, maxy = buildable_polygon.bounds\n        buildable_w, buildable_h = maxx - minx, maxy - miny\n        px0, py0, px1, py1 = unary_union(list(positions.values())).bounds\n        width, height = px1 - px0, py1 - py0\n\n        if entrance_side == \"south\":\n            x0 = minx + (buildable_w - width) / 2\n            y0 = miny\n        elif entrance_side == \"north\":\n            x0 = minx + (buildable_w - width) / 2\n            y0 = maxy - height\n        elif entrance_side == \"west\":\n            x0 = minx\n            y0 = miny + (buildable_h - height) / 2\n        else:  # \"east\"\n            x0 = maxx - width\n            y0 = miny + (buildable_h - height) / 2\n\n        return x0 - px0, y0 - py0\n\n    def _evaluate(self, layout: Layout, all_room_ids: List[str]) -> Tuple[int, float, set]:\n        \"\"\"Una sola validacion por layout, reutilizada para la\n        puntuacion (duro/blando) Y el bloqueo progresivo -- mismo\n        patron que `SimulatedAnnealingLayoutGenerator._evaluate`.\"\"\"\n        violations = self._constraint_validator.validate(layout).violations\n        hard = len(violations)\n        soft = self._soft_scorer.score(layout) if self._soft_scorer else 0.0\n        violating_ids = {\n            room_id for room_id in all_room_ids\n            if any(f\"'{room_id}'\" in v for v in violations)\n        }\n        locked = set(all_room_ids) - violating_ids\n        return hard, soft, locked\n", "housing_generator/infrastructure/algorithms/layout_generation/btree_partition.py": "\"\"\"Árbol B* (Chang & Chang, 2000) para distribuir TODAS las estancias\nde un programa en un solar de una sola vez -- representación NO-guillotina\nalternativa a `partition_tree.py`, que solo puede representar particiones\ndonde cada corte divide el rectángulo entero de lado a lado. Formas en L,\nen U, o con patio interior son, por definición, imposibles con guillotina\npura, sin importar cuánto se mejore la búsqueda.\n\nA diferencia de `PartitionNode` (donde las hojas son estancias y los\nnodos internos son cortes), aquí CADA nodo representa una estancia\ndirectamente. Las coordenadas X las decide la propia estructura del\nárbol; las coordenadas Y requieren una estructura de contorno (perfil\ntipo \"skyline\" de lo ya ocupado) -- ver `compute_positions`.\n\nMigración planificada a fondo, con las decisiones de diseño y el\nprototipo verificado, en `docs/referencia/generador/prototipo-btree/`.\nVer [ARCH:btree-partition].\n\"\"\"\nimport copy\nimport math\nimport random\nfrom dataclasses import dataclass\nfrom typing import Dict, List, Optional, Tuple\nfrom shapely.geometry import Polygon, box\n\n\n@dataclass\nclass BStarNode:\n    \"\"\"Nodo del árbol B*. Cada nodo es una estancia -- no hay distinción\n    hoja/nodo interno como en `PartitionNode`.\n\n    `left`: \"el bloque más bajo, pegado a la derecha del padre\"\n    (x = x_padre + ancho_padre). `right`: \"el primer bloque arriba,\n    misma X que el padre\" (x = x_padre). `aspect_ratio`: ancho/alto\n    buscable, preserva el área declarada exactamente sea cual sea su\n    valor -- mismo espíritu que `ratio_override`/`slide_wall` del\n    árbol de partición, adaptado a que aquí cada nodo ES una estancia,\n    no un corte.\n\n    [ARCH:btree-partition]\n    \"\"\"\n    room_id: str\n    aspect_ratio: float = 1.0\n    left: Optional[\"BStarNode\"] = None\n    right: Optional[\"BStarNode\"] = None\n\n    def nodes(self) -> List[\"BStarNode\"]:\n        \"\"\"Todos los nodos del subárbol, incluido este -- equivalente a\n        `leaves()` de `PartitionNode`, pero aquí TODO nodo es una\n        estancia, no solo las hojas.\"\"\"\n        result = [self]\n        if self.left is not None:\n            result += self.left.nodes()\n        if self.right is not None:\n            result += self.right.nodes()\n        return result\n\n\ndef build_random_tree(room_ids: List[str], rng: random.Random) -> BStarNode:\n    \"\"\"Construye un árbol B* de topología aleatoria, cada room_id una\n    vez -- punto de partida para la búsqueda. Inserción sucesiva en un\n    hueco libre (`left`/`right` vacío) elegido al azar entre todos los\n    nodos ya colocados, no una construcción recursiva por división\n    (a diferencia de `partition_tree.build_random_tree`, que sí lo es\n    -- el árbol B* se construye de forma incremental por naturaleza).\"\"\"\n    if not room_ids:\n        raise ValueError(\"room_ids no puede estar vacío\")\n    shuffled = list(room_ids)\n    rng.shuffle(shuffled)\n    root = BStarNode(room_id=shuffled[0])\n    for room_id in shuffled[1:]:\n        huecos = [\n            (nodo, lado)\n            for nodo in root.nodes()\n            for lado in (\"left\", \"right\")\n            if getattr(nodo, lado) is None\n        ]\n        nodo, lado = rng.choice(huecos)\n        setattr(nodo, lado, BStarNode(room_id=room_id))\n    return root\n\n\n# Cache de una sola entrada, por REFERENCIA real (no por id()) -- mismo\n# patron ya probado en GeometryAdjacencyGraphBuilder\n# ([ARCH:geometry-adjacency-graph]): cachear por id() falla porque\n# Python reutiliza agresivamente direcciones de memoria de objetos\n# liberados. Motivo real, medido con cProfile, no optimizacion\n# especulativa: `random_neighbor` ya calcula las posiciones del\n# candidato para comprobar el bloqueo progresivo\n# (ver compute_positions en random_neighbor mas abajo) -- sin esta\n# cache, `_materialize` las recalculaba desde cero para el MISMO\n# arbol justo despues, 2748 llamadas para 1360 evaluaciones medidas\n# (~2x redundante). Ver [ARCH:btree-partition].\n_cache_root_ref: Optional[BStarNode] = None\n_cache_areas_ref: Optional[Dict[str, float]] = None\n_cache_positions: Optional[Dict[str, Polygon]] = None\n\n\ndef compute_positions(root: BStarNode, areas: Dict[str, float]) -> Dict[str, Polygon]:\n    \"\"\"Calcula la posición real de cada estancia vía el algoritmo de\n    contorno (Chang & Chang 2000) -- devuelve polígonos shapely, mismo\n    formato que `place_tree()` del árbol de partición, para que el\n    resto del sistema (validadores, persistencia, visor) no note\n    ninguna diferencia entre representaciones.\n\n    El contorno es una lista de segmentos (x1, x2, altura) -- el\n    \"perfil\" de lo ya ocupado. Cada estancia nueva \"cae\" hasta\n    apoyarse en lo que ya hay ocupado en su rango de X (como en\n    Tetris), no en una posición fija de antemano.\n    \"\"\"\n    global _cache_root_ref, _cache_areas_ref, _cache_positions\n    if root is _cache_root_ref and areas is _cache_areas_ref:\n        assert _cache_positions is not None\n        return _cache_positions\n\n    positions: Dict[str, Polygon] = {}\n    contour: List[Tuple[float, float, float]] = []\n\n    def height_in_range(x1: float, x2: float) -> float:\n        max_h = 0.0\n        for (cx1, cx2, cy) in contour:\n            if cx1 < x2 and cx2 > x1:  # se solapan en X\n                max_h = max(max_h, cy)\n        return max_h\n\n    def update_contour(x1: float, x2: float, y: float) -> None:\n        nuevo = []\n        for (cx1, cx2, cy) in contour:\n            if cx2 <= x1 or cx1 >= x2:\n                nuevo.append((cx1, cx2, cy))\n            else:\n                if cx1 < x1:\n                    nuevo.append((cx1, x1, cy))\n                if cx2 > x2:\n                    nuevo.append((x2, cx2, cy))\n        nuevo.append((x1, x2, y))\n        contour[:] = sorted(nuevo)\n\n    def place(node: Optional[BStarNode], x: float) -> None:\n        if node is None:\n            return\n        area = areas[node.room_id]\n        w = math.sqrt(area * node.aspect_ratio)\n        h = math.sqrt(area / node.aspect_ratio)\n        y = height_in_range(x, x + w)\n        positions[node.room_id] = box(x, y, x + w, y + h)\n        update_contour(x, x + w, y + h)\n        place(node.left, x + w)  # hijo izquierdo: pegado a la derecha del padre\n        place(node.right, x)     # hijo derecho: misma X que el padre, encima\n\n    place(root, 0.0)\n    _cache_root_ref, _cache_areas_ref, _cache_positions = root, areas, positions\n    return positions\n\n\ndef swap_modules(root: BStarNode, id_a: str, id_b: str) -> BStarNode:\n    \"\"\"Op3 (Chang & Chang): intercambia qué estancia ocupa cada nodo --\n    la forma del árbol no cambia, solo la identidad. Equivalente\n    directo a `swap_leaves` del árbol de partición.\"\"\"\n    nuevo = copy.deepcopy(root)\n    for nodo in nuevo.nodes():\n        if nodo.room_id == id_a:\n            nodo.room_id = id_b\n        elif nodo.room_id == id_b:\n            nodo.room_id = id_a\n    return nuevo\n\n\ndef _find_node(root: BStarNode, room_id: str) -> BStarNode:\n    for nodo in root.nodes():\n        if nodo.room_id == room_id:\n            return nodo\n    raise ValueError(f\"'{room_id}' no esta en el arbol\")\n\n\ndef _find_parent(root: BStarNode, objetivo: BStarNode) -> Tuple[Optional[BStarNode], Optional[str]]:\n    def buscar(nodo: Optional[BStarNode], padre: Optional[BStarNode], lado: Optional[str]):\n        if nodo is None:\n            return None\n        if nodo is objetivo:\n            return (padre, lado)\n        r = buscar(nodo.left, nodo, \"left\")\n        if r is not None:\n            return r\n        return buscar(nodo.right, nodo, \"right\")\n    resultado = buscar(root, None, None)\n    assert resultado is not None, \"el nodo objetivo no pertenece a este arbol\"\n    return resultado\n\n\ndef move_module(root: BStarNode, room_id: str, rng: random.Random) -> BStarNode:\n    \"\"\"Op2 (Chang & Chang): extrae una estancia de su posición actual y\n    la inserta en un hueco libre completamente distinto del árbol --\n    a diferencia de `swap_modules`, esto SÍ cambia la forma del árbol,\n    no solo quién ocupa cada hueco. Es el movimiento que no existe en\n    el árbol de partición actual, y el que ataca de raíz la limitación\n    ya diagnosticada (los movimientos actuales solo reasignan\n    identidad, nunca crean huecos nuevos). Ver [ARCH:btree-partition].\n\n    Solo mueve nodos hoja (sin hijos) -- mover un nodo con\n    descendientes exigiría decidir qué hacer con ellos (reinsertarlos\n    también, o dejarlos colgando de donde estaban), fuera de alcance\n    de este movimiento simple. Si el nodo elegido no es hoja, no-op\n    (devuelve el árbol sin cambios).\n    \"\"\"\n    nuevo = copy.deepcopy(root)\n    objetivo = _find_node(nuevo, room_id)\n    if objetivo.left is not None or objetivo.right is not None:\n        return nuevo  # no-op: mover nodos con descendientes queda fuera de alcance\n\n    padre, lado = _find_parent(nuevo, objetivo)\n    if padre is None:\n        return nuevo  # es la raiz sin hijos -- no hay nada que mover (arbol de 1 nodo)\n    assert lado is not None, \"si hay padre, siempre hay lado -- invariante de _find_parent\"\n    setattr(padre, lado, None)\n\n    huecos = [\n        (nodo, lado2)\n        for nodo in nuevo.nodes()\n        for lado2 in (\"left\", \"right\")\n        if getattr(nodo, lado2) is None\n    ]\n    if not huecos:\n        setattr(padre, lado, objetivo)  # sin huecos disponibles, deshacer\n        return nuevo\n    nuevo_padre, nuevo_lado = rng.choice(huecos)\n    assert nuevo_lado is not None\n    setattr(nuevo_padre, nuevo_lado, objetivo)\n    return nuevo\n\n\ndef resize_module(root: BStarNode, room_id: str, rng: random.Random, step: float = 0.15) -> BStarNode:\n    \"\"\"Redimensiona una estancia \"blanda\" (área fija, proporción\n    variable) -- equivalente a `slide_wall` del árbol de partición,\n    adaptado a que aquí la proporción vive en la propia estancia, no\n    en un corte. Perturba `aspect_ratio` multiplicativamente (nunca\n    negativo, evita colapsar a una franja de anchura/altura cero).\"\"\"\n    nuevo = copy.deepcopy(root)\n    nodo = _find_node(nuevo, room_id)\n    factor = 1 + rng.uniform(-step, step)\n    nodo.aspect_ratio = max(0.05, min(20.0, nodo.aspect_ratio * factor))\n    return nuevo\n\n\ndef reset_aspect_ratio(root: BStarNode, room_id: str) -> BStarNode:\n    \"\"\"Restablece la proporción de una estancia a 1:1 (cuadrada) --\n    equivalente a `reset_ratio` del árbol de partición: deshace la\n    deriva acumulada por varios `resize_module` sucesivos, dándole a\n    la búsqueda una forma real de deshacer, no solo de generar.\"\"\"\n    nuevo = copy.deepcopy(root)\n    _find_node(nuevo, room_id).aspect_ratio = 1.0\n    return nuevo\n\n\ndef swap_children(root: BStarNode, room_id: str) -> BStarNode:\n    \"\"\"Intercambia los hijos `left`/`right` de una estancia -- lo que\n    antes iba \"pegado a la derecha\" pasa a ir \"encima\", y viceversa.\n    Movimiento local, más barato que `move_module`.\"\"\"\n    nuevo = copy.deepcopy(root)\n    nodo = _find_node(nuevo, room_id)\n    nodo.left, nodo.right = nodo.right, nodo.left\n    return nuevo\n\n\nESCAPE_PROBABILITY = 0.15  # NO normativo, mismo criterio que\n# partition_tree.ESCAPE_PROBABILITY: con que frecuencia se ignora el\n# bloqueo por completo, para no quedarse atascado si arreglar algo\n# exige desplazar temporalmente una estancia ya bloqueada.\n\n\ndef random_neighbor(\n    root: BStarNode,\n    rng: random.Random,\n    areas: Dict[str, float],\n    locked_room_ids: Optional[set] = None,\n) -> BStarNode:\n    \"\"\"Genera un árbol vecino mediante uno de cinco movimientos:\n    intercambiar, mover, redimensionar, restablecer proporción, o\n    intercambiar hijos. Ver [ARCH:btree-partition].\n\n    `locked_room_ids`: bloqueo progresivo por COMPROBACIÓN REAL (a\n    diferencia de `partition_tree.random_neighbor`, que protege por\n    posición en el árbol) -- en árbol B* el contorno es compartido,\n    así que tocar una estancia puede desplazar a otra que no se tocó\n    directamente (confirmado con código durante la Fase 2 de esta\n    migración: cambiar el tamaño de una estancia desplazaba a otra dos\n    niveles por debajo, sin tocarla). Se recalculan las posiciones\n    antes/después del movimiento candidato y se rechaza (se devuelve\n    el árbol sin cambios) si alguna estancia bloqueada se desplazó\n    como efecto colateral -- confirmado con el usuario como la opción\n    preferida (más costosa, pero más flexible que proteger solo la\n    cadena de antecesores). Con probabilidad `ESCAPE_PROBABILITY`, se\n    ignora el bloqueo por completo (válvula de escape, evita atascos).\n    \"\"\"\n    ignorar_bloqueo = not locked_room_ids or rng.random() < ESCAPE_PROBABILITY\n    bloqueadas: set = set() if ignorar_bloqueo or locked_room_ids is None else locked_room_ids\n\n    nodos = root.nodes()\n    room_id = rng.choice([n.room_id for n in nodos])\n    move = rng.choice((\"swap\", \"move\", \"resize\", \"reset\", \"swap_children\"))\n\n    if move == \"swap\":\n        otro = rng.choice([n.room_id for n in nodos if n.room_id != room_id])\n        candidato = swap_modules(root, room_id, otro)\n    elif move == \"move\":\n        candidato = move_module(root, room_id, rng)\n    elif move == \"resize\":\n        candidato = resize_module(root, room_id, rng)\n    elif move == \"reset\":\n        candidato = reset_aspect_ratio(root, room_id)\n    else:  # swap_children\n        candidato = swap_children(root, room_id)\n\n    if not bloqueadas:\n        return candidato\n\n    pos_antes = compute_positions(root, areas)\n    pos_despues = compute_positions(candidato, areas)\n    for locked_id in bloqueadas:\n        antes = pos_antes[locked_id].bounds\n        despues = pos_despues[locked_id].bounds\n        if antes != despues:\n            return root  # movimiento rechazado, devuelve el arbol sin cambios\n    return candidato\n", "housing_generator/infrastructure/algorithms/layout_generation/footprint.py": "\"\"\"Cálculo de la huella construible (footprint) dentro del área\nedificable de la parcela -- a petición del usuario: la vivienda no\ntiene por qué ocupar el 100% de la parcela, real como se sitúan las\nviviendas unifamiliares de verdad (siempre queda jardín/patio\nalrededor). El sobrante (VACIO) es exterior real, no una pieza más\ndel reparto de estancias -- ver [ARCH:area-objetivo].\n\nAntes de esto, el árbol de partición llenaba SIEMPRE el 100% del área\nedificable con el programa declarado -- si la parcela era mayor que\nla suma de áreas, TODAS las estancias se inflaban proporcionalmente\npara llenar el hueco (encontrado con un caso real: un Pasillo de\n4.0m2 declarados generado más grande que un Dormitorio de 8.0m2).\n\"\"\"\nimport math\nfrom shapely.geometry import Polygon, box\n\nFOOTPRINT_BUFFER = 0.15  # margen sobre la suma de areas declaradas -- NO\n# normativo, criterio de ingenieria: da margen al recocido para\n# satisfacer otras restricciones (adyacencia, contacto exterior...)\n# sin inflar las estancias mas alla del +-15% de AreaObjetivoValidator.\n\n\ndef footprint_target_area(total_declared_area: float) -> float:\n    \"\"\"Área objetivo de la huella construible: suma de áreas\n    declaradas + margen. Ver [ARCH:area-objetivo].\"\"\"\n    return total_declared_area * (1 + FOOTPRINT_BUFFER)\n\n\ndef clamp_footprint_width(width: float, footprint_area: float, buildable_w: float, buildable_h: float) -> float:\n    \"\"\"Ancho de huella válido: la huella (width x area/width) debe\n    caber dentro del área edificable en ambas dimensiones.\"\"\"\n    min_width = footprint_area / buildable_h  # si width fuera menor, el alto excederia buildable_h\n    max_width = buildable_w\n    min_width = min(min_width, max_width)  # seguridad si el area no cabe de ningun modo\n    return min(max_width, max(min_width, width))\n\n\ndef footprint_rectangle(\n    buildable_polygon: Polygon, footprint_width: float, footprint_area: float, entrance_side: str,\n) -> Polygon:\n    \"\"\"Rectángulo de la huella construible, del tamaño y proporción\n    dados, anclado al lado de entrada de la parcela (la vivienda hacia\n    la calle, el vacío detrás/alrededor -- confirmado explícitamente).\n    Centrado en el eje perpendicular al de anclaje.\"\"\"\n    minx, miny, maxx, maxy = buildable_polygon.bounds\n    buildable_w, buildable_h = maxx - minx, maxy - miny\n\n    width = clamp_footprint_width(footprint_width, footprint_area, buildable_w, buildable_h)\n    height = min(buildable_h, footprint_area / width)\n\n    if entrance_side == \"south\":\n        x0 = minx + (buildable_w - width) / 2\n        y0 = miny\n    elif entrance_side == \"north\":\n        x0 = minx + (buildable_w - width) / 2\n        y0 = maxy - height\n    elif entrance_side == \"west\":\n        x0 = minx\n        y0 = miny + (buildable_h - height) / 2\n    else:  # \"east\"\n        x0 = maxx - width\n        y0 = miny + (buildable_h - height) / 2\n\n    return box(x0, y0, x0 + width, y0 + height)\n\n\nFOOTPRINT_RESIZE_STEP = 0.15  # perturbacion relativa maxima del ancho de huella por movimiento\n\n\ndef resize_footprint_width(\n    current_width: float, footprint_area: float, buildable_w: float, buildable_h: float, rng,\n) -> float:\n    \"\"\"Perturba el ancho de huella (recocido simulado) -- el alto se\n    deriva para mantener el area objetivo constante, dentro de los\n    limites de la parcela edificable.\"\"\"\n    delta = rng.uniform(-FOOTPRINT_RESIZE_STEP, FOOTPRINT_RESIZE_STEP)\n    proposed = current_width * (1 + delta)\n    return clamp_footprint_width(proposed, footprint_area, buildable_w, buildable_h)\n\n\ndef initial_footprint_width(footprint_area: float, buildable_w: float, buildable_h: float) -> float:\n    \"\"\"Ancho de huella inicial: lo mas cercano a cuadrado que quepa en\n    la parcela edificable, punto de partida razonable para la\n    busqueda (que luego explora otras proporciones).\"\"\"\n    square_width = math.sqrt(footprint_area)\n    return clamp_footprint_width(square_width, footprint_area, buildable_w, buildable_h)\n", "housing_generator/infrastructure/algorithms/layout_generation/graph_based_generator.py": "from typing import List, Dict\nfrom shapely.geometry import Polygon, box\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.enums import ZoneType\n\n# Orden de las zonas a lo largo del eje de \"profundidad\", desde la fachada/\n# acceso hacia el interior, siguiendo el gradiente de privacidad\n# dia -> noche -> servicio habitual en vivienda residencial.\n_ZONE_ORDER = [ZoneType.DAY, ZoneType.NIGHT, ZoneType.SERVICE]\n\n\nclass GraphBasedLayoutGenerator(LayoutGeneratorPort):\n    \"\"\"Generador de particionado simplificado: franjas por zona, luego\n    cajas por estancia dentro de cada franja, proporcional al área.\n    Deliberadamente simple, sustituible sin tocar el resto del sistema.\n    Ver [ARCH:graph-based-generator].\n    \"\"\"\n\n    def generate(self, program: Program, lot: Lot, zones: List[Zone]) -> Layout:\n        minx, miny, maxx, maxy = lot.boundary.polygon.bounds\n        total_height = maxy - miny\n\n        ordered_zones = sorted(\n            zones,\n            key=lambda z: _ZONE_ORDER.index(z.zone_type) if z.zone_type in _ZONE_ORDER else 99,\n        )\n\n        zone_areas: Dict[ZoneType, float] = {\n            zone.zone_type: sum(\n                program.room_by_id(rid).dimensions.area_m2 for rid in zone.room_ids\n            )\n            for zone in ordered_zones\n        }\n        total_area = sum(zone_areas.values()) or 1.0\n\n        placed_rooms = list(program.rooms)\n        rooms_by_id = {r.id: r for r in placed_rooms}\n\n        cursor_y = miny\n        for zone in ordered_zones:\n            zone_height = total_height * (zone_areas[zone.zone_type] / total_area)\n            zone_box = box(minx, cursor_y, maxx, cursor_y + zone_height)\n            zone.boundary = Boundary(polygon=zone_box)\n\n            self._place_rooms_in_zone(zone, zone_box, rooms_by_id)\n            cursor_y += zone_height\n\n        return Layout(lot=lot, rooms=placed_rooms, zones=ordered_zones)\n\n    def _place_rooms_in_zone(self, zone: Zone, zone_box: Polygon, rooms_by_id: Dict) -> None:\n        minx, miny, maxx, maxy = zone_box.bounds\n        zone_width = maxx - minx\n        zone_rooms = [rooms_by_id[rid] for rid in zone.room_ids]\n\n        # Heuristica de nucleo humedo: humedas primero (izquierda), para\n        # alinearlas en columna con zonas contiguas. Ver [ARCH:graph-based-generator].\n        zone_rooms = sorted(zone_rooms, key=lambda r: not r.is_wet)\n\n        total_area = sum(r.dimensions.area_m2 for r in zone_rooms) or 1.0\n\n        cursor_x = minx\n        for room in zone_rooms:\n            share = room.dimensions.area_m2 / total_area\n            width = zone_width * share\n            room_box = box(cursor_x, miny, cursor_x + width, maxy)\n            room.boundary = Boundary(polygon=room_box)\n            cursor_x += width\n", "housing_generator/infrastructure/algorithms/layout_generation/partition_tree.py": "\"\"\"Arbol de particion recursivo (slicing tree) para distribuir TODAS las\nestancias de un programa en un solar de una sola vez, sin una fase previa\nde reparto por macro-zona geometrica.\n\nCada hoja del arbol contiene una estancia; cada nodo interno divide su\nrectangulo en dos, en horizontal o vertical, con una proporcion\ndeterminada por el area total de estancias de cada subarbol. Es la\nrepresentacion clasica de \"slicing floorplan\" usada en floorplanning\n(particion guillotina): cualquier arbol binario con una direccion de\ncorte por nodo interno se traduce en una planta rectangular valida sin\nsolapes ni huecos.\n\"\"\"\nimport copy\nimport random\nfrom dataclasses import dataclass\nfrom typing import Dict, List, Optional\nfrom shapely.geometry import Polygon, box\n\n\n@dataclass\nclass PartitionNode:\n    \"\"\"Nodo del árbol. Una hoja tiene `room_id`; un nodo interno tiene\n    `direction` y dos subárboles `first`/`second`.\n\n    `direction`: None = automática (minimiza la peor proporción\n    ancho:alto del corte). \"h\"/\"v\" fuerza esa dirección, usado por\n    `flip_direction` para explorar topologías no automáticas.\n    `ratio_override`: proporción del corte forzada manualmente (0-1,\n    fracción de `first`), en vez de derivarla del área declarada.\n\n    [ARCH:partition-node]\n    \"\"\"\n    room_id: Optional[str] = None\n    direction: Optional[str] = None\n    first: Optional[\"PartitionNode\"] = None\n    second: Optional[\"PartitionNode\"] = None\n    ratio_override: Optional[float] = None\n\n    @property\n    def is_leaf(self) -> bool:\n        return self.room_id is not None\n\n    def leaves(self) -> List[\"PartitionNode\"]:\n        if self.is_leaf:\n            return [self]\n        # invariante mantenida por construccion (build_random_tree,\n        # random_neighbor): un nodo NO-hoja siempre tiene first/second.\n        # mypy no puede demostrarlo solo (Python no tiene \"tipos suma\"\n        # nativos para esto) -- el assert documenta la invariante Y le\n        # da a mypy la informacion de estrechamiento de tipo que necesita.\n        assert self.first is not None and self.second is not None, \\\n            \"Nodo interno sin first/second -- invariante del arbol violada\"\n        return self.first.leaves() + self.second.leaves()\n\n    def internal_nodes(self) -> List[\"PartitionNode\"]:\n        if self.is_leaf:\n            return []\n        assert self.first is not None and self.second is not None, \\\n            \"Nodo interno sin first/second -- invariante del arbol violada\"\n        return [self] + self.first.internal_nodes() + self.second.internal_nodes()\n\n\ndef build_random_tree(room_ids: List[str], rng: random.Random) -> PartitionNode:\n    \"\"\"Construye un árbol de topología aleatoria, cada room_id una vez\n    (punto de partida para la búsqueda). `direction=None` en todos los\n    nodos -- ver [ARCH:partition-node].\"\"\"\n    if len(room_ids) == 1:\n        return PartitionNode(room_id=room_ids[0])\n\n    shuffled = list(room_ids)\n    rng.shuffle(shuffled)\n    split = rng.randint(1, len(shuffled) - 1)\n    first = build_random_tree(shuffled[:split], rng)\n    second = build_random_tree(shuffled[split:], rng)\n    return PartitionNode(direction=None, first=first, second=second)\n\n\ndef _leaf_area(leaf: \"PartitionNode\", areas: Dict[str, float]) -> float:\n    \"\"\"Area de una hoja -- helper compartido por place_tree y\n    _current_ratio, evita repetir el assert de invariante en cada sitio.\"\"\"\n    assert leaf.room_id is not None, \"Nodo no-hoja pasado a _leaf_area -- invariante violada\"\n    return areas[leaf.room_id]\n\n\ndef _worst_aspect_ratio(width: float, height: float, ratio: float, direction: str) -> float:\n    \"\"\"Peor proporción ancho:alto entre las dos piezas de cortar\n    width x height en `ratio` (fracción de `first`), en `direction`.\n    Ver [ARCH:partition-node].\"\"\"\n    if direction == \"v\":\n        w1, h1 = width * ratio, height\n        w2, h2 = width * (1 - ratio), height\n    else:\n        w1, h1 = width, height * ratio\n        w2, h2 = width, height * (1 - ratio)\n    r1 = max(w1, h1) / max(min(w1, h1), 1e-6)\n    r2 = max(w2, h2) / max(min(w2, h2), 1e-6)\n    return max(r1, r2)\n\n\ndef _area_derived_ratio(node: PartitionNode, areas: Dict[str, float]) -> float:\n    \"\"\"Proporcion derivada PURAMENTE del area declarada de cada\n    subarbol, ignorando cualquier ratio_override existente -- el punto\n    de referencia \"justo\" tanto para el corte por defecto (place_tree)\n    como para acotar cuanto puede alejarse slide_wall (ver mas abajo,\n    [ARCH:area-objetivo]).\"\"\"\n    assert node.first is not None and node.second is not None, \\\n        \"Nodo interno sin first/second -- invariante del arbol violada\"\n    first_area = sum(_leaf_area(leaf, areas) for leaf in node.first.leaves())\n    second_area = sum(_leaf_area(leaf, areas) for leaf in node.second.leaves())\n    total = first_area + second_area or 1.0\n    return first_area / total\n\n\ndef place_tree(node: PartitionNode, rectangle: Polygon, areas: Dict[str, float]) -> Dict[str, Polygon]:\n    \"\"\"Recorre el arbol y devuelve, para cada room_id, el rectangulo que\n    le corresponde dentro de `rectangle`, proporcional al area total de\n    estancias de cada subarbol en cada corte.\"\"\"\n    if node.is_leaf:\n        assert node.room_id is not None\n        return {node.room_id: rectangle}\n\n    assert node.first is not None and node.second is not None, \\\n        \"Nodo interno sin first/second -- invariante del arbol violada\"\n    minx, miny, maxx, maxy = rectangle.bounds\n    ratio = node.ratio_override if node.ratio_override is not None else _area_derived_ratio(node, areas)\n\n    # direccion efectiva: automatica minimiza la peor proporcion\n    # resultante (ver [ARCH:partition-node]), o la forzada por override.\n    width, height = maxx - minx, maxy - miny\n    if node.direction is not None:\n        effective_direction = node.direction\n    else:\n        ratio_v = _worst_aspect_ratio(width, height, ratio, \"v\")\n        ratio_h = _worst_aspect_ratio(width, height, ratio, \"h\")\n        effective_direction = \"v\" if ratio_v <= ratio_h else \"h\"\n\n    if effective_direction == \"v\":  # corte vertical: reparte a lo largo de X\n        split_x = minx + (maxx - minx) * ratio\n        first_box = box(minx, miny, split_x, maxy)\n        second_box = box(split_x, miny, maxx, maxy)\n    else:  # corte horizontal: reparte a lo largo de Y\n        split_y = miny + (maxy - miny) * ratio\n        first_box = box(minx, miny, maxx, split_y)\n        second_box = box(minx, split_y, maxx, maxy)\n\n    placements: Dict[str, Polygon] = {}\n    placements.update(place_tree(node.first, first_box, areas))\n    placements.update(place_tree(node.second, second_box, areas))\n    return placements\n\n\nSLIDE_WALL_STEP = 0.08          # perturbacion maxima por movimiento (+-8%)\n# BUG REAL encontrado por el usuario (captura de pantalla: un Pasillo\n# de 4.0m2 declarados generado mas grande que un Dormitorio de 8.0m2)\n# e investigado a fondo tras anadir AreaObjetivoValidator: los limites\n# ABSOLUTOS anteriores (0.15/0.85) permitian que el ratio de CUALQUIER\n# corte se alejara hasta esos extremos sin importar su proporcion\n# \"justa\" (derivada del area) -- para un corte cuya proporcion justa\n# es, p.ej., 3% (una estancia diminuta junto a un subarbol grande),\n# nada impedia deslizarlo hasta el 85% (28 veces su area justa) tras\n# muchas iteraciones de recocido, sin ninguna fuerza que lo devolviera\n# -- confirmado empiricamente: 0 de 20 semillas distintas conseguian\n# generar un layout valido con validacion de area activa, no era mala\n# suerte de semilla, era estructural. Corregido acotando RELATIVO a la\n# proporcion justa de cada corte (`_area_derived_ratio`), no con una\n# ventana absoluta igual para todos los cortes. Ver [ARCH:area-objetivo].\nSLIDE_WALL_MAX_DEVIATION = 0.20  # +-20% relativo al ratio justo (derivado del area)\nSLIDE_WALL_ABSOLUTE_MIN = 0.05    # limite de seguridad, evita cortes degenerados\nSLIDE_WALL_ABSOLUTE_MAX = 0.95\n\n\ndef _current_ratio(node: PartitionNode, areas: Dict[str, float]) -> float:\n    \"\"\"Proporcion EFECTIVA actual de un nodo interno: su `ratio_override`\n    si ya tiene uno, o la derivada de las areas declaradas si no -- es\n    el punto de partida real para \"deslizar\" desde ahi, no un valor fijo.\"\"\"\n    if node.ratio_override is not None:\n        return node.ratio_override\n    return _area_derived_ratio(node, areas)\n\n\ndef _clear_stale_overrides(node: PartitionNode, room_ids: set) -> bool:\n    \"\"\"Limpia `ratio_override` en cualquier nodo interno cuyo subarbol\n    contenga alguna de las estancias en `room_ids` -- tras un\n    swap_leaves, un ratio_override ya fijado en un antecesor quedaria\n    calculado para la estancia VIEJA (area distinta), sin que nada lo\n    invalidase. Devuelve si el subarbol de `node` contiene alguna de\n    esas estancias (para la recursion). Ver [ARCH:area-objetivo].\"\"\"\n    if node.is_leaf:\n        return node.room_id in room_ids\n    assert node.first is not None and node.second is not None, \\\n        \"Nodo interno sin first/second -- invariante del arbol violada\"\n    contiene = (\n        _clear_stale_overrides(node.first, room_ids)\n        or _clear_stale_overrides(node.second, room_ids)\n    )\n    if contiene:\n        node.ratio_override = None\n    return contiene\n\n\ndef _subtree_room_ids(node: PartitionNode) -> set:\n    \"\"\"Room_ids de todas las hojas bajo `node` (incluida ella misma si\n    es hoja) -- usado por el bloqueo progresivo para saber si un nodo\n    interno tiene algo sin resolver debajo. Ver [ARCH:locking-progresivo].\"\"\"\n    return {leaf.room_id for leaf in node.leaves()}\n\n\nESCAPE_PROBABILITY = 0.15  # NO normativo, criterio de ingenieria: con\n# que frecuencia se ignora el bloqueo por completo en un movimiento,\n# para no quedarse atascado si arreglar una estancia exige tocar\n# temporalmente una ya bloqueada. Ver [ARCH:locking-progresivo].\n\n\ndef random_neighbor(\n    tree: PartitionNode,\n    rng: random.Random,\n    areas: Dict[str, float],\n    locked_room_ids: Optional[set] = None,\n) -> PartitionNode:\n    \"\"\"Genera un árbol vecino mediante uno de cinco movimientos:\n    intercambiar hojas, invertir dirección, intercambiar subárboles,\n    \"deslizar pared\" (perturbar la proporción de un corte), o\n    \"restablecer corte\" (deshacer un ratio_override, volver a la\n    proporción justa derivada del área). Ver [ARCH:partition-node].\n\n    BUG REAL encontrado en diagnostico por aislamiento de variables\n    (a peticion del usuario): slide_wall solo AÑADE deriva (aunque\n    acotada por corte, ver SLIDE_WALL_MAX_DEVIATION), nunca la\n    deshace -- una estancia con varios antecesores, cada uno con su\n    propio ratio_override activo de forma independiente, acumula la\n    deriva de TODOS ellos a la vez (confirmado empiricamente: una\n    estancia con 4 antecesores, 2 con override activo, llegaba a\n    60-70% de desviacion final aunque cada corte individual estuviera\n    dentro del +-20% permitido). \"reset_ratio\" le da a la busqueda una\n    forma real de deshacer esa deriva cuando ya no hace falta, no solo\n    de generarla. Ver [ARCH:area-objetivo-acumulada].\n\n    `locked_room_ids`: BLOQUEO PROGRESIVO (a peticion del usuario, tras\n    diagnostico real: contacto exterior simultaneo para varias\n    estancias NO es dificil geometricamente -- una topologia en tira\n    con direccion consistente lo resuelve trivialmente -- pero nuestra\n    propia busqueda, ciega, podia deshacer una buena disposicion ya\n    conseguida sin ninguna proteccion). Las estancias en este conjunto\n    (sin ninguna violacion actual) quedan protegidas: swap_leaves solo\n    intercambia entre estancias SIN bloquear, y el resto de movimientos\n    solo actuan sobre nodos cuyo subarbol tenga al menos una estancia\n    sin resolver. Con probabilidad `ESCAPE_PROBABILITY`, se ignora el\n    bloqueo por completo (valvula de escape, evita atascos si arreglar\n    algo exige tocar temporalmente una estancia ya bloqueada). `None`\n    (por defecto) preserva el comportamiento anterior sin bloqueo.\n    \"\"\"\n    ignorar_bloqueo = not locked_room_ids or rng.random() < ESCAPE_PROBABILITY\n    bloqueadas: set = set() if ignorar_bloqueo or locked_room_ids is None else locked_room_ids\n\n    new_tree = copy.deepcopy(tree)\n    move = rng.choice((\"swap_leaves\", \"flip_direction\", \"swap_children\", \"slide_wall\", \"reset_ratio\"))\n\n    if move == \"swap_leaves\":\n        leaves = new_tree.leaves()\n        elegibles = [leaf for leaf in leaves if leaf.room_id not in bloqueadas]\n        if len(elegibles) >= 2:\n            a, b = rng.sample(elegibles, 2)\n            a.room_id, b.room_id = b.room_id, a.room_id\n            _clear_stale_overrides(new_tree, {a.room_id, b.room_id})\n        return new_tree\n\n    internals = new_tree.internal_nodes()\n    elegibles_internos = [n for n in internals if _subtree_room_ids(n) - bloqueadas]\n    if not elegibles_internos:\n        return new_tree\n\n    if move == \"reset_ratio\":\n        # solo tiene sentido sobre nodos que YA tienen un override --\n        # si ninguno lo tiene, no hay nada que deshacer, se ignora el\n        # movimiento (el arbol vuelve tal cual, equivalente a \"no-op\").\n        overridden = [n for n in elegibles_internos if n.ratio_override is not None]\n        if overridden:\n            rng.choice(overridden).ratio_override = None\n        return new_tree\n\n    target = rng.choice(elegibles_internos)\n\n    if move == \"flip_direction\":\n        # ciclo None -> \"h\" -> \"v\" -> None (ver [ARCH:partition-node])\n        if target.direction is None:\n            target.direction = \"h\"\n        elif target.direction == \"h\":\n            target.direction = \"v\"\n        else:\n            target.direction = None\n    elif move == \"swap_children\":\n        # el ratio_override (si lo hay) representa \"fraccion de first\" --\n        # tras intercambiar first/second, ese numero fijo quedaria\n        # aplicado al lado CONTRARIO del que se calculo, invirtiendo el\n        # corte -- mismo tipo de problema que swap_leaves. Se limpia\n        # para que se recalcule desde el area real de cada lado.\n        target.first, target.second = target.second, target.first\n        target.ratio_override = None\n    else:  # slide_wall\n        current = _current_ratio(target, areas)\n        natural = _area_derived_ratio(target, areas)\n        delta = rng.uniform(-SLIDE_WALL_STEP, SLIDE_WALL_STEP)\n        proposed = current + delta\n        min_bound = max(natural * (1 - SLIDE_WALL_MAX_DEVIATION), SLIDE_WALL_ABSOLUTE_MIN)\n        max_bound = min(natural * (1 + SLIDE_WALL_MAX_DEVIATION), SLIDE_WALL_ABSOLUTE_MAX)\n        target.ratio_override = min(max_bound, max(min_bound, proposed))\n    return new_tree\n", "housing_generator/infrastructure/algorithms/layout_generation/simulated_annealing_generator.py": "import copy\nimport math\nimport random\nfrom typing import Dict, List, Optional\n\nfrom housing_generator.application.ports.layout_generator_port import LayoutGeneratorPort\nfrom housing_generator.application.ports.constraint_validator_port import ConstraintValidatorPort\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.entities.zone import Zone\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.infrastructure.algorithms.layout_generation.partition_tree import (\n    PartitionNode,\n    build_random_tree,\n    place_tree,\n    random_neighbor,\n)\nfrom housing_generator.infrastructure.geometry.shapely_utils import polygon_to_shapes\nfrom housing_generator.infrastructure.algorithms.layout_generation.footprint import (\n    footprint_target_area,\n    footprint_rectangle,\n    initial_footprint_width,\n    resize_footprint_width,\n)\nfrom housing_generator.infrastructure.algorithms.layout_generation.soft_constraint_scorer import (\n    SoftConstraintScorer,\n)\n\n\nclass SimulatedAnnealingLayoutGenerator(LayoutGeneratorPort):\n    \"\"\"Genera el layout con un árbol de partición sobre todas las\n    estancias a la vez, buscando la mejor topología mediante recocido\n    simulado. Función objetivo: comparación lexicográfica (duro,\n    blando), duro siempre dominante. Ver [ARCH:simulated-annealing].\n    \"\"\"\n\n    def __init__(\n        self,\n        constraint_validator: ConstraintValidatorPort,\n        max_iterations: int = 2000,\n        initial_temperature: float = 10.0,\n        cooling_rate: float = 0.995,\n        seed: Optional[int] = None,\n        soft_constraint_scorer: Optional[SoftConstraintScorer] = None,\n    ):\n        self._constraint_validator = constraint_validator\n        self._max_iterations = max_iterations\n        self._initial_temperature = initial_temperature\n        self._cooling_rate = cooling_rate\n        self._seed = seed\n        self._soft_scorer = soft_constraint_scorer\n\n    def generate(self, program: Program, lot: Lot, zones: List[Zone]) -> Layout:\n        # rng recreado en cada llamada, para que seed sea reproducible\n        # siempre, no solo la primera vez. Ver [ARCH:simulated-annealing].\n        self._rng = random.Random(self._seed)\n\n        room_ids = [r.id for r in program.rooms]\n        areas = {r.id: r.dimensions.area_m2 for r in program.rooms}\n\n        # huella construible: NO ocupa el 100% de la parcela -- se\n        # calcula del tamano justo para el programa declarado (+\n        # margen), el resto queda como VACIO real (exterior). La\n        # PROPORCION de la huella (ancho:alto) tambien es parte de la\n        # busqueda, no fija -- confirmado explicitamente. Ver\n        # [ARCH:area-objetivo].\n        buildable = lot.buildable_area.polygon\n        bminx, bminy, bmaxx, bmaxy = buildable.bounds\n        buildable_w, buildable_h = bmaxx - bminx, bmaxy - bminy\n        footprint_area = footprint_target_area(sum(areas.values()))\n        current_footprint_width = initial_footprint_width(footprint_area, buildable_w, buildable_h)\n\n        current_tree = build_random_tree(room_ids, self._rng)\n        current_layout = self._materialize(current_tree, current_footprint_width, footprint_area, program, lot, areas)\n        current_hard, current_soft, current_locked = self._evaluate(current_layout, room_ids)\n\n        best_layout = current_layout\n        best_hard, best_soft = current_hard, current_soft\n\n        temperature = self._initial_temperature\n        for _ in range(self._max_iterations):\n            if best_hard == 0 and best_soft == 0:\n                break\n\n            if self._rng.random() < 0.2:  # 20%: redimensionar huella, no tocar arbol\n                candidate_tree = current_tree\n                candidate_footprint_width = resize_footprint_width(\n                    current_footprint_width, footprint_area, buildable_w, buildable_h, self._rng\n                )\n            else:\n                # bloqueo progresivo: las estancias SIN violaciones\n                # actuales quedan protegidas de la mayoria de\n                # movimientos -- ver [ARCH:locking-progresivo].\n                candidate_tree = random_neighbor(current_tree, self._rng, areas, locked_room_ids=current_locked)\n                candidate_footprint_width = current_footprint_width\n\n            candidate_layout = self._materialize(candidate_tree, candidate_footprint_width, footprint_area, program, lot, areas)\n            candidate_hard, candidate_soft, candidate_locked = self._evaluate(candidate_layout, room_ids)\n\n            # comparacion lexicografica: si lo duro cambia, decide solo\n            # el delta duro; lo blando solo cuenta si empata. Ver\n            # [ARCH:simulated-annealing].\n            if candidate_hard != current_hard:\n                delta = candidate_hard - current_hard\n            else:\n                delta = candidate_soft - current_soft\n\n            accepted = delta <= 0 or self._rng.random() < math.exp(-delta / max(temperature, 1e-9))\n            if accepted:\n                current_tree, current_layout = candidate_tree, candidate_layout\n                current_footprint_width = candidate_footprint_width\n                current_hard, current_soft, current_locked = candidate_hard, candidate_soft, candidate_locked\n                if (current_hard, current_soft) < (best_hard, best_soft):\n                    best_layout = current_layout\n                    best_hard, best_soft = current_hard, current_soft\n\n            temperature *= self._cooling_rate\n\n        best_layout.metadata[\"annealing_score\"] = best_hard  # compatibilidad: violaciones duras del mejor layout\n        best_layout.metadata[\"hard_violations\"] = best_hard\n        best_layout.metadata[\"soft_penalty\"] = best_soft\n        return best_layout\n\n    def _evaluate(self, layout: Layout, all_room_ids: List[str]) -> tuple:\n        \"\"\"Una sola validacion por layout, reutilizada para la\n        puntuacion (duro/blando) Y el bloqueo progresivo -- evita\n        validar dos veces por iteracion. Devuelve\n        (hard, soft, locked_room_ids).\"\"\"\n        violations = self._constraint_validator.validate(layout).violations\n        hard = len(violations)\n        soft = self._soft_scorer.score(layout) if self._soft_scorer else 0.0\n        violating_ids = {\n            room_id for room_id in all_room_ids\n            if any(f\"'{room_id}'\" in v for v in violations)\n        }\n        locked = set(all_room_ids) - violating_ids\n        return hard, soft, locked\n\n    def _materialize(\n        self,\n        tree: PartitionNode,\n        footprint_width: float,\n        footprint_area: float,\n        program: Program,\n        lot: Lot,\n        areas: Dict[str, float],\n    ) -> Layout:\n        # huella construible dentro del area edificable, NO toda ella\n        # -- ver footprint.py, [ARCH:area-objetivo].\n        buildable_polygon = lot.buildable_area.polygon\n        footprint_polygon = footprint_rectangle(buildable_polygon, footprint_width, footprint_area, lot.entrance_side)\n        placements = place_tree(tree, footprint_polygon, areas)\n\n        placed_rooms = []\n        for room in program.rooms:\n            placed_room = copy.copy(room)  # copia superficial: no muta el Room del Program original\n            placed_room.boundary = Boundary(polygon=placements[room.id])\n            placed_rooms.append(placed_room)\n\n        zones_map: Dict = {}\n        for room in placed_rooms:\n            zones_map.setdefault(room.zone, []).append(room.id)\n        built_zones = [Zone(zone_type=zone_type, room_ids=ids) for zone_type, ids in zones_map.items()]\n\n        layout = Layout(lot=lot, rooms=placed_rooms, zones=built_zones)\n        # VACIO: exterior real (jardin/patio), no un Room del dominio\n        # -- solo geometria para el visor. Coordenadas directas (no WKT)\n        # para que el visor las dibuje sin necesitar un parser de WKT en\n        # JS -- una lista de anillos, cada uno lista de [x,y] (soporta\n        # Polygon y MultiPolygon si la resta produce varias piezas\n        # separadas). Ver [ARCH:area-objetivo].\n        vacio_polygon = buildable_polygon.difference(footprint_polygon)\n        layout.metadata[\"vacio_shapes\"] = polygon_to_shapes(vacio_polygon)\n        return layout\n", "housing_generator/infrastructure/algorithms/layout_generation/soft_constraint_scorer.py": "from typing import List\nimport networkx as nx\nfrom housing_generator.application.ports.adjacency_graph_builder_port import AdjacencyGraphBuilderPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.enums import AdjacencyStrength\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\n\n# Ver [ARCH:soft-constraint-scorer].\nTARGET_CERCA_SALTOS = 2\nTARGET_ALEJAR_SALTOS = 3\nPESO_CERCA_NO_SATISFECHO = 1.0\nPESO_ALEJAR_NO_SATISFECHO = 1.0\n\n\nclass SoftConstraintScorer:\n    \"\"\"Calcula la penalización blanda de un Layout, para sumarla a las\n    violaciones duras en la función objetivo del recocido -- nunca\n    bloquea nada. Ver [ARCH:soft-constraint-scorer].\"\"\"\n\n    def __init__(\n        self,\n        adjacency_requirements: List[AdjacencyRequirement],\n        graph_builder: AdjacencyGraphBuilderPort,\n    ):\n        self._soft_requirements = [\n            req for req in adjacency_requirements\n            if req.strength in (AdjacencyStrength.SHOULD_BE_NEAR, AdjacencyStrength.SHOULD_BE_AWAY)\n        ]\n        self._graph_builder = graph_builder\n\n    def score(self, layout: Layout) -> float:\n        if not self._soft_requirements:\n            return 0.0\n\n        graph = self._graph_builder.build(layout)\n        penalty = 0.0\n\n        for req in self._soft_requirements:\n            if req.room_a_id not in graph or req.room_b_id not in graph:\n                # solo dispara si la estancia no esta colocada. Ver\n                # [ARCH:soft-constraint-scorer].\n                if req.strength == AdjacencyStrength.SHOULD_BE_NEAR:\n                    penalty += PESO_CERCA_NO_SATISFECHO\n                continue\n\n            if nx.has_path(graph, req.room_a_id, req.room_b_id):\n                distance = nx.shortest_path_length(graph, req.room_a_id, req.room_b_id)\n            else:\n                distance = float(\"inf\")\n\n            if req.strength == AdjacencyStrength.SHOULD_BE_NEAR:\n                if distance > TARGET_CERCA_SALTOS:\n                    penalty += PESO_CERCA_NO_SATISFECHO\n            else:  # SHOULD_BE_AWAY\n                if distance < TARGET_ALEJAR_SALTOS:\n                    penalty += PESO_ALEJAR_NO_SATISFECHO\n\n        return penalty\n", "housing_generator/infrastructure/algorithms/zoning/__init__.py": "", "housing_generator/infrastructure/algorithms/zoning/treemap_zoning.py": "from typing import List\nfrom collections import defaultdict\nfrom housing_generator.application.ports.zoning_strategy_port import ZoningStrategyPort\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.zone import Zone\n\n\nclass TreemapZoningStrategy(ZoningStrategyPort):\n    \"\"\"Agrupa estancias en Zone segun su ZoneType declarado (dia/noche/servicio).\n\n    El dimensionado/posicionamiento de las zonas en si se deja al\n    LayoutGenerator; esta estrategia solo decide el *agrupamiento*,\n    replicando el paso clasico de 'diagrama de zonificacion' previo a\n    la traduccion a diagrama de burbujas y luego a planta.\n    \"\"\"\n\n    def build_zones(self, program: Program) -> List[Zone]:\n        grouped = defaultdict(list)\n        for room in program.rooms:\n            grouped[room.zone].append(room.id)\n\n        return [\n            Zone(zone_type=zone_type, room_ids=room_ids)\n            for zone_type, room_ids in grouped.items()\n        ]\n", "housing_generator/infrastructure/geometry/__init__.py": "", "housing_generator/infrastructure/geometry/shapely_utils.py": "\"\"\"Utilidades geometricas compartidas basadas en shapely.\n\nSe deja como modulo separado para que los generadores de layout no\ndupliquen logica de particionado/interseccion cuando se anadan nuevas\nestrategias (CSP, genetico, etc.).\n\"\"\"\nimport math\nfrom typing import List, Optional, Tuple\nfrom shapely.geometry import Polygon, LineString\n\n\ndef _rectangle_mrr_if_valid(polygon: Polygon, relative_tolerance: float = 0.01) -> Optional[Polygon]:\n    \"\"\"Calcula `minimum_rotated_rectangle` UNA sola vez y comprueba si\n    `polygon` es (aproximadamente) ese rectangulo -- devuelve el propio\n    mrr si es valido, o None si no. Consolidado tras un hallazgo real\n    de cProfile (no optimizacion especulativa): `_is_axis_or_rotated_rectangle`\n    y `rectangle_side_lengths` se llamaban SIEMPRE juntas, cada una\n    calculando `minimum_rotated_rectangle` por separado sobre el MISMO\n    poligono -- 9160 llamadas medidas en una prueba real, el doble de\n    las necesarias. Ver [ARCH:shapely-utils].\"\"\"\n    mrr = polygon.minimum_rotated_rectangle\n    mrr_area = mrr.area\n    if mrr_area <= 0:\n        return None\n    if abs(polygon.area - mrr_area) > relative_tolerance * mrr_area:\n        return None\n    return mrr\n\n\ndef _mrr_side_lengths(mrr: Polygon) -> Tuple[float, float]:\n    coords = list(mrr.exterior.coords)  # 5 puntos, el ultimo repite el primero\n    side_a = math.hypot(coords[1][0] - coords[0][0], coords[1][1] - coords[0][1])\n    side_b = math.hypot(coords[2][0] - coords[1][0], coords[2][1] - coords[1][1])\n    return side_a, side_b\n\n\ndef can_fit_rectangle(polygon: Polygon, side_a_m: float, side_b_m: float) -> Optional[bool]:\n    \"\"\"¿Cabe un rectangulo de `side_a_m` x `side_b_m` dentro de `polygon`\n    (en cualquiera de las dos orientaciones)?\n\n    Mismos TRES estados que `can_inscribe_square` (del que esta funcion\n    es la generalizacion): True / False / None (\"no verificable\", nunca\n    confundido con \"aprobado\").\n    \"\"\"\n    mrr = _rectangle_mrr_if_valid(polygon)\n    if mrr is None:\n        return None\n    width, height = _mrr_side_lengths(mrr)\n    return (width >= side_a_m and height >= side_b_m) or (width >= side_b_m and height >= side_a_m)\n\n\ndef can_inscribe_square(polygon: Polygon, side_length_m: float) -> Optional[bool]:\n    \"\"\"¿Cabe un cuadrado de `side_length_m` de lado dentro de `polygon`?\n    Caso particular de `can_fit_rectangle` con los dos lados iguales.\"\"\"\n    return can_fit_rectangle(polygon, side_length_m, side_length_m)\n\n\ndef meets_minimum_width(polygon: Polygon, min_width_m: float) -> Optional[bool]:\n    \"\"\"Ancho libre entre paramentos enfrentados (A.3.2.1 / A.3.2.3): el\n    lado MAS CORTO del rectangulo debe ser >= min_width_m. A diferencia\n    de `can_fit_rectangle`, aqui el lado corto de LA PROPIA estancia es\n    el que se mide directamente, no si cabe otra forma dentro.\"\"\"\n    mrr = _rectangle_mrr_if_valid(polygon)\n    if mrr is None:\n        return None\n    width, height = _mrr_side_lengths(mrr)\n    return min(width, height) >= min_width_m\n\n\ndef count_exterior_sides(\n    room_polygon: Polygon,\n    lot_polygon: Polygon,\n    min_contact_m: float = 0.3,\n    excluded_segments: Optional[List[LineString]] = None,\n) -> Optional[int]:\n    \"\"\"Cuenta cuántos de los 4 lados de `room_polygon` tienen contacto\n    real con el límite de `lot_polygon` (`min_contact_m` de borde\n    compartido). `excluded_segments`: lados de medianera, no cuentan\n    como exterior real. Ver [ARCH:shapely-utils].\"\"\"\n    mrr = _rectangle_mrr_if_valid(room_polygon)\n    if mrr is None:\n        return None\n\n    coords = list(mrr.exterior.coords)  # 5 puntos, el ultimo repite el primero\n    lot_boundary = lot_polygon.boundary\n    if excluded_segments:\n        for seg in excluded_segments:\n            lot_boundary = lot_boundary.difference(seg.buffer(1e-6))\n\n    count = 0\n    for i in range(4):\n        side = LineString([coords[i], coords[i + 1]])\n        overlap_length = side.intersection(lot_boundary).length\n        if overlap_length >= min_contact_m:\n            count += 1\n    return count\n\n\ndef evaluate_minimum_width(\n    room_id: str,\n    polygon: Polygon,\n    threshold_m: float,\n    violation_message: str,\n    warning_message: str,\n) -> tuple:\n    \"\"\"Evalúa el ancho libre mínimo (3 estados) y devuelve\n    (violaciones, avisos), listo para `violations.extend(v)`. Helper\n    compartido por varios validadores. Ver [ARCH:shapely-utils].\"\"\"\n    cumple = meets_minimum_width(polygon, threshold_m)\n    if cumple is False:\n        return ([f\"'{room_id}': {violation_message}\"], [])\n    elif cumple is None:\n        return ([], [f\"'{room_id}': {warning_message}\"])\n    return ([], [])\n\n\ndef polygon_to_shapes(geom) -> List[dict]:\n    \"\"\"Convierte una geometría (`Polygon` o `MultiPolygon`) en una\n    lista de \"formas\", cada una con su anillo exterior y sus anillos\n    interiores (huecos, p.ej. un patio rodeado por todos lados)\n    AGRUPADOS juntos -- a diferencia de una lista plana de anillos,\n    esto preserva qué hueco pertenece a qué forma. Necesario para\n    renderizarlo correctamente en el visor (recorte real del hueco,\n    no otra pieza más pintada encima con el mismo color) -- hallazgo\n    real al revisar las conexiones entre Python y el dashboard: la\n    lista plana anterior no permitía distinguir \"esto es un hueco de\n    esta forma\" de \"esto es una pieza separada del MultiPolygon\".\n    Compartida entre `SimulatedAnnealingLayoutGenerator` (nunca\n    produce huecos, huella siempre maciza) y `BTreeLayoutGenerator`\n    (sí puede producirlos). Ver [ARCH:shapely-utils], [ARCH:btree-partition].\n\n    Formato: `[{\"exterior\": [[x,y],...], \"interiors\": [[[x,y],...], ...]}, ...]`\n    \"\"\"\n    if geom.is_empty:\n        return []\n    polygons = list(geom.geoms) if geom.geom_type == \"MultiPolygon\" else [geom]\n    return [\n        {\n            \"exterior\": [list(coord) for coord in poly.exterior.coords],\n            \"interiors\": [[list(coord) for coord in interior.coords] for interior in poly.interiors],\n        }\n        for poly in polygons\n    ]\n", "housing_generator/infrastructure/persistence/__init__.py": "", "housing_generator/infrastructure/persistence/json_layout_repository.py": "import json\nfrom typing import List, Optional\nfrom housing_generator.application.ports.layout_repository_port import LayoutRepositoryPort\nfrom housing_generator.domain.entities.layout import Layout\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.infrastructure.algorithms.adjacency.door_graph import build_door_graph\n\n\nclass JsonLayoutRepository(LayoutRepositoryPort):\n    \"\"\"Serializa los datos esenciales de un Layout. El round-trip completo\n    de geometria (via shapely.wkt) se puede anadir cuando haga falta cargar\n    layouts guardados, no solo inspeccionarlos.\"\"\"\n\n    @staticmethod\n    def to_dict(layout: Layout, adjacency_requirements: Optional[List[AdjacencyRequirement]] = None) -> dict:\n        \"\"\"Extraido de `save()` para reutilizar la MISMA serializacion\n        (rooms/doors/metadata) sin pasar por disco -- retomado al\n        construir el puente de navegador (`interface/browser/bridge.py`),\n        que necesita el dict en memoria, no un archivo.\"\"\"\n        doors = []\n        if adjacency_requirements:\n            door_graph = build_door_graph(layout, adjacency_requirements)\n            doors = [{\"room_a\": a, \"room_b\": b} for a, b in door_graph.edges()]\n\n        return {\n            \"rooms\": [\n                {\n                    \"id\": r.id,\n                    \"name\": r.name,\n                    \"type\": r.room_type.value,\n                    \"zone\": r.zone.value,\n                    \"area_m2\": r.dimensions.area_m2,\n                    \"bounds\": list(r.boundary.polygon.bounds) if r.boundary else None,\n                }\n                for r in layout.rooms\n            ],\n            \"doors\": doors,\n            \"metadata\": layout.metadata,\n        }\n\n    def save(\n        self, layout: Layout, path: str,\n        adjacency_requirements: Optional[List[AdjacencyRequirement]] = None,\n    ) -> None:\n        data = self.to_dict(layout, adjacency_requirements)\n        with open(path, \"w\", encoding=\"utf-8\") as f:\n            json.dump(data, f, indent=2, ensure_ascii=False)\n\n    def load(self, path: str) -> Layout:\n        raise NotImplementedError(\"La carga completa de un Layout desde JSON aun no esta implementada\")\n", "housing_generator/infrastructure/persistence/seleccion_plantas_importer.py": "\"\"\"Importador de `seleccion_plantas.json` (exportación del dashboard,\npestaña \"Sección vertical\") hacia un `Program` real utilizable por el\ngenerador. Ver [ARCH:seleccion-plantas-importer].\n\"\"\"\nimport json\nfrom pathlib import Path\nfrom typing import Dict, FrozenSet, List, NamedTuple, Optional, Union\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.value_objects.dimensions import Dimensions\nfrom housing_generator.domain.enums import RoomType, NivelPlanta, DISPLAY_NAMES\nfrom housing_generator.domain.services.type_adjacency_catalog import build_adjacency_requirements\n\n# Areas por defecto, genericas -- solo formato antiguo o entrada sin\n# area_m2 valida. Ver [ARCH:seleccion-plantas-importer].\nAREAS_POR_DEFECTO_M2: Dict[RoomType, float] = {\n    RoomType.LIVING_ROOM: 25.0,\n    RoomType.DINING_ROOM: 14.0,\n    RoomType.KITCHEN: 10.0,\n    RoomType.BEDROOM: 12.0,\n    RoomType.MASTER_BEDROOM: 15.0,\n    RoomType.BATHROOM: 5.5,\n    RoomType.TOILET: 3.0,\n    RoomType.ENTRANCE_HALL: 4.5,\n    RoomType.STUDY: 9.0,\n    RoomType.LAUNDRY: 3.0,\n    RoomType.DRYING_AREA: 2.0,\n    RoomType.STORAGE: 3.0,\n    RoomType.STORAGE_ROOM: 4.0,\n    RoomType.GARAGE: 18.0,\n    RoomType.TECHNICAL_ROOM: 3.0,\n    RoomType.CORRIDOR: 4.0,\n}\n\n# tipo_vivienda -> Lot.medianera_sides. Ver [ARCH:seleccion-plantas-importer].\nMEDIANERA_SIDES_BY_TIPO_VIVIENDA: Dict[str, FrozenSet[str]] = {\n    \"aislada\": frozenset(),\n    \"pareada\": frozenset({\"east\"}),\n    \"adosada\": frozenset({\"east\", \"west\"}),\n}\n\n\nclass SeleccionImportada(NamedTuple):\n    \"\"\"Resultado de `import_seleccion_plantas`: el `Program` real, y los\n    `medianera_sides` resueltos a partir de `tipo_vivienda` -- listos\n    para pasarselos directamente a `Lot(medianera_sides=...)`.\"\"\"\n    program: Program\n    medianera_sides: FrozenSet[str]\n\n\ndef import_seleccion_plantas(\n    source: Union[str, Path, dict],\n    areas_m2: Optional[Dict[RoomType, float]] = None,\n) -> SeleccionImportada:\n    \"\"\"Construye un `Program` real a partir del JSON exportado por el\n    dashboard, y resuelve `medianera_sides` desde `tipo_vivienda`.\n    `source`: ruta o dict ya cargado. Soporta formato nuevo (v2,\n    cantidad+área reales) y antiguo (lista plana). Adyacencias\n    derivadas automáticamente del catálogo. Ver\n    [ARCH:seleccion-plantas-importer].\n    \"\"\"\n    if isinstance(source, (str, Path)):\n        with open(source, encoding=\"utf-8\") as f:\n            payload = json.load(f)\n    else:\n        payload = source\n\n    default_areas = {**AREAS_POR_DEFECTO_M2, **(areas_m2 or {})}\n    rooms: List[Room] = []\n\n    for level_name, entries in payload.get(\"levels\", {}).items():\n        level = NivelPlanta[level_name]\n        for entry in entries:\n            if isinstance(entry, str):\n                # formato antiguo: solo el nombre de tipo, sin cantidad ni area\n                type_name, count, area = entry, 1, None\n            else:\n                # formato nuevo: {\"type\": ..., \"count\": ..., \"area_m2\": ...}\n                type_name = entry[\"type\"]\n                count = max(1, int(entry.get(\"count\", 1)))\n                area = entry.get(\"area_m2\")\n\n            room_type = RoomType[type_name]\n            final_area = area if area else default_areas.get(room_type, 10.0)\n\n            for i in range(1, count + 1):\n                suffix = f\"_{i}\" if count > 1 else \"\"\n                room_id = f\"{type_name.lower()}_{level_name.lower()}{suffix}\"\n                display_name = DISPLAY_NAMES.get(room_type, room_type.value)\n                if count > 1:\n                    display_name = f\"{display_name} {i}\"\n                rooms.append(Room(\n                    id=room_id,\n                    name=display_name,\n                    room_type=room_type,\n                    dimensions=Dimensions(area_m2=final_area),\n                    level=level,\n                ))\n\n    adjacency = build_adjacency_requirements(rooms)\n    program = Program(rooms=rooms, adjacency_requirements=adjacency)\n\n    tipo_vivienda = payload.get(\"tipo_vivienda\", \"aislada\")\n    medianera_sides = MEDIANERA_SIDES_BY_TIPO_VIVIENDA.get(tipo_vivienda, frozenset())\n\n    return SeleccionImportada(program=program, medianera_sides=medianera_sides)\n", "housing_generator/interface/__init__.py": "", "housing_generator/interface/browser/__init__.py": "", "housing_generator/interface/browser/bridge.py": "\"\"\"Puente entre el dashboard (JavaScript, en el navegador) y el\ngenerador real (este mismo paquete Python), pensado para ejecutarse\ndentro de Pyodide -- no un servidor aparte. Solo cruza datos planos\n(dict/JSON), nunca objetos de dominio. Ver [ARCH:browser-bridge].\n\"\"\"\nfrom typing import Optional\nfrom shapely.geometry import box\n\nfrom housing_generator.config.container import build_generate_building_use_case\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.exceptions import LayoutGenerationError\nfrom housing_generator.infrastructure.persistence.json_layout_repository import JsonLayoutRepository\nfrom housing_generator.infrastructure.persistence.seleccion_plantas_importer import import_seleccion_plantas\n\n\ndef generar_edificio(\n    seleccion_payload: dict,\n    lot_width_m: float,\n    lot_height_m: float,\n    seed: int = 1,\n    max_iterations: int = 3000,\n    retry_seeds: int = 5,\n    vivienda_accesible: bool = False,\n    retranqueo_m: Optional[float] = None,\n    retranqueo_incremento_por_planta_m: Optional[float] = None,\n    experimental_btree: bool = False,\n) -> dict:\n    \"\"\"Genera un edificio real a partir de una selección del dashboard\n    y una parcela rectangular. Reintenta semillas automáticamente\n    (mismo comportamiento que `--retry-seeds` del CLI).\n\n    `retranqueo_m`/`retranqueo_incremento_por_planta_m`: mismos\n    conceptos ya conectados al CLI (`--retranqueo`/`--retranqueo-incremento`)\n    -- sin forma de usarlos desde el dashboard hasta ahora, encontrado\n    al revisar las conexiones entre Python y el dashboard a petición\n    del usuario. `experimental_btree`: mismo flag que\n    `--experimental-btree` del CLI, misma migración en curso -- ver\n    `docs/referencia/generador/prototipo-btree/`.\n\n    Devuelve SIEMPRE un dict:\n      {\"ok\": True, \"semilla_usada\": N, \"reintentos\": N,\n       \"floors\": {\"planta_baja\": {\"rooms\":[...], \"doors\":[...], \"metadata\":{...}}, ...}}\n    o, si fallan todos los intentos:\n      {\"ok\": False, \"error\": \"mensaje legible\", \"semillas_probadas\": N}\n\n    Ver [ARCH:browser-bridge].\n    \"\"\"\n    try:\n        seleccion = import_seleccion_plantas(seleccion_payload)\n    except (KeyError, ValueError) as e:\n        return {\"ok\": False, \"error\": f\"El JSON de selección no tiene el formato esperado: {e}\", \"semillas_probadas\": 0}\n\n    program = seleccion.program\n    if not program.rooms:\n        return {\"ok\": False, \"error\": \"La selección no tiene ninguna estancia -- añade al menos el programa mínimo.\", \"semillas_probadas\": 0}\n\n    lot = Lot(\n        boundary=Boundary(polygon=box(0, 0, lot_width_m, lot_height_m)),\n        medianera_sides=seleccion.medianera_sides,\n        retranqueo_m=retranqueo_m,\n        retranqueo_incremento_por_planta_m=retranqueo_incremento_por_planta_m,\n    )\n\n    building = None\n    last_error: Optional[Exception] = None\n    attempts = max(1, retry_seeds)\n    used_seed = seed\n\n    for attempt in range(attempts):\n        used_seed = seed + attempt\n        use_case = build_generate_building_use_case(\n            adjacency_requirements=program.adjacency_requirements,\n            seed=used_seed,\n            max_iterations=max_iterations,\n            vivienda_accesible=vivienda_accesible,\n            experimental_btree=experimental_btree,\n        )\n        try:\n            building = use_case.execute(program, lot)\n            break\n        except LayoutGenerationError as e:\n            last_error = e\n\n    if building is None:\n        return {\n            \"ok\": False,\n            \"error\": f\"No se pudo generar tras probar {attempts} semillas (desde {seed} hasta {seed + attempts - 1}). \"\n                     f\"Último error: {last_error}\",\n            \"semillas_probadas\": attempts,\n        }\n\n    floors = {}\n    for level, layout in building.floors.items():\n        floors[level.value] = JsonLayoutRepository.to_dict(layout, adjacency_requirements=program.adjacency_requirements)\n\n    return {\n        \"ok\": True,\n        \"semilla_usada\": used_seed,\n        \"reintentos\": used_seed - seed,\n        \"medianera_sides\": sorted(seleccion.medianera_sides),\n        \"floors\": floors,\n    }\n", "housing_generator/interface/cli/__init__.py": "", "housing_generator/interface/cli/main.py": "\"\"\"Punto de entrada CLI: construye un Program + Lot de ejemplo y ejecuta\nel generador. Sirve como demostracion end-to-end de la arquitectura.\"\"\"\nimport argparse\nfrom shapely.geometry import box\n\nfrom housing_generator.config.container import build_generate_layout_use_case, build_generate_building_use_case\nfrom housing_generator.application.dto.generation_request import GenerationRequest\nfrom housing_generator.domain.entities.program import Program\nfrom housing_generator.domain.entities.room import Room\nfrom housing_generator.domain.entities.lot import Lot\nfrom housing_generator.domain.value_objects.dimensions import Dimensions\nfrom housing_generator.domain.value_objects.boundary import Boundary\nfrom housing_generator.domain.value_objects.adjacency import AdjacencyRequirement\nfrom housing_generator.domain.enums import RoomType, AdjacencyStrength\nfrom housing_generator.domain.exceptions import LayoutGenerationError\nfrom housing_generator.domain.services.type_adjacency_catalog import build_adjacency_requirements\nfrom housing_generator.infrastructure.persistence.json_layout_repository import JsonLayoutRepository\nfrom housing_generator.infrastructure.persistence.seleccion_plantas_importer import import_seleccion_plantas\n\n\ndef build_sample_program(auto_adjacency: bool = False) -> Program:\n    \"\"\"`auto_adjacency=True`: deriva los AdjacencyRequirement\n    automáticamente del catálogo formalizado en vez de la declaración\n    manual de abajo. Mismas estancias en ambos casos.\n\n    6 estancias (programa mínimo exacto), no 11 ni 9 -- reducido en dos\n    pasos a petición del usuario (\"quiero solucionar el problema y que\n    pueda generarse ya, está roto\"). Ni 11 estancias (6 adyacencias) ni\n    9 (4 adyacencias) convergieron de forma fiable ni con 15-20 semillas\n    de reintento real -- confirmado empíricamente en esta sesión que el\n    problema es el NÚMERO de estancias combinado con la mezcla de tipos,\n    no cualquier adyacencia concreta (ver [ARCH:locking-progresivo]).\n    Este tamaño exacto SÍ se confirmó repetidamente en esta sesión con\n    tasas de éxito reales del 40-80% de las semillas probadas. Como este\n    programa es solo dato de EJEMPLO del CLI (no un requisito de ningún\n    usuario real), reducirlo a lo que sí converge de forma fiable es la\n    solución pragmática correcta, no una renuncia -- para programas más\n    grandes, el dashboard/CLI real siguen aceptando cualquier tamaño que\n    el usuario declare, esto solo afecta a la demo por defecto.\n    \"\"\"\n    rooms = [\n        Room(id=\"living\", name=\"Estar\", room_type=RoomType.LIVING_ROOM, dimensions=Dimensions(area_m2=25)),\n        Room(id=\"kitchen\", name=\"Cocina\", room_type=RoomType.KITCHEN, dimensions=Dimensions(area_m2=12)),\n        Room(id=\"bath1\", name=\"Bano\", room_type=RoomType.BATHROOM, dimensions=Dimensions(area_m2=6)),\n        Room(id=\"laundry\", name=\"Lavadero\", room_type=RoomType.LAUNDRY, dimensions=Dimensions(area_m2=6)),\n        Room(id=\"drying\", name=\"Tendedero\", room_type=RoomType.DRYING_AREA, dimensions=Dimensions(area_m2=2)),\n        Room(id=\"storage\", name=\"Almacen\", room_type=RoomType.STORAGE, dimensions=Dimensions(area_m2=4)),\n    ]\n    if auto_adjacency:\n        adjacency = build_adjacency_requirements(rooms)\n    else:\n        adjacency = [\n            AdjacencyRequirement(\"kitchen\", \"laundry\", AdjacencyStrength.MUST_BE_NEAR),\n        ]\n    return Program(rooms=rooms, adjacency_requirements=adjacency)\n\n\ndef build_sample_lot() -> Lot:\n    # 14x16=224m2 -- ya no hace falta ajustar esto a mano al tamano del\n    # programa: SimulatedAnnealingLayoutGenerator calcula su propia\n    # huella construible (footprint.py), el sobrante queda como vacio\n    # real (jardin/patio), no infla las estancias. Ver [ARCH:area-objetivo].\n    return Lot(boundary=Boundary(polygon=box(0, 0, 14, 16)))\n\n\ndef main():\n    parser = argparse.ArgumentParser(description=\"Generador de viviendas por zonificacion dia/noche/servicio\")\n    parser.add_argument(\"--output\", default=\"layout.json\", help=\"Ruta de salida del layout generado\")\n    parser.add_argument(\n        \"--seed\", type=int, default=4,\n        help=\"Semilla del recocido simulado (por defecto 4, fija -- determinista). \"\n             \"Usa otro valor para explorar variantes distintas.\",\n    )\n    parser.add_argument(\"--max-iterations\", type=int, default=3000, help=\"Iteraciones del recocido simulado\")\n    parser.add_argument(\n        \"--auto-adjacency\", action=\"store_true\",\n        help=\"Derivar Obligatorio/Preferencia automaticamente del catalogo formalizado \"\n             \"de 120 pares (build_adjacency_requirements) en vez de la declaracion \"\n             \"manual del programa de ejemplo -- genera bastantes mas requisitos \"\n             \"(44 en vez de 6 para las mismas 11 estancias), busqueda mas dificil, \"\n             \"puede necesitar --max-iterations mayor o probar otra --seed.\",\n    )\n    parser.add_argument(\n        \"--vivienda-accesible\", action=\"store_true\",\n        help=\"Exigir circulo de giro Ø1.50m en estancias habitables + bano, y pasillo \"\n             \"≥1.20m (mas exigente que el general 1.00m) -- DB-SUA Anejo A + Base 5.4 \"\n             \"Galicia (vivienda adaptada para usuarios de silla de ruedas). OPT-IN: la \"\n             \"gran mayoria de viviendas NO estan obligadas a esto. Retomado de un modulo \"\n             \"Lua de un proyecto anterior del usuario (accesibilidad.lua) -- solo cubre \"\n             \"lo geometricamente verificable con este proyecto (circulo/ancho), no \"\n             \"mobiliario (altura de encimera, aproximacion a la cama...), que no se \"\n             \"modela aqui.\",\n    )\n    parser.add_argument(\n        \"--import-seleccion\", metavar=\"RUTA\", default=None,\n        help=\"Importar 'seleccion_plantas.json' (exportacion del dashboard) en vez del \"\n             \"programa de ejemplo -- genera un edificio multi-planta real. Con el formato \"\n             \"nuevo (version 2) usa la cantidad y area reales declaradas en el dashboard; \"\n             \"con el formato antiguo (solo nombres de tipo), usa AREAS_POR_DEFECTO_M2 como \"\n             \"aproximacion generica -- revisar antes de un proyecto real en ese caso. \"\n             \"'tipo_vivienda' del JSON (aislada/pareada/adosada) se traduce automaticamente \"\n             \"a Lot.medianera_sides. Ignora --auto-adjacency (las adyacencias siempre se \"\n             \"derivan del catalogo aqui).\",\n    )\n    parser.add_argument(\n        \"--retry-seeds\", type=int, default=5,\n        help=\"Con --import-seleccion, cuantas semillas distintas probar automaticamente \"\n             \"(empezando en --seed, incrementando de 1 en 1) antes de rendirse -- \"\n             \"retomado de un caso real: la primera semilla de un programa concreto no \"\n             \"convergio, la 4a si. Los programas que salen de --import-seleccion no estan \"\n             \"curados a mano (a diferencia del ejemplo del CLI), asi que necesitan mas \"\n             \"margen de busqueda de forma habitual, no como excepcion. Poner a 1 para \"\n             \"desactivar el reintento y usar solo --seed tal cual.\",\n    )\n    parser.add_argument(\n        \"--lot-size\", metavar=\"ANCHOxFONDO\", default=None,\n        help=\"Con --import-seleccion, tamano de parcela en metros (p.ej. '14x16') en vez \"\n             \"del tamano de ejemplo por defecto (14x16, el mismo valor) -- util para \"\n             \"acercarse al tamano real de tu parcela, o para dar mas margen si el \"\n             \"programa importado es grande.\",\n    )\n    parser.add_argument(\n        \"--retranqueo\", type=float, default=None,\n        help=\"Separacion minima a los lindes de parcela, en metros (vivienda AISLADA) -- \"\n             \"concepto ya implementado y probado (Lot.retranqueo_m), sin forma de \"\n             \"activarlo desde el CLI hasta ahora. Por defecto, sin retranqueo (area \"\n             \"edificable = parcela completa), igual que antes de anadir este flag.\",\n    )\n    parser.add_argument(\n        \"--retranqueo-incremento\", type=float, default=None,\n        help=\"Cuanto se reduce el contorno edificable, en metros, de cada planta \"\n             \"respecto a la de abajo (vivienda multi-planta) -- concepto ya implementado \"\n             \"y probado (Lot.retranqueo_incremento_por_planta_m), sin forma de activarlo \"\n             \"desde el CLI hasta ahora. Requiere --retranqueo tambien (no tiene sentido \"\n             \"incrementar un retranqueo que no existe). Por defecto, mismo contorno para \"\n             \"todas las plantas, igual que antes de anadir este flag.\",\n    )\n    parser.add_argument(\n        \"--experimental-btree\", action=\"store_true\",\n        help=\"Usa BTreeLayoutGenerator (arbol B*, Chang & Chang 2000) en vez del \"\n             \"generador por defecto -- migracion en curso (Fase 4/5, comparacion \"\n             \"empirica), ver docs/referencia/generador/prototipo-btree/. Solo aplica \"\n             \"con --import-seleccion (multi-planta); el camino por defecto sigue \"\n             \"usando el generador actual.\",\n    )\n    parser.add_argument(\n        \"--edificabilidad\", type=float, default=None,\n        help=\"Coeficiente de edificabilidad (m2techo/m2suelo) de la ficha urbanistica \"\n             \"real -- comprobacion de viabilidad ANTES de generar, no un valor inventado \"\n             \"aqui. Por defecto, sin restriccion de edificabilidad.\",\n    )\n    parser.add_argument(\n        \"--ocupacion-maxima\", type=float, default=None,\n        help=\"Porcentaje maximo de ocupacion de parcela (0-100) de la ficha urbanistica \"\n             \"real. Por defecto, sin restriccion de ocupacion.\",\n    )\n    parser.add_argument(\n        \"--altura-maxima-plantas\", type=int, default=None,\n        help=\"Numero maximo de plantas permitido por la ficha urbanistica real. Por \"\n             \"defecto, sin restriccion de altura.\",\n    )\n    parser.add_argument(\n        \"--frente-minimo\", type=float, default=None,\n        help=\"Ancho minimo de fachada al vial (metros), en el lado sur de la parcela \"\n             \"(por defecto, street_side='south'). Por defecto, sin restriccion de frente.\",\n    )\n    args = parser.parse_args()\n\n    if args.retranqueo_incremento is not None and args.retranqueo is None:\n        raise SystemExit(\"--retranqueo-incremento requiere tambien --retranqueo (no tiene sentido incrementar un retranqueo que no existe).\")\n\n    if args.import_seleccion:\n        seleccion = import_seleccion_plantas(args.import_seleccion)\n        program = seleccion.program\n        if args.lot_size:\n            w_str, h_str = args.lot_size.lower().split(\"x\")\n            lot = Lot(\n                boundary=Boundary(polygon=box(0, 0, float(w_str), float(h_str))),\n                medianera_sides=seleccion.medianera_sides,\n                retranqueo_m=args.retranqueo,\n                retranqueo_incremento_por_planta_m=args.retranqueo_incremento,\n                coeficiente_edificabilidad=args.edificabilidad,\n                ocupacion_maxima_pct=args.ocupacion_maxima,\n                altura_maxima_plantas=args.altura_maxima_plantas,\n                frente_minimo_m=args.frente_minimo,\n            )\n        else:\n            base_lot = build_sample_lot()\n            lot = Lot(\n                boundary=base_lot.boundary,\n                medianera_sides=seleccion.medianera_sides,\n                retranqueo_m=args.retranqueo,\n                retranqueo_incremento_por_planta_m=args.retranqueo_incremento,\n                coeficiente_edificabilidad=args.edificabilidad,\n                ocupacion_maxima_pct=args.ocupacion_maxima,\n                altura_maxima_plantas=args.altura_maxima_plantas,\n                frente_minimo_m=args.frente_minimo,\n            )\n        if seleccion.medianera_sides:\n            print(f\"(tipo_vivienda del JSON -> medianera en: {', '.join(sorted(seleccion.medianera_sides))})\")\n\n        building = None\n        last_error = None\n        for attempt in range(max(1, args.retry_seeds)):\n            seed = args.seed + attempt\n            use_case = build_generate_building_use_case(\n                adjacency_requirements=program.adjacency_requirements,\n                seed=seed,\n                max_iterations=args.max_iterations,\n                vivienda_accesible=args.vivienda_accesible,\n                experimental_btree=args.experimental_btree,\n            )\n            try:\n                building = use_case.execute(program, lot)\n                if attempt > 0:\n                    print(f\"(semilla {args.seed} no convergio, funciono con semilla {seed} \"\n                          f\"tras {attempt + 1} intentos)\")\n                break\n            except LayoutGenerationError as e:\n                last_error = e\n        if building is None:\n            raise SystemExit(\n                f\"No se pudo generar tras probar {args.retry_seeds} semillas \"\n                f\"(desde {args.seed} hasta {args.seed + args.retry_seeds - 1}). \"\n                f\"Ultimo error: {last_error}\"\n            )\n\n        for level, layout in building.floors.items():\n            output_path = args.output.replace(\".json\", f\"_{level.value}.json\")\n            JsonLayoutRepository().save(layout, output_path, adjacency_requirements=program.adjacency_requirements)\n            print(f\"Planta '{level.value}' generada y guardada en {output_path}\")\n            for room in layout.rooms:\n                b = room.boundary.polygon.bounds\n                print(f\"  - {room.name:22s} zona={room.zone.value:8s} bounds=({b[0]:.1f}, {b[1]:.1f}, {b[2]:.1f}, {b[3]:.1f})\")\n        return\n\n    program = build_sample_program(auto_adjacency=args.auto_adjacency)\n    lot = build_sample_lot()\n    if any([args.retranqueo, args.retranqueo_incremento, args.edificabilidad,\n            args.ocupacion_maxima, args.altura_maxima_plantas, args.frente_minimo]):\n        lot = Lot(\n            boundary=lot.boundary,\n            entrance_side=lot.entrance_side,\n            retranqueo_m=args.retranqueo,\n            retranqueo_incremento_por_planta_m=args.retranqueo_incremento,\n            coeficiente_edificabilidad=args.edificabilidad,\n            ocupacion_maxima_pct=args.ocupacion_maxima,\n            altura_maxima_plantas=args.altura_maxima_plantas,\n            frente_minimo_m=args.frente_minimo,\n        )\n\n    layout = None\n    last_error = None\n    for attempt in range(max(1, args.retry_seeds)):\n        seed = args.seed + attempt\n        use_case = build_generate_layout_use_case(\n            adjacency_requirements=program.adjacency_requirements,\n            seed=seed,\n            max_iterations=args.max_iterations,\n            vivienda_accesible=args.vivienda_accesible,\n        )\n        try:\n            layout = use_case.execute(GenerationRequest(program=program, lot=lot))\n            if attempt > 0:\n                print(f\"(semilla {args.seed} no convergio, funciono con semilla {seed} \"\n                      f\"tras {attempt + 1} intentos)\")\n            break\n        except LayoutGenerationError as e:\n            last_error = e\n    if layout is None:\n        raise SystemExit(\n            f\"No se pudo generar tras probar {args.retry_seeds} semillas \"\n            f\"(desde {args.seed} hasta {args.seed + args.retry_seeds - 1}). \"\n            f\"Ultimo error: {last_error}\"\n        )\n\n    JsonLayoutRepository().save(layout, args.output, adjacency_requirements=program.adjacency_requirements)\n\n    print(f\"Layout generado y guardado en {args.output}\\n\")\n    for room in layout.rooms:\n        b = room.boundary.polygon.bounds\n        print(f\"  - {room.name:22s} zona={room.zone.value:8s} bounds=({b[0]:.1f}, {b[1]:.1f}, {b[2]:.1f}, {b[3]:.1f})\")\n\n\nif __name__ == \"__main__\":\n    main()\n"};
